-- Poems batch 203
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6f834065-03f3-4197-8a43-93195e345b3b','果山春郊即事七首  其六','吳泳','宋','宋诗','song-poetry','','[]','官事無窮類海潮，寸腸忍使自煎炮。',32,'全唐诗/poet.song.191000.json','["官事無窮類海潮，寸腸忍使自煎炮。", "橐駝種樹安心法，且併閒功子細抄。"]'),
('445e21a8-ad1d-479e-a3b5-b3657fd76027','果山春郊即事七首  其七','吳泳','宋','宋诗','song-poetry','','[]','酒燈棋雨憶昏黄，那得佳朋話此腸。',32,'全唐诗/poet.song.191000.json','["酒燈棋雨憶昏黄，那得佳朋話此腸。", "豪氣已隨煙柳折，未能除得作詩狂。"]'),
('015567fc-ec58-4a30-996b-d510150db7fe','郫縣春日吟  其一','吳泳','宋','宋诗','song-poetry','','[]','去年春日百花斑，今歲逢春萬竹間。',32,'全唐诗/poet.song.191000.json','["去年春日百花斑，今歲逢春萬竹間。", "花靚竹香宜細看，春風不會一朝閒。"]'),
('8857e150-0904-4614-87e9-0f4e5ecd2215','郫縣春日吟  其二','吳泳','宋','宋诗','song-poetry','','[]','無窮官事日裝懷，甫及芳時略放開。',32,'全唐诗/poet.song.192000.json','["無窮官事日裝懷，甫及芳時略放開。", "騷僕編排詩社去，酪奴勾管醉鄉來。"]'),
('d406e3a8-a717-4937-bcb5-389f8b1ba3f9','郫縣春日吟  其三','吳泳','宋','宋诗','song-poetry','','[]','後霜庭草芳猶茁，承露林花翠欲欹。',32,'全唐诗/poet.song.192000.json','["後霜庭草芳猶茁，承露林花翠欲欹。", "體認乾元何處是，初春天氣早晨時。"]'),
('e0322120-9f15-4322-bd21-dd4b898547fa','郫縣春日吟  其四','吳泳','宋','宋诗','song-poetry','','[]','雨脚垂垂未肯休，舍東流滿舍西流。',32,'全唐诗/poet.song.192000.json','["雨脚垂垂未肯休，舍東流滿舍西流。", "八分春種胚胎了，新水纔來便徹頭。"]'),
('54571537-6cc9-455d-9144-d024a2fc67fc','郫縣春日吟  其五','吳泳','宋','宋诗','song-poetry','','[]','不寒不暖杏花天，爭看蠶叢古寺邊。',32,'全唐诗/poet.song.192000.json','["不寒不暖杏花天，爭看蠶叢古寺邊。", "舊日尚留耕雨具，新年難得買花錢。"]'),
('9f022cad-c82b-43d5-bee4-f3dc26264fdc','郫縣春日吟  其六','吳泳','宋','宋诗','song-poetry','','[]','樹桑五畝育雞豚，器用匏尊老瓦盆。',32,'全唐诗/poet.song.192000.json','["樹桑五畝育雞豚，器用匏尊老瓦盆。", "舊禮諸儒都壞盡，西家却有典型存。"]'),
('4d8c1e51-2246-4172-b784-353ca342a429','郫縣春日吟  其七','吳泳','宋','宋诗','song-poetry','','[]','曖曖人村翠樹連，鶑拖野色度晴川。',32,'全唐诗/poet.song.192000.json','["曖曖人村翠樹連，鶑拖野色度晴川。", "新詩無限來供眼，才涉思量又不圓。"]'),
('1c375014-2672-4e1e-b5d0-d568c6de891c','郫縣春日吟  其八','吳泳','宋','宋诗','song-poetry','','[]','醉騎花影少年間，謔弄風光古將壇。',32,'全唐诗/poet.song.192000.json','["醉騎花影少年間，謔弄風光古將壇。", "漸覺年來無補益，祇將春貯在脾肝。"]'),
('5c828f34-0036-454a-879d-e377effdd147','郫縣春日吟  其九','吳泳','宋','宋诗','song-poetry','','[]','素絲五緎詠羔羊，且是公餘燕日長。',32,'全唐诗/poet.song.192000.json','["素絲五緎詠羔羊，且是公餘燕日長。", "黄妳味甘逢孔聖，黑甜睡美謁羲皇。"]'),
('2b32bd65-83a7-4000-843e-d4bf87755cae','郫縣春日吟  其一○','吳泳','宋','宋诗','song-poetry','','[]','舊穀纔登幼婦場，新蠶復出小姑忙。',32,'全唐诗/poet.song.192000.json','["舊穀纔登幼婦場，新蠶復出小姑忙。", "書生却弄閒針線，枉學明河織女襄。"]'),
('fa1a22a9-88e8-449c-af7d-c56538721330','和洪司令梅花  其一','吳泳','宋','宋诗','song-poetry','','[]','結綺臨春貯麗華，吹香偶到野人家。',32,'全唐诗/poet.song.192000.json','["結綺臨春貯麗華，吹香偶到野人家。", "霜明月白紗窗浄，但見梅詩不見花。"]'),
('6bb8af62-be57-46ec-8427-39b183e5ff9f','和洪司令梅花  其二','吳泳','宋','宋诗','song-poetry','','[]','杼雲新卷雪泥乾，剪剪輕風薄薄寒。',32,'全唐诗/poet.song.192000.json','["杼雲新卷雪泥乾，剪剪輕風薄薄寒。", "莫遣水龍吹別調，放教春在玉欄干。"]'),
('7b2ac1fd-02d6-4bd9-92a5-5c4805edf1fb','和虞滄江賦梅  其一','吳泳','宋','宋诗','song-poetry','','[]','素肌香骨水爲寒，曲樹斜枝木作酸。',32,'全唐诗/poet.song.192000.json','["素肌香骨水爲寒，曲樹斜枝木作酸。", "百匝遶花看未足，庭空參斗夜闌干。"]'),
('b9277cd5-7492-405c-a414-25d07cdd291b','和虞滄江賦梅  其二','吳泳','宋','宋诗','song-poetry','','[]','衣分冰潔佩瓊瑰，笑歛溪頭月下杯。',32,'全唐诗/poet.song.192000.json','["衣分冰潔佩瓊瑰，笑歛溪頭月下杯。", "歲晏得朋真樂在，不須青女作行媒。"]'),
('5c175a74-6972-453c-aee2-31a99ee95767','和虞滄江賦梅  其三','吳泳','宋','宋诗','song-poetry','','[]','青蒲翠草望秋零，亂絮迷春困不醒。',32,'全唐诗/poet.song.192000.json','["青蒲翠草望秋零，亂絮迷春困不醒。", "林下水邊時一見，對人應是眼中青。"]'),
('b61ace9a-1f35-49c1-b961-8342b8f4b6d7','和虞滄江賦梅  其四','吳泳','宋','宋诗','song-poetry','','[]','每對梅花輒解顔，瑶林孤絕迥難攀。',32,'全唐诗/poet.song.192000.json','["每對梅花輒解顔，瑶林孤絕迥難攀。", "擬將和靖橫枝句，摟入離騷大小山。"]'),
('d8db773d-b8d1-4fa6-aba7-d08ef9306f1d','和虞滄江賦梅  其五','吳泳','宋','宋诗','song-poetry','','[]','吟成亟取夜鐘敲，淡月籠窗昏曉交。',32,'全唐诗/poet.song.192000.json','["吟成亟取夜鐘敲，淡月籠窗昏曉交。", "真態莫將形色看，當如相馬得蒲梢。"]'),
('a34e4373-e76d-45d2-9e66-418237367353','和虞滄江賦梅  其六','吳泳','宋','宋诗','song-poetry','','[]','萬山春到直叢叢，誰省東皇有化功。',32,'全唐诗/poet.song.192000.json','["萬山春到直叢叢，誰省東皇有化功。", "生意溶溶呈露處，看隨葵麥蕩摇風。"]'),
('33286d0a-c7d0-4f5d-93cb-f6f342657174','和虞滄江賦梅  其七','吳泳','宋','宋诗','song-poetry','','[]','不御鉛華別是花，丰神高潔自成家。',32,'全唐诗/poet.song.192000.json','["不御鉛華別是花，丰神高潔自成家。", "含章不解春風意，猶倚殘粧隔絳紗。"]'),
('6db395d1-99a5-4b15-83d7-0c45842627bc','和虞滄江賦梅  其八','吳泳','宋','宋诗','song-poetry','','[]','交花煜煜露生香，一味清來浣我腸。',32,'全唐诗/poet.song.192000.json','["交花煜煜露生香，一味清來浣我腸。", "文字語言今落去，聊吹別調作醒狂。"]'),
('98b095ba-3f3c-44c4-bd42-11f2ee913ca4','安西馬','吳泳','宋','宋诗','song-poetry','','[]','月脇霜飛鏡夾瞳，龍媒掃盡朔庭空。',32,'全唐诗/poet.song.192000.json','["月脇霜飛鏡夾瞳，龍媒掃盡朔庭空。", "沙丘尚有真驪牡，端自方臯一顧中。"]'),
('c62e33ac-8dca-49ba-a1b6-9c1ebdd7a6c8','蠟梅','吳泳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','若得西湖處士疑，如何顔色到鵝兒。',32,'全唐诗/poet.song.192000.json','["若得西湖處士疑，如何顔色到鵝兒。", "清香全與江梅似，只欠橫斜照水枝。"]'),
('a1fdf165-aebe-4d1f-9d54-22aed91fe270','登羅浮山  其一','吳泳','宋','宋诗','song-poetry','','[]','要閒終是不曾閒，猛歇當頭名利關。',32,'全唐诗/poet.song.192000.json','["要閒終是不曾閒，猛歇當頭名利關。", "揩洗一雙清浄眼，稻花雨裏看浮山。"]'),
('c0dd88d2-cc45-4a09-b1b1-0b15de070801','登羅浮山  其二','吳泳','宋','宋诗','song-poetry','','[]','海山半夜失蓬萊，微带雲根雨脚來。',32,'全唐诗/poet.song.192000.json','["海山半夜失蓬萊，微带雲根雨脚來。", "元是道家清絕境，世間妄指作陽臺。"]'),
('2207eef4-284c-4968-ba20-9d7962fcce8e','登羅浮山  其三','吳泳','宋','宋诗','song-poetry','','[]','玉蟾奔月竈爐乾，老鶴巢松殿宇寒。',32,'全唐诗/poet.song.192000.json','["玉蟾奔月竈爐乾，老鶴巢松殿宇寒。", "裏面看山山不見，不如只嚮外邊看。"]'),
('0c2b1294-a620-4197-9b87-a25ad44a9335','琵琶','吳泳','宋','宋诗','song-poetry','','[]','錦調巴音祇四絃，倚門空抱向誰憐。',32,'全唐诗/poet.song.192000.json','["錦調巴音祇四絃，倚門空抱向誰憐。", "主人一自知音後，傳入王孫綺玳筵。"]'),
('83de261f-6607-4663-bf7f-8c64c3963d36','桂','吳泳','宋','宋诗','song-poetry','','[]','團團玉葉振天芳，清澈瓊樓午夜光。',32,'全唐诗/poet.song.192000.json','["團團玉葉振天芳，清澈瓊樓午夜光。", "元是小山分種去，移來西蜀作甘棠。"]'),
('d1d4eed8-1811-4177-a2e6-91636bac9e73','玉川茶','吳泳','宋','宋诗','song-poetry','','[]','一旗初試蜀山春，團銙誰論蔡與丁。',32,'全唐诗/poet.song.192000.json','["一旗初試蜀山春，團銙誰論蔡與丁。", "更出苦言澆諫味，世間醉夢合俱醒。"]'),
('5211fe04-e10b-40c5-88a3-3736cf698d67','病中宿白水','吳泳','宋','宋诗','song-poetry','','[]','觸熱山行陡頓餘，急携拄杖息禪居。',32,'全唐诗/poet.song.192000.json','["觸熱山行陡頓餘，急携拄杖息禪居。", "老僧不惜山中寶，持出銀函貝葉書。"]'),
('9f48316b-4732-4223-8536-23f4e1a2e76d','中峰','吳泳','宋','宋诗','song-poetry','','[]','連空閣道結飛霞，衲子雲遊少住家。',32,'全唐诗/poet.song.192000.json','["連空閣道結飛霞，衲子雲遊少住家。", "問訊兩仙呼不應，鳥啼驚落一巖花。"]'),
('52a5c2bc-e03e-473f-a837-48444535c2d4','和張憲登烏尤山  其一','吳泳','宋','宋诗','song-poetry','','[]','燕臺愛士拔其尤，徹去藩籬吝與驕。',32,'全唐诗/poet.song.192000.json','["燕臺愛士拔其尤，徹去藩籬吝與驕。", "藻翰宿春題品徧，青青無復土山焦。"]'),
('ea1d1057-c178-4d7a-8057-d9c5d1795789','和張憲登烏尤山  其二','吳泳','宋','宋诗','song-poetry','','[]','世涂偪仄動逢尤，山似高人色頗驕。',32,'全唐诗/poet.song.192000.json','["世涂偪仄動逢尤，山似高人色頗驕。", "寸碧亭亭還綠遶，知音不待爨桐焦。"]'),
('20fdc653-d50f-46f8-ad54-11d92f71dcbc','和張憲登烏尤山  其三','吳泳','宋','宋诗','song-poetry','','[]','放懷物外亦何尤，便謂遊遨士也驕。',32,'全唐诗/poet.song.192000.json','["放懷物外亦何尤，便謂遊遨士也驕。", "西日下來巖際宿，別尊難齧嚼皆焦。"]'),
('53fb058e-4c84-4a61-b025-d8819c0ec634','和張憲登烏尤山  其四','吳泳','宋','宋诗','song-poetry','','[]','子知天分不人尤，豈若紛紛式屢驕。',32,'全唐诗/poet.song.192000.json','["子知天分不人尤，豈若紛紛式屢驕。", "舊見已知霜葉脫，新知纔似穀牙焦。"]'),
('8c177eb9-20d4-477d-8bae-907398ce6e08','和張憲登烏尤山  其五','吳泳','宋','宋诗','song-poetry','','[]','天戈何日戮蚩尤，省得營屯戍卒驕。',32,'全唐诗/poet.song.192000.json','["天戈何日戮蚩尤，省得營屯戍卒驕。", "事會無窮人物眇，坳杯莫救釜中焦。"]'),
('5f3b6c54-a023-4592-9a94-49665a407679','和張憲登烏尤山  其六','吳泳','宋','宋诗','song-poetry','','[]','椒丘徐步不離尤，結駟朱門易養驕。',32,'全唐诗/poet.song.192000.json','["椒丘徐步不離尤，結駟朱門易養驕。", "寧似木鷄甘用拙，弗如龜筴以靈焦。"]'),
('b4a8bcd2-1c5b-475d-a5a6-89676fc13340','和觀棋','吳泳','宋','宋诗','song-poetry','','[]','七雄虎鬭着難下，三季蚖蟠石不磨。',32,'全唐诗/poet.song.192000.json','["七雄虎鬭着難下，三季蚖蟠石不磨。", "蠻觸紛紛無了日，青秧白水弄鐮柯。"]'),
('4fb710da-382f-4eaf-a489-a57519a37769','華嚴寺','吳泳','宋','宋诗','song-poetry','','[]','纔上華嚴第一山，倚天雙闕不曾關。',32,'全唐诗/poet.song.192000.json','["纔上華嚴第一山，倚天雙闕不曾關。", "白花紫柏漫山路，猶覺桃源在世間。"]'),
('3eda3a07-c3d4-4e39-9f7b-85bb145a2a5b','上峰頂','吳泳','宋','宋诗','song-poetry','','[]','一峰駱駝嶺突兀，萬級胡孫梯屈盤。',32,'全唐诗/poet.song.192000.json','["一峰駱駝嶺突兀，萬級胡孫梯屈盤。", "佛法豈無平易處，怕人只作等閒看。"]'),
('8ac48f74-fdb9-420e-b49d-967436751aa6','光相寺','吳泳','宋','宋诗','song-poetry','','[]','雲氣巃嵸羃曉山，晴曦倒影射闌干。',32,'全唐诗/poet.song.192000.json','["雲氣巃嵸羃曉山，晴曦倒影射闌干。", "須臾變態還空寂，水接天光一片寒。"]'),
('5db369fc-4cd1-4e2d-b9a4-b88c8d9fdb79','牛心寺','吳泳','宋','宋诗','song-poetry','','[]','青蓮兩兩照山開，道是金僊手自栽。',32,'全唐诗/poet.song.192000.json','["青蓮兩兩照山開，道是金僊手自栽。", "人與金牛俱不見，更從何處覓心來。"]'),
('9404df75-28c3-4ae6-a09f-58649ff78e86','和李雁湖晚春即事八首  其一','吳泳','宋','宋诗','song-poetry','','[]','琴書澹泊古羲軒，花木幽閒漢綺園。',32,'全唐诗/poet.song.192000.json','["琴書澹泊古羲軒，花木幽閒漢綺園。", "碧落青嵩無用買，湖光一曲道真渾。"]'),
('5f340967-1617-46fd-940b-8b3e0f870653','和李雁湖晚春即事八首  其二','吳泳','宋','宋诗','song-poetry','','[]','紛紛花片落車茵，點點苔錢襯屐痕。',32,'全唐诗/poet.song.192000.json','["紛紛花片落車茵，點點苔錢襯屐痕。", "造化生機渾不盡，又將新綠轉春溫。"]'),
('25b22ab1-a4a3-455e-b984-fc67bfcb6184','和李雁湖晚春即事八首  其三','吳泳','宋','宋诗','song-poetry','','[]','藹藹停雲八表昏，終風吹雨泊天門。',32,'全唐诗/poet.song.192000.json','["藹藹停雲八表昏，終風吹雨泊天門。", "繫船東港緣壕去，落日牛羊下遠村。"]'),
('ef6e77f4-e6ee-4fff-843f-df5ed20691b3','和李雁湖晚春即事八首  其四','吳泳','宋','宋诗','song-poetry','','[]','避人不必武陵源，蕩有芙蓉谿有蓀。',32,'全唐诗/poet.song.192000.json','["避人不必武陵源，蕩有芙蓉谿有蓀。", "弄水澆花心自遠，何妨酌客兩三尊。"]'),
('4e1d3591-bdfd-4f04-b3d0-34d9b8ab0af7','和李雁湖晚春即事八首  其五','吳泳','宋','宋诗','song-poetry','','[]','長鯨須嚮海波翻，澤雉何由肯畜樊。',32,'全唐诗/poet.song.192000.json','["長鯨須嚮海波翻，澤雉何由肯畜樊。", "步障連空鞋一屋，不如蕭散半山園。"]'),
('d8f6debe-266b-44f9-af41-28b916c38712','和李雁湖晚春即事八首  其六','吳泳','宋','宋诗','song-poetry','','[]','丰神玉雪更清溫，胸次涵濡七澤吞。',32,'全唐诗/poet.song.192000.json','["丰神玉雪更清溫，胸次涵濡七澤吞。", "聞道晚年偏好易，手探月窟足天根。"]'),
('80260d30-4f3d-4da2-b7f8-c9a397b7042f','和李雁湖晚春即事八首  其七','吳泳','宋','宋诗','song-poetry','','[]','庭草如茵鹿養茸，體當生意屬僊翁。',32,'全唐诗/poet.song.192000.json','["庭草如茵鹿養茸，體當生意屬僊翁。", "遊龍不作千巖雨，却卷雲根向洞中。"]'),
('aaca1a14-a0c5-4722-9008-2da54b4d8934','和李雁湖晚春即事八首  其八','吳泳','宋','宋诗','song-poetry','','[]','杏花漠漠柳陰陰，彷彿前年禮殿深。',32,'全唐诗/poet.song.192000.json','["杏花漠漠柳陰陰，彷彿前年禮殿深。", "頼有詩書緣不盡，青燈細雨短長吟。"]'),
('d24662b7-29a7-4fe8-abcf-25681ed75181','嘉禾頌七章章四句  其一','吳泳','宋','宋诗','song-poetry','','[]','翼翼嘉禾，在梁之畝。',20,'全唐诗/poet.song.192000.json','["翼翼嘉禾，在梁之畝。", "九穗離離，實栗實秀。"]'),
('735331e3-0ed4-44a5-8879-0bac970f1e87','嘉禾頌七章章四句  其二','吳泳','宋','宋诗','song-poetry','','[]','其秀維何，奕葉有儺。',20,'全唐诗/poet.song.192000.json','["其秀維何，奕葉有儺。", "春種秋實，備時中和。"]'),
('89916aa3-314b-45b5-ab25-f0a1d959cd60','嘉禾頌七章章四句  其三','吳泳','宋','宋诗','song-poetry','','[]','中和既時，重穎既垂。',20,'全唐诗/poet.song.192000.json','["中和既時，重穎既垂。", "自嚮其本，豈不爾思。"]'),
('f15f744a-c350-438f-804a-a54869da77b4','嘉禾頌七章章四句  其四','吳泳','宋','宋诗','song-poetry','','[]','維昔唐叔，實施王命。',21,'全唐诗/poet.song.192000.json','["維昔唐叔，實施王命。", "伊今之人，惟唐叔是景。"]'),
('4bfb75e1-45ef-46fc-8a59-708525b0e271','嘉禾頌七章章四句  其五','吳泳','宋','宋诗','song-poetry','','[]','惟唐叔是景，獻諸天子。',21,'全唐诗/poet.song.192000.json','["惟唐叔是景，獻諸天子。", "天子不有，以歸肇祀。"]'),
('faea2e47-d0aa-474a-9427-5da6c390e71d','嘉禾頌七章章四句  其六','吳泳','宋','宋诗','song-poetry','','[]','芝生九莖，不可以爲秔。',22,'全唐诗/poet.song.192000.json','["芝生九莖，不可以爲秔。", "狐生九尾，不可以爲袂。"]'),
('fdede70d-896c-46e0-97c2-cd7e8016bf44','嘉禾頌七章章四句  其七','吳泳','宋','宋诗','song-poetry','','[]','實爲我嘉穀，以穀我口腹。',22,'全唐诗/poet.song.192000.json','["實爲我嘉穀，以穀我口腹。", "以妥以侑，式介多福。"]'),
('a5a00ca1-ea5b-41c5-bab5-052398355c3b','城上烏','吳泳','宋','宋诗','song-poetry','','[]','爾何不向別處棲，東飛日白足，南飛有樹枝。',120,'全唐诗/poet.song.192000.json','["爾何不向別處棲，東飛日白足，南飛有樹枝。", "翺翔空中不欲墮，逋尾又向城頭歸。", "城雖高，人亦好，三匝重來屋邊遶。", "不緣啄雁稗，不爲唼鳬藻。", "鴉鴉唾駡閭里常，睠睠忠言主人告。", "所生八九子，頼有三雛成。", "兩雛連檣去，一雛聞絃驚。", "往來城頭蹔棲止，旭日又恐東方明。"]'),
('4a6c6a82-d1d9-464e-9b0c-a2b50bf265e4','羽林郎','吳泳','宋','宋诗','song-poetry','','[]','漢家官兵名羽林，臂鷹走馬長楸陰。',96,'全唐诗/poet.song.192000.json','["漢家官兵名羽林，臂鷹走馬長楸陰。", "選填並隸光祿籍，宿衛日費司農金。", "遥聞虜騎前犯塞，六部良家人不耐。", "黄鬚兒戰鄴下軍，白袍兵劫花門寨。", "義軍轉閫無已時，就令虜得名王歸。", "封侯起第豢醲賞，仍是漢殿前孤兒。"]'),
('3a88e9bf-2ecf-46b3-92cb-e66785a4b1d2','送鮮于帥三首  其一','吳泳','宋','宋诗','song-poetry','','[]','載錫珪符起伏龍，遄提小隊出南中。',64,'全唐诗/poet.song.192000.json','["載錫珪符起伏龍，遄提小隊出南中。", "軍容倒海鯨波息，旗采吹雲蚓瘴空。", "但倚碩才爲保障，仍開誠意接兵戎。", "渡瀘已覺秋風晚，爭看籌邊第一功。"]'),
('7e72fbdd-621c-467f-9667-18b11776cb67','送鮮于帥三首  其二','吳泳','宋','宋诗','song-poetry','','[]','時事牽連卒未休，三邊烽火又驚秋。',64,'全唐诗/poet.song.192000.json','["時事牽連卒未休，三邊烽火又驚秋。", "養鷹未得鷹揚力，豢虎終懷虎視憂。", "面勢只緣前局誤，肘方合向古人求。", "玉關不是無兵守，上策人心要急收。"]'),
('86e49506-e357-4d30-a3f8-e749cb4bc6ae','送鮮于帥三首  其三','吳泳','宋','宋诗','song-poetry','','[]','憶昨行臺再見時，恍兮涪水送將歸。',64,'全唐诗/poet.song.192000.json','["憶昨行臺再見時，恍兮涪水送將歸。", "丰神比舊微加瘦，道力于今轉覺肥。", "頼有一燈標日指，曾無寸草報春暉。", "孔門獨立成何事，祇舞風雩詠浴沂。"]'),
('12dedd7c-740c-469d-ba0b-1d24826c0625','句  其一','黄子實','宋','宋诗','song-poetry','','[]','賸携尊酒斟藍尾，惜不杯羹薦墨頭。',16,'全唐诗/poet.song.192000.json','["賸携尊酒斟藍尾，惜不杯羹薦墨頭。"]'),
('4364f9f3-4a85-4dd8-bf5d-f393c400cb9b','句  其二','黄子實','宋','宋诗','song-poetry','','[]','履痕莫辨陰王跡，敢去多題漢晉年。',16,'全唐诗/poet.song.192000.json','["履痕莫辨陰王跡，敢去多題漢晉年。"]'),
('3b3391d9-6284-4bd6-be26-fdb432a55180','句  其三','黄子實','宋','宋诗','song-poetry','','[]','月穿篷席罅，風軋舵牙聲。',12,'全唐诗/poet.song.192000.json','["月穿篷席罅，風軋舵牙聲。"]'),
('81b8f454-41e9-494f-b725-ffd31d8f9fc5','句  其四','黄子實','宋','宋诗','song-poetry','','[]','旅夢難安枕，村酤不滿瓶。',12,'全唐诗/poet.song.192000.json','["旅夢難安枕，村酤不滿瓶。"]'),
('2dcddf62-8dab-45f7-9137-a04ea134334e','詠瑟師','沈宏甫','宋','宋诗','song-poetry','','[]','宇宙浩浩誰詩鳴，遺響闃寂如英莖。',32,'全唐诗/poet.song.192000.json','["宇宙浩浩誰詩鳴，遺響闃寂如英莖。", "更無高談細論者，唐末婀娜江西清。"]'),
('8a5cb905-d358-4096-be23-5e0685d6a828','甘露巖','鄒恕','宋','宋诗','song-poetry','','[]','蘭若半空中，雲山第幾重。',48,'全唐诗/poet.song.192000.json','["蘭若半空中，雲山第幾重。", "瀑流千丈練，鶴宿五株松。", "曉雨禪房黑，霜林木葉紅。", "懸崖回首望，歸思過前峰。"]'),
('bc16e935-0213-4609-8875-d4aa4ce289e2','過太行山  其一','徐範','宋','宋诗','song-poetry','','[]','茫茫遠樹隔煙霏，獵獵西風振客衣。',64,'全唐诗/poet.song.192000.json','["茫茫遠樹隔煙霏，獵獵西風振客衣。", "山雨未晴嵐氣濕，溪流欲盡水聲微。", "回車廟古丹青老，碗子城荒草木稀。", "珍重狄公千載意，馬頭重見白雲飛。"]'),
('56f1733f-0626-4c64-94fa-a49a693538dc','過太行山  其二','徐範','宋','宋诗','song-poetry','','[]','路繞羊腸躡屐躋，萬山金碧總堪題。',64,'全唐诗/poet.song.192000.json','["路繞羊腸躡屐躋，萬山金碧總堪題。", "舉頭日月中天近，極目乾坤五嶽低。", "自笑鹽車騏驥厄，誰憐枳棘鳳凰棲。", "欲投古寺禪房宿，喜見僧歸落日西。"]'),
('dec6c64c-07c1-4ae0-9b45-4064f77ce4a3','咏梅','范楷','宋','宋诗','song-poetry','','[]','開徧南枝又北枝，春風消息不嫌遲。',32,'全唐诗/poet.song.192000.json','["開徧南枝又北枝，春風消息不嫌遲。", "平生自抱冰爲骨，莫待趨炎附熱時。"]'),
('06b7acfc-40dd-461c-85bd-d474a5fb14a3','酬答張安撫伯玉先生','薛師點','宋','宋诗','song-poetry','','[]','寡交率天性，積疴攻妙藥。',108,'全唐诗/poet.song.192000.json','["寡交率天性，積疴攻妙藥。", "干祿念烝嘗，著書恣談謔。", "永矢離畏途，何况縻好爵。", "感子故人意，屏吏延鈴閣。", "時剖千秋心，兼訂三山約。", "風流張平子，文采謝康樂。", "潛魚媚幽潭，高鳥昵林薄。", "物類既參差，天地亦寥廓。", "但愁霜霰多，石出兼水落。"]'),
('53ac69fd-da3c-4129-b8d5-5c3222b9f626','壽徐倉使','黄垺','宋','宋诗','song-poetry','','[]','四明山水遠且清，秀氣鍾作千人英。',272,'全唐诗/poet.song.192000.json','["四明山水遠且清，秀氣鍾作千人英。", "南州高士真濟美，天地正粹涵中襟。", "學問淵源派伊洛，文章典麗鏗䪫韺。", "射策丹墀壓群彥，聲名一日蜚玉京。", "粵從膴仕久揚歷，政事所至皆有稱。", "讎較芸編上群玉，蕃宣苕水騰頌聲。", "凝旒簡眷異儔正，追班文石煥郎星。", "清規屹立朝譽振，儒術既行邦計贏。", "論思獻納衆所矚，其奈宵旰懷遠氓。", "咨諏出攬澄清轡，肅持庾節賙列城。", "視時斂散民食足，觀風按察吏膽驚。", "側聽賜環馹騎速，行看荷橐天衢亨。", "節過清明纔六日，欣逢吉夢叶長庚。", "和氣却隨春氣足，福星還並壽星明。", "己聞好語日邊至，莫辭爛熳傾罍觥。", "自慚小草依松柏，臭味相投意甚真。", "矢詩不但爲公壽，八荒壽域更躋民。"]'),
('10bb80a8-2a69-486c-9180-b9d89fddb356','擬虹亭','黄夢得','宋','宋诗','song-poetry','','[]','父老橋邊問我翁，笑談能辦濟川功。',64,'全唐诗/poet.song.192000.json','["父老橋邊問我翁，笑談能辦濟川功。", "水光碧界一千頃，晴影紅翻二百弓。", "好與諸公來玩月，方知此地亦垂虹。", "乘風似有驚人語，高枕滄浪放眼空。"]'),
('5c2d28fc-954c-456b-acb9-bdb77b7ee190','句  其一','黄夢得','宋','宋诗','song-poetry','','[]','北望三湘西九嶷，箇中無處不嶔崎。',16,'全唐诗/poet.song.192000.json','["北望三湘西九嶷，箇中無處不嶔崎。"]'),
('c04094e3-b540-402c-bb77-64de8f228f9c','句  其二','黄夢得','宋','宋诗','song-poetry','','[]','天意因以旌遺逸。',8,'全唐诗/poet.song.192000.json','["天意因以旌遺逸。"]'),
('f940f9fe-e5ad-4ef9-a0be-0da716a727a9','黄稹宅','黄燮','宋','宋诗','song-poetry','','[]','大夫橋畔水繁華，春滿郊原樹滿花。',32,'全唐诗/poet.song.192000.json','["大夫橋畔水繁華，春滿郊原樹滿花。", "石馬導前蒙御葬，數聲雞犬是吾家。"]'),
('e51643b0-c259-4aae-b75a-c40db1513a4e','綺川亭','楊志','宋','宋诗','song-poetry','','[]','一泓綠凈滄浪水，千朶紅稠菡萏花。',32,'全唐诗/poet.song.192000.json','["一泓綠凈滄浪水，千朶紅稠菡萏花。", "病眼紛紛何所似，江天落日散餘霞。"]'),
('d0d300d9-0192-44b2-b61f-a8b42aaf4dc8','石澗龍首山','楊志','宋','宋诗','song-poetry','','[]','殘年仍置閏，五日恰逢春。',48,'全唐诗/poet.song.192000.json','["殘年仍置閏，五日恰逢春。", "携酒各獨賞，敲門僧不嗔。", "雙榕如拱立，萬井故橫陳。", "僧舍少盤薄，元規塵上人。"]'),
('591c3a6d-1cba-4d18-a4f3-7074584f4526','鼓樓懷古','楊志','宋','宋诗','song-poetry','','[]','興廢何年事，無由問老成。',48,'全唐诗/poet.song.192000.json','["興廢何年事，無由問老成。", "代爲兜率地，留得古樓名。", "石塔添潮影，銅壺斷漏聲。", "我來空弔古，恨不賦蕪城。"]'),
('05b69149-a5be-4c0b-b0bd-510b3c7e4234','法安寺','趙汝馭','宋','宋诗','song-poetry','','[]','四山圍一寺，勝地出花封。',48,'全唐诗/poet.song.192000.json','["四山圍一寺，勝地出花封。", "秀竹辭春籜，晴雲生夏峰。", "僧閑流水檻，村急夕陽舂。", "與客下山去，鶴歸猶带松。"]'),
('02aa3d81-80ea-465a-a3be-99ed1cb75c60','元蘇二公祠','趙汝馭','宋','宋诗','song-poetry','','[]','春祠當上巳，新像合蒼城。',48,'全唐诗/poet.song.192000.json','["春祠當上巳，新像合蒼城。", "慨想交鄰意，兼懷過客情。", "宅遺環水碧，驛带古楊湆。", "天上文星會，人間弦誦聲。"]'),
('0f6ae229-276e-49ad-9fd7-bec1197d536a','雲峰庵','趙汝馭','宋','宋诗','song-poetry','','[]','一庵移向白雲深，丁卯年來住至今。',32,'全唐诗/poet.song.192000.json','["一庵移向白雲深，丁卯年來住至今。", "鳥哢蟬鳴俱過耳，心如鐵石髮如金。"]'),
('2796c2c1-de6a-46d4-81cd-b827014de6c7','見日庵','趙汝馭','宋','宋诗','song-poetry','','[]','莫把桃花誤世間，日方明處隠尤難。',32,'全唐诗/poet.song.192000.json','["莫把桃花誤世間，日方明處隠尤難。", "道人辦得心堅固，好向飛雲頂上安。"]'),
('0630144e-43cf-4dd1-a8c7-43dd30c75075','石樓','趙汝馭','宋','宋诗','song-poetry','','[]','歷井捫參跬步行，直排閶闔叫雲扃。',64,'全唐诗/poet.song.192000.json','["歷井捫參跬步行，直排閶闔叫雲扃。", "着身高處不知險，回首看時方始驚。", "世界三千藏粒粟，江湖萬里付浮萍。", "何須更跨揚州鶴，穩御仙軿朝帝京。"]'),
('0820b26c-26ca-4d45-8251-33322c3e0453','可賦庵','趙汝馭','宋','宋诗','song-poetry','','[]','舊題可賦足幽深，手植疏梅有石心。',32,'全唐诗/poet.song.192000.json','["舊題可賦足幽深，手植疏梅有石心。", "當日和羹人不見，竹風疑是讀書音。"]'),
('48303cd3-b245-49c8-b73b-6e3771765d70','句','趙汝馭','宋','宋诗','song-poetry','','[]','唐僧逢漢寶，山洞得天名。',12,'全唐诗/poet.song.192000.json','["唐僧逢漢寶，山洞得天名。"]'),
('4e17dcca-1131-433b-9d8f-d79a1adecead','題洞霄','趙汝湜','宋','宋诗','song-poetry','','[]','巑屼列千峰，一柱屹翹楚。',48,'全唐诗/poet.song.192000.json','["巑屼列千峰，一柱屹翹楚。", "迴復藴奇秀，有此雲霞所。", "巖封五里霧，松撼半天雨。", "深知境未窮，正欠驚人語。"]'),
('53f3a352-68eb-4a01-9a15-912eddd31655','自和','趙汝湜','宋','宋诗','song-poetry','','[]','洞府日月閒，風景自清楚。',48,'全唐诗/poet.song.192000.json','["洞府日月閒，風景自清楚。", "九關啟天鑰，容我朝帝所。", "清緣宿仙館，夢碎石泉雨。", "明朝得羊珠，試向張華語。"]'),
('e9931769-4c87-456b-887a-ac95f194ef20','敬和九鎖步虛詞 天關鎖','趙汝湜','宋','宋诗','song-poetry','','[]','雲墉高嵯峨，七蕤銜銅環。',48,'全唐诗/poet.song.192000.json','["雲墉高嵯峨，七蕤銜銅環。", "有象非有質，真儔得躋攀。", "九天著通籍，保我玉鍊顔。", "英英青旄節，悠悠款靈關。"]'),
('db3ef863-8f6c-401e-801a-bb86859dfc7c','敬和九鎖步虛詞 藏雲鎖','趙汝湜','宋','宋诗','song-poetry','','[]','靈根鬰三素，一氣同氤氳。',48,'全唐诗/poet.song.192000.json','["靈根鬰三素，一氣同氤氳。", "冉冉霄上游，永離囂塵熏。", "空體含五華，霞貫泥丸君。", "鐶剛爾何神，攝身混祥雲。"]'),
('8aebbdbb-fcef-43a2-8279-ddee65bd7c24','敬和九鎖步虛詞 凌虛鎖','趙汝湜','宋','宋诗','song-poetry','','[]','太空本無形，天衢迥蕭疎。',48,'全唐诗/poet.song.192000.json','["太空本無形，天衢迥蕭疎。", "火煉身彌輕，意行神已如。", "飄飄跨倒景，棽麗舞雲裾。", "無礙故逍遥，灑然翔清墟。"]'),
('5b59a9ca-c331-4299-9a99-2eea92d0929f','敬和九鎖步虛詞 通真鎖','趙汝湜','宋','宋诗','song-poetry','','[]','五嶽皆積骨，千霜永難晨。',48,'全唐诗/poet.song.192000.json','["五嶽皆積骨，千霜永難晨。", "胡爲甘短景，不悟丹臺春。", "至道豈在煩，錄精練胎津。", "六六琴心文，一悟通玄真。"]'),
('d0c59bf2-716d-45e7-8fab-8f00b6aeed78','敬和九鎖步虛詞 龍吟鎖','趙汝湜','宋','宋诗','song-poetry','','[]','矯首東方宮，變化何由尋。',48,'全唐诗/poet.song.192000.json','["矯首東方宮，變化何由尋。", "神用妙難擬，飈電赫森森。", "雨施不爲功，雲從本無心。", "人間謾懷想，戛鉢希雷吟。"]'),
('e79d4a5b-f522-448c-b70a-0c6016cd0184','敬和九鎖步虛詞 洞微鎖','趙汝湜','宋','宋诗','song-poetry','','[]','大道不容言，有滯還有鞿。',48,'全唐诗/poet.song.192000.json','["大道不容言，有滯還有鞿。", "返本含元造，竟達無上機。", "希夷絕視聽，得一衆甫歸。", "向來寢虛師，至訣殊精微。"]'),
('66252894-d740-41b5-ad5d-be7568a0fc66','敬和九鎖步虛詞 雲璈鎖','趙汝湜','宋','宋诗','song-poetry','','[]','悠悠劫爲朝，萬民恣遨遊。',48,'全唐诗/poet.song.192000.json','["悠悠劫爲朝，萬民恣遨遊。", "三山眇如塊，舉步身彌高。", "絳宮近咫尺，天風度騷騷。", "至音非笙歌，泠然八琅璈。"]'),
('60546ce5-9f9c-453d-8237-07c03b318bca','敬和九鎖步虛詞 朝元鎖','趙汝湜','宋','宋诗','song-poetry','','[]','煌煌玉京闕，瑞靄紛天垣。',48,'全唐诗/poet.song.192000.json','["煌煌玉京闕，瑞靄紛天垣。", "嚴扈森虎兵，金朱煥靈門。", "星弁集萬真，龍旂間華旛。", "齊心潔形神，稽首朝混元。"]'),
('b827003f-ca5c-4cc6-a472-c4dbfd32d88a','敬和九鎖步虛詞 飛鸞鎖','趙汝湜','宋','宋诗','song-poetry','','[]','漸入雲霄徑，清氣逼人寒。',48,'全唐诗/poet.song.192000.json','["漸入雲霄徑，清氣逼人寒。", "欲學長生訣，先過此重壇。", "無屋堪竚足，有地可藏丹。", "遥瞻深鎖處，時見遶飛鸞。"]'),
('a5af40e8-cb69-44c9-be93-fd860ee0c91b','贈羽人何授','趙汝湜','宋','宋诗','song-poetry','','[]','秋水爲神玉爲骨，片雲出洞遊虛碧。',32,'全唐诗/poet.song.192000.json','["秋水爲神玉爲骨，片雲出洞遊虛碧。", "竚看他年鶴駕歸，顯彼青天與白日。"]'),
('fb46aa92-5f33-4837-8982-bc27cd107d2a','餞陳匝峰之廉泉','趙善璙','宋','宋诗','song-poetry','','[]','桃源渺何處，夢短到家難。',48,'全唐诗/poet.song.192000.json','["桃源渺何處，夢短到家難。", "不辦一丘費，猶爲九品官。", "鶴嫌新俸薄，鷗訝舊盟寒。", "附翼攀鱗事，書生不敢干。"]'),
('101e7af6-d3f1-4939-9d9a-fe75cda4ff21','別荆州諸友','呂殊','宋','宋诗','song-poetry','','[]','荆州三度別，此別猶酸冷。',216,'全唐诗/poet.song.192000.json','["荆州三度別，此別猶酸冷。", "蒹葭逐岸靡，烟雨隔林迥。", "去棹行且留，離觴醉還醒。", "緬懷荆州士，鵠立霜毛整。", "爽信何由人，班班紛脫穎。", "况是清俊流，魁然挈裘領。", "相逢名教樂，殊忘舊機境。", "草木臭味同，何庸絕畦町。", "虎豹識避就，寧忍覆陷阱。", "人情不盡遠，頗諒心耿耿。", "眼底絕荆榛，夙生獨何幸。", "時恨多曠違，赧容多面頸。", "分袂復自茲，深淵惜斷綆。", "斷綆無續期，分袂有時并。", "但願各自珍，時當動深省。", "一簣會成山，九仞猶棄井。", "要令百煉金，清瑩無留礦。", "大哉乾坤內，吾道相與命。"]'),
('ceb564a4-5b18-479a-bdf0-d26fc1c31bf9','題清谿神女祠','呂殊','宋','宋诗','song-poetry','','[]','生居萬山中，二年依澤國。',144,'全唐诗/poet.song.192000.json','["生居萬山中，二年依澤國。", "偶於坐曹暇，聊欲訪禪默。", "再拜神女祠，劈山定何術。", "上有琳宮巖，作論期破惑。", "只今澄潭中，異影眩莫執。", "泉源入幽窈，蛾眉如可及。", "吾聞大地下，出沒水中日。", "胡爲二魶魚，欲歸猶未得。", "變化乘雲雷，那能繫不食。", "山深風竅號，天寒日車急。", "寄語龍宮君，安穩藏故穴。", "近來託怪多，勿遣容易測。"]'),
('ff8e1814-6dcf-4179-bac7-1e137cc130fa','蛾眉亭','呂殊','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','采石江頭月正弦，捉月臺邊酒滿船。',98,'全唐诗/poet.song.192000.json','["采石江頭月正弦，捉月臺邊酒滿船。", "擾擾利名蟻慕羶，如公豈但酒獨賢。", "平生醉裏詩三千，捲起長江作長箋。", "悲哉人世隔天淵，一日乘風反自然。", "死生在我我則天，欲死得死豈其冤。", "欲罷長風大放顛，蒼茫何處可拍騎鯨肩。"]'),
('9e1efb97-8d12-4241-80d1-a4d5d5a3a3dc','句','呂殊','宋','宋诗','song-poetry','','[]','遊子驚車破，農人念稼傷。',12,'全唐诗/poet.song.192000.json','["遊子驚車破，農人念稼傷。"]'),
('8adbad03-4a66-4a5d-8416-2d08a9c49c5e','梅莊春間','劉厚南','宋','宋诗','song-poetry','','[]','最喜逍遥泉石間，幽居四面繞青山。',64,'全唐诗/poet.song.192000.json','["最喜逍遥泉石間，幽居四面繞青山。", "苔迷荒徑人稀到，花壓重門晝自關。", "古剎風傳鐘磬遠，平疇雨過桔槔閒。", "荷鋤手摘園中筍，配酒三杯壯客顔。"]'),
('d8c3a316-c3b9-46c6-9319-10a4222bf4ac','贈陳宗之  其一','鄭斯立','宋','宋诗','song-poetry','','[]','昔人躭隠約，屠酤身亦安。',204,'全唐诗/poet.song.192000.json','["昔人躭隠約，屠酤身亦安。", "矧伊叢古書，枕藉於其間。", "讀書博詩趣，鬻書奉親歡。", "君能有此樂，冷淡世所難。", "我本抱孤尚，爲貧試彈冠。", "欲和南薰琴，秋風欻戒寒。", "恬無分外想，賸有日晷閒。", "閲書於市廛，得君羈思寬。", "誦其所爲詩，刻苦雕肺肝。", "陶韋淡不俗，郊島深以艱。", "君勇欲兼之，日夜吟辛酸。", "京華聲利窟，車馬如浪翻。", "淡妝誰爲容，古曲誰爲彈。", "桐陰覆月色，靜夜獨往還。", "人皆掉臂過，我自刮眼看。", "百年適志耳，豈必身是官。", "不見林和靖，清名載孤山。"]'),
('3ed9f846-16b7-4b07-9ba8-5fc00727f28d','贈陳宗之  其二','鄭斯立','宋','宋诗','song-poetry','','[]','羨君家闕下，不踏九衢塵。',48,'全唐诗/poet.song.192000.json','["羨君家闕下，不踏九衢塵。", "萬卷書中坐，一生閑裏身。", "貪詩疑有債，閲世欲無人。", "昨日相思處，桐花爛熳春。"]'),
('30632e10-a8d3-4ce7-bdb3-4468045fcd29','白獺湖','章樵','宋','宋诗','song-poetry','','["\u897f\u6e56"]','屈曲連汀隠復明，西湖奇觀到南屏。',64,'全唐诗/poet.song.192000.json','["屈曲連汀隠復明，西湖奇觀到南屏。", "萍花巧綴玉鈿碧，山色浄涵螺髻青。", "隋女啼粧羞缺月，秦娥望幸對明星。", "主人約束當尊俎，未放騷翁眼獨醒。"]'),
('1c3ac6af-ff1f-4d62-aabf-b7fbe5cf8107','伽溪','章樵','宋','宋诗','song-poetry','','[]','試將生計問農家，兒大扶犁女漚麻。',32,'全唐诗/poet.song.192000.json','["試將生計問農家，兒大扶犁女漚麻。", "燒筍煮葵供午餉，山中樂事自無涯。"]'),
('c988d562-98bc-44de-899a-fe08b33b7abd','書懷','戴栩','宋','宋诗','song-poetry','','[]','隨牒滄海隅，兩見初月吐。',288,'全唐诗/poet.song.192000.json','["隨牒滄海隅，兩見初月吐。", "緬懷故山友，飄散等風雨。", "低頭繙簿書，仄足隨步武。", "荒哉舊時學，千石壓一縷。", "涇渭誰濁清，荼薺互甘苦。", "癡兒了官事，朝飯或過午。", "聊爲五斗淹，未受三命俯。", "有得那免失，無闕孰爲補。", "門前流水車，六轡去如組。", "忽逢阮生途，微徑何由取。", "夸者類死權，所死固已粗。", "人生天地間，誰客復誰主。", "蛙鳴儻適意，賢於兩部鼓。", "蝸角起相攘，戰劇赤白羽。", "息機自搰搰，獨趣甘踽踽。", "喧寂不相謀，笑人從鄧禹。", "行藏正有時，倚樓追杜甫。", "固知抱書癖，未肯學錢虜。", "長纓覊單于，尺紙招贊普。", "古來磊落人，過眼蚊蚋聚。", "且復對青山，天外修眉嫵。", "悠然成獨酌，醉語免童羖。", "是時秋冬交，寒事欲墐戶。", "蛩螿夜唧唧，草木霜莽莽。"]'),
('9fa8c436-82e8-4b7d-a18e-11952ded9949','寄題林上舍真意堂用其元和淵明韻二首  其一','戴栩','宋','宋诗','song-poetry','','[]','趨贏厭市寂，洗聽嫌瓢喧。',60,'全唐诗/poet.song.192000.json','["趨贏厭市寂，洗聽嫌瓢喧。", "襟素倘相越，取捨誰爲偏。", "卓哉靖節翁，人境得僊山。", "有真諒無贋，無往豈有還。", "唯彼南山雲，朝夕可晤言。"]'),
('f9a10838-191e-402e-8bb1-9455add3a5d6','寄題林上舍真意堂用其元和淵明韻二首  其二','戴栩','宋','宋诗','song-poetry','','[]','山雲將雨忙，山風得松喧。',60,'全唐诗/poet.song.192000.json','["山雲將雨忙，山風得松喧。", "嗟我無用世，懶癖抱奇偏。", "鴛鴻玷清宁，猿鶴猜舊山。", "羨君不浪出，悔我今空還。", "三復和陶什，慙謝不能言。"]'),
('8c602b9b-f17a-43be-be02-43c517dac289','和葉水心會昌觀小集','戴栩','宋','宋诗','song-poetry','','[]','深居抱窮空，弱質資凍暴。',144,'全唐诗/poet.song.192000.json','["深居抱窮空，弱質資凍暴。", "躡齊邇高堂，凌陰得重燠。", "敗素諒難遷，窘逼尚可復。", "再拜窺著書，甘以謝華轂。", "涉海浩無津，眩汗頸爲縮。", "萬葩拾一二，淺心自蘭菊。", "喟焉懷世情，否泰幾翻覆。", "經綸委道周，伊誰穫已熟。", "哲人信委蛇，愛士比金玉。", "盖摩集雲門，艇湊思遠瀆。", "一觴爲我陶，千載期爾朂。", "歲晏霜雪交，故林有喬木。"]'),
('f47eb48b-4dfd-4802-a5db-16572ec9e78b','次韻水心端午思遠樓小集','戴栩','宋','宋诗','song-poetry','','[]','衆嫭容獨醜，孤正軋羣傾。',96,'全唐诗/poet.song.192000.json','["衆嫭容獨醜，孤正軋羣傾。", "何必遠者思，今古同一情。", "士方慕潔修，各以好自縈。", "一旦履華膴，爭奪遺世名。", "梟獍隨詆鳳，螻螘起困鯨。", "醉中觸靈均，到今喚不醒。", "朋社角曼衍，冶遊眩輕盈。", "無情湘水窟，有恨郢山棱。"]'),
('71a7c5f0-ec5a-4ec6-bb54-ee3ce32c4c61','賞梅游中塘分韻得影字呈水心','戴栩','宋','宋诗','song-poetry','','[]','神僊宅空碧，下亦愛人境。',216,'全唐诗/poet.song.192000.json','["神僊宅空碧，下亦愛人境。", "中塘豈所私，羣物賁華景。", "始憇羅浮舟，水迅山石礦。", "三岡肇茲源，清曠可百井。", "踈起樵屋煙，密竚玉娥影。", "隴獅鼓雪鬃，石烏延帨頸。", "未竟前後村，忽迤東西嶺。", "潔諧竹買隣，醜愧櫟生癭。", "歲晏澤澍枯，日燥霜力猛。", "翩其千萬芳，阻此一半騁。", "窮哦弔羈艷，熾炬藥酷冷。", "誰料風騷家，敢奪造化秉。", "兒童駭新觀，父老發舊省。", "初斸莎根移，肅布花陣整。", "春筐望雨肥，月橋任枝㾪。", "胡爲浪鈎引，衆喧侵獨靜。", "滋味已足冠，色香難自屏。", "徘徊重徘徊，天北大星耿。"]'),
('36ecfdee-661d-4383-a8e8-9bafb7d247f2','後園老梅爲園丁斧而薪之有所存者直幹危梢耳近亦放三四花吁嗟梅兮生非其地儻移在離騷園中肯作如是觀耶故詩以弔之','戴栩','宋','宋诗','song-poetry','','[]','爾梅生不辰，失身蔬茹圃。',264,'全唐诗/poet.song.192000.json','["爾梅生不辰，失身蔬茹圃。", "雖沾灌溉力，却受穢濁侮。", "未能同臭味，祇得共甘苦。", "青隨菜甲肥，翠引蒿芽吐。", "與時自高下，何意較爾汝。", "畦丁厭長成，恐礙寸金土。", "清陰仰密葉，日日逢而怒。", "踈柯並柔枝，旦旦伐而斧。", "如此冰玉姿，若爲荆棘伍。", "孤標餘寸息，老命懸一縷。", "四圍蒼蘚黏，半心蝕蟲蠱。", "禁持幾霜雪，剝落久風雨。", "潛陽動地脈，生意頓鼓舞。", "塗抹三四花，豈自矜媚嫵。", "香清不如少，骨勁不嫌古。", "試問白玉堂，何如破茅宇。", "畢竟天地間，貴賤各有主。", "苟非吾所安，雖榮亦何取。", "說與此花知，善自且撐拄。", "須有歲寒人，徙根松竹塢。", "知汝非錯薪，肯容刈其楚。", "巡簷一笑春，能忘在莒不。"]'),
('8c2e9804-50e2-4a9d-9aa1-5ac60f143ef8','送袁著作守徽州','戴栩','宋','宋诗','song-poetry','','[]','明月峩進賢，飛霞粲朝服。',192,'全唐诗/poet.song.192000.json','["明月峩進賢，飛霞粲朝服。", "歸着萊氏斑，堂前問凉燠。", "肘旁一印懸，字刻新安牧。", "清時寶靜恬，頹俗迷返復。", "而君膝上傳，賸此名節馥。", "頳鯉躍天池，羣鯫蕩相逐。", "中廼有一鱗，不洄亦不洑。", "驪龍雷電威，閃光注兩目。", "未知豢者誰，欲使同豭鶩。", "君家此二圖，厥理探已熟。", "翩然九門去，飫爾萬家福。", "風移戶賦稠，雨足山苗彧。", "一將蘭芸香，盡洗筩缿牘。", "手別阻齊房，心期屬帆軸。", "昔聞孔敬康，埋采彼深谷。", "遲君膏覲車，後乘載幽獨。"]'),
('8d858357-081d-453b-9a5d-43c4e5b33f68','送翁靈舒赴越帥分韻得欲字','戴栩','宋','宋诗','song-poetry','','[]','越峰羅四圍，越水鏡相燭。',168,'全唐诗/poet.song.192000.json','["越峰羅四圍，越水鏡相燭。", "我昔扁舟來，十日看不足。", "天垂禹祠旁，海入秦望曲。", "荒寒暝色歸，牛背下鴝鵒。", "興亡百粵鄉，俛仰千載俗。", "恨我劣風騷，眼到筆不屬。", "君今挾此遊，萬象困搜斸。", "有類古趫將，敵勍乃所欲。", "市驅羲獻軍，降豎元賀纛。", "策勳六義右，正始渺絲粟。", "秋風吹蟲聲，桂菊漸結束。", "京華萬種身，聚散棋着局。", "吾徒日夕偕，文字當杯醁。", "奈何奪此翁，爲我謝州督。"]'),
('a701f579-2111-407b-ad4a-9914cfd5ddc5','定海餞王郎中','戴栩','宋','宋诗','song-poetry','','[]','曈曈明月佩，奕奕朝霞裳。',192,'全唐诗/poet.song.192000.json','["曈曈明月佩，奕奕朝霞裳。", "握蘭侍帝所，搴蘭思衡湘。", "衡湘渺何許，玉節耿有光。", "耄倪九城民，喜色紛迎將。", "曰予逢聖代，有君冠虞唐。", "臯禹翊元化，萬宇如一堂。", "欲銷庾籍蠹，乃借芸籤香。", "我聞生人初，此屋有盖藏。", "官漁吏爲罟，頳此百尾魴。", "湖南素清絕，帛賤米不翔。", "攬轡亦何事，談笑還循良。", "歸來倡九牧，論思助時康。", "此別非久隔，此懷詎暫忘。", "湖風開縐碧，柳雨滋柔黄。", "朋簪各有贈，再拜獻一觴。", "短章不成琢，愧彼金玉相。"]'),
('bb36ad1c-b841-4bda-8b9c-4015ed3f03c5','上丞相壽','戴栩','宋','宋诗','song-poetry','','[]','人統開璿曆，台符煥紫躔。',288,'全唐诗/poet.song.192000.json','["人統開璿曆，台符煥紫躔。", "數如環復始，天與壽無邊。", "麟閣精神異，龍輿寵數專。", "先朝稱舊弼，潞國最長年。", "遼幣猶增遣，河流未肯旋。", "爭如今日盛，獨致太平全。", "青社歸傳檄，陰山息控弦。", "堤成江勢却，疆闢稻畦連。", "燮理功何鉅，勤勞意自便。", "寒分編戶粟，雪賜羽林錢。", "吉日登符寶，中天敞棟梴。", "九重申駿命，一德共蟬聯。", "吾道今隆矣，人文益粲然。", "來歸褒衍聖，訪後續伊川。", "美績隨時現，神謀應物圓。", "基扶周鼎晏，色補舜衣妍。", "獨立觀昭曠，中持斡化權。", "通融文共武，銷壓黨兼偏。", "位乃昭文右，功惟尚父先。", "福流寰海遍，謙守此心堅。", "卦象黄裳繇，詩家綠竹篇。", "流傳皆琬琰，賡頌幾歌絃。", "峻極千齡際，中和二日前。", "沙堤春駘蕩，鳳沼曉澄鮮。"]'),
('2031d4a1-f25d-4f03-9311-d7f3d53b0015','賀丞相家廟詩','戴栩','宋','宋诗','song-poetry','','[]','有永恢皇祚，中興挺世臣。',288,'全唐诗/poet.song.192000.json','["有永恢皇祚，中興挺世臣。", "王封一品貴，廟錫五筵新。", "日月臨華表，璇璣近彩晨。", "秀當吳嶠色，流自鄮江津。", "給吹儀褒燧，銘功鼎賜栒。", "神游來燕日，吉朔契龜辰。", "騶騎傳呼鬨，儀鸞供帳陳。", "九街收雨凈，午漏带鐘勻。", "從以簪纓貴，來羞俎豆珍。", "思隨時共肅，懽與律回春。", "感激思親淚，舂容致主身。", "羣工瞻禮樂，百兩溢車輪。", "粵若今爲盛，應無古與倫。", "王珪漸寂寞，諸葛抱酸辛。", "父子千齡並，明良一德純。", "秉心同此學，錫福遍生民。", "日者邦維固，天令敵運屯。", "版圖重入漢，玉璽已收秦。", "遵養謀先定，規恢氣遂振。", "相仍鳴鸑鷟，雙玉上麒麟。", "帝謂先朝舊，卿勳不數人。", "何官崇寵渥，無地匪經綸。", "禮始昭陵建，恩參潞國均。", "有嚴京邑宇，還望越祠鄰。"]'),
('923e6b88-5829-40cb-8c1c-8dc5abcde792','龍湫瀑','戴栩','宋','宋诗','song-poetry','','[]','石壁百尋高，噀空飛雪濤。',96,'全唐诗/poet.song.192000.json','["石壁百尋高，噀空飛雪濤。", "鳥窺翻進退，龍住本雄豪。", "長嘯勢隨壯，細聽聲忽逃。", "沫霏侵佛像，境凈絕谿毛。", "峻頂聞通海，殘流不著舠。", "虹霓無故見，靈怪有時遭。", "久對崖疑動，遲行路不勞。", "貫休濛雨句，人詠入詩騷。"]'),
('d46cdcb9-4fa5-4167-87fa-bd21026e693c','同水心弔薛子舒墓','戴栩','宋','宋诗','song-poetry','','[]','自劚青雲去，長途墜玉鑣。',168,'全唐诗/poet.song.192000.json','["自劚青雲去，長途墜玉鑣。", "有名天所吝，無病藥爲妖。", "月斧千家寂，霓梭五色銷。", "夢靈虛吐鳳，數短實如鴞。", "筦庫嗟常調，弓旌欠特招。", "貴兒嫌苦淡，盛葉不蕭條。", "往憶京華旅，相隨柳外橋。", "行藏今止此，歲月忽同飄。", "留札寬親抱，緘文付穉髫。", "敬亭花自發，族隴木仍喬。", "稍待刊銘志，從知慰泬寥。", "友朋如昨日，來往未辭遥。", "酹散窗生霧，吟寒斗掛杓。", "百年齊一盡，終譽在山椒。"]'),
('6feb5a0d-67d5-4fd1-84c0-9c2d61de059b','宿山寺','戴栩','宋','宋诗','song-poetry','','[]','湔祓六根塵，來尋下榻盟。',48,'全唐诗/poet.song.192000.json','["湔祓六根塵，來尋下榻盟。", "夢回秋已至，心定暑初清。", "急雨打窗過，飛泉落澗聲。", "佛燈猶弄影，趺坐到天明。"]'),
('d1672ca0-5c2f-46bc-a582-58e72fcb763f','勸耕題正覺寺詩次王文康韻二首  其一','戴栩','宋','宋诗','song-poetry','','[]','渤澥東南極，何年梵室開。',48,'全唐诗/poet.song.192000.json','["渤澥東南極，何年梵室開。", "地形緣水盡，潮勢挾山來。", "古市朝仍暮，遥帆去若回。", "老僧無一事，窗日射飛埃。"]'),
('c66a84c2-7267-4606-abb1-dfac23b08feb','勸耕題正覺寺詩次王文康韻二首  其二','戴栩','宋','宋诗','song-poetry','','[]','海山春過半，未見一花開。',48,'全唐诗/poet.song.192000.json','["海山春過半，未見一花開。", "巖溜無時滴，松風盡日來。", "前生身已到，歸路首重回。", "祇恐山靈笑，衣巾着吏埃。"]'),
('448f18b5-f1b5-4cca-bab7-7224fe583b8e','清源寺','戴栩','宋','宋诗','song-poetry','','[]','踏破祖師關，參黄仍弔顔。',48,'全唐诗/poet.song.192000.json','["踏破祖師關，參黄仍弔顔。", "龍分一脈水，鶴占半屏山。", "塔影浮雲外，松陰落照間。", "本因閒到此，吟苦不能閒。"]'),
('624b700c-85cd-478c-a2f8-8bcdbb2f94b5','自龍湫出靈巖','戴栩','宋','宋诗','song-poetry','','[]','四山奇更峭，外看未知山。',48,'全唐诗/poet.song.192000.json','["四山奇更峭，外看未知山。", "藏此千峰在，多應一壑間。", "飄湍洗雲骨，靈異出人寰。", "埋沒尚多有，寄言榛與菅。"]'),
('05c253b3-bd91-4452-8d93-b6ea0a4ce7a8','羅漢寺','戴栩','宋','宋诗','song-poetry','','[]','崖勢石龍如，中爲大士居。',48,'全唐诗/poet.song.192000.json','["崖勢石龍如，中爲大士居。", "茗花時現異，檀施最緣渠。", "竈爇山枝濕，燈懸龕影虛。", "山門難即去，奇嶂列前除。"]'),
('f5fc99a0-de76-4770-b024-dc4782c14ff5','題石龍','戴栩','宋','宋诗','song-poetry','','[]','嵌崖雙合處，罅石隠龍形。',48,'全唐诗/poet.song.192000.json','["嵌崖雙合處，罅石隠龍形。", "鱗甲從人看，莓苔自舊青。", "兩漥唯一滴，盡日不盈瓶。", "飲此清甘極，全令塵思醒。"]'),
('3967a475-aedf-4906-b122-32809a6b2fde','白鶴寺作','戴栩','宋','宋诗','song-poetry','','[]','子晉昔游處，平臺片石成。',48,'全唐诗/poet.song.192000.json','["子晉昔游處，平臺片石成。", "寺名猶記鶴，松響却疑笙。", "巖壁飛雙瀑，金沙照一泓。", "野人豈仙伴，隨鹿過溪行。"]'),
('90a65878-bae5-4d86-a8c4-47e91e15237b','寄劉成道','戴栩','宋','宋诗','song-poetry','','[]','歸淮方向浙，度盡一年寒。',48,'全唐诗/poet.song.192000.json','["歸淮方向浙，度盡一年寒。", "想見添詩卷，傳聞攝酒官。", "雨多江溆暗，米賤客愁寬。", "舊友參臺幕，應留看牡丹。"]'),
('de791560-a816-43aa-9ade-85c31cd72821','宿局次韻盧直院炎夜之作','戴栩','宋','宋诗','song-poetry','','[]','市屋炎蒸極，愛眠官署亭。',48,'全唐诗/poet.song.192000.json','["市屋炎蒸極，愛眠官署亭。", "灑泉清坐石，疏紙出危櫺。", "露草有塵色，風枝無動形。", "懷人兼述句，鐘盡鑰開扃。"]'),
('461515c1-8232-4033-9090-dd012bcd543a','定海寒食西湖憶盧玉堂葬西湖之上近傳有僧請大仙降者是其筆','戴栩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒食無朝謁，閒携載酒車。',48,'全唐诗/poet.song.192000.json','["寒食無朝謁，閒携載酒車。", "燧青宮蠟火，雨白野棠花。", "舊友頻游處，荒阡一酹賒。", "傳聞有仙筆，麗句落僧家。"]'),
('2d50261b-eb35-4ee7-b14a-3892a1b062c2','送蔣德瞻弋陽','戴栩','宋','宋诗','song-poetry','','[]','下車先訪俗，期減月樁銀。',48,'全唐诗/poet.song.192000.json','["下車先訪俗，期減月樁銀。", "廉使舊知己，長官賢過人。", "吏稀中路接，山密道家隣。", "縣譜傳無用，祇將琴譜親。"]'),
('5b27ec63-d2fd-49ac-afe8-a05db9a5ae28','坐中有一桃花自屋棧飛下因而即事','戴栩','宋','宋诗','song-poetry','','[]','幽意靜中見，春風處處通。',48,'全唐诗/poet.song.192000.json','["幽意靜中見，春風處處通。", "層階生暈碧，罅瓦落飄紅。", "禪語關詩趣，寒陰出酒功。", "人家社日近，翠餌搗香蓬。"]'),
('f20b2949-f46b-48db-b306-e92b7ffabafc','送宋君輔迎母往總所','戴栩','宋','宋诗','song-poetry','','[]','步合趨臺閣，人於此去疑。',48,'全唐诗/poet.song.192000.json','["步合趨臺閣，人於此去疑。", "定應中路召，早是十年遲。", "草奏懷邊略，開緘得賀詩。", "從親登賞處，花發小春枝。"]'),
('068217cf-0ea8-416f-a031-05f33a81b9a8','送盧次夔赴仲父校書之詔','戴栩','宋','宋诗','song-poetry','','[]','離家向京國，客思獨從容。',48,'全唐诗/poet.song.192000.json','["離家向京國，客思獨從容。", "有句詩人讀，無書館吏供。", "蟄雷先一月，晴嶺沓千峰。", "馬上思親處，題緘寄所逢。"]'),
('5f0881d0-5a7f-4492-99b6-7397564d9a9a','夏肯父爲先都倉求水心墓誌未得而歸社中諸友皆賦詩送其行','戴栩','宋','宋诗','song-poetry','','[]','文星金石筆，許爾有新銘。',48,'全唐诗/poet.song.192000.json','["文星金石筆，許爾有新銘。", "寬作春風約，歸看宰樹青。", "房留僧閉月，舟渡鴈移汀。", "憑寄梅花酹，先賢必典型。"]'),
('8444f82a-0ba6-44f0-bf9a-2b7c3b937f3f','餞曹西士宰南康','戴栩','宋','宋诗','song-poetry','','[]','君名華省裏，廬嶽未應過。',48,'全唐诗/poet.song.192000.json','["君名華省裏，廬嶽未應過。", "壽日人兼餞，凉風湖際多。", "茶醒憐鶴睡，琴寂聽漁歌。", "候騎新來說，先聲衆已和。"]'),
('75bf3074-a8f5-48ff-b0e3-70432d9ccb6d','送西士之南康','戴栩','宋','宋诗','song-poetry','','[]','祇聽留行語，難工送別詩。',48,'全唐诗/poet.song.192000.json','["祇聽留行語，難工送別詩。", "清才今少比，循吏古爲師。", "水轉朝京路，山迎近縣時。", "種蓮曾有社，應共逸人期。"]'),
('12e5d03c-3fb4-4252-b0b4-0f7bb09eccd5','農家','戴栩','宋','宋诗','song-poetry','','[]','農家何所有，掛壁一鋤犁。',48,'全唐诗/poet.song.192000.json','["農家何所有，掛壁一鋤犁。", "歲計唯供賦，門前自好溪。", "剝麻稭覆日，繰繭蛹分雞。", "不復知炎月，南風焚稲泥。"]'),
('38b23b37-544e-4baa-8a30-1b03da956378','久雨記農父語','戴栩','宋','宋诗','song-poetry','','[]','炊煙不出窟，雨久未知晴。',48,'全唐诗/poet.song.192000.json','["炊煙不出窟，雨久未知晴。", "冷縮秧芽爛，滋含樹耳生。", "南風愁甲換，濕土怕星明。", "朝客慚無補，歸來伴耦耕。"]'),
('34d3242b-dd11-4f13-92a5-54dae119ad3e','眠輕','戴栩','宋','宋诗','song-poetry','','[]','眠輕夢不定，晨戶入踈風。',48,'全唐诗/poet.song.192000.json','["眠輕夢不定，晨戶入踈風。", "清坐一遐想，古人皆大空。", "少言訓俗客，忍事付天公。", "祇了此生足，不嗟吾道窮。"]'),
('e34b8690-f243-48a4-bd1c-18bb0483092e','蔡尚書挽詞二首  其一','戴栩','宋','宋诗','song-poetry','','[]','又報文昌拆，耆儒去玉除。',48,'全唐诗/poet.song.192000.json','["又報文昌拆，耆儒去玉除。", "經綸於世密，趨和與時踈。", "閩地祠常衮，詞臣說仲舒。", "香名五十載，終竟道如初。"]'),
('878ac4cc-9ee8-449f-b8c5-135fd70426c0','蔡尚書挽詞二首  其二','戴栩','宋','宋诗','song-poetry','','[]','廊廟平戎策，詩書諭善箴。',48,'全唐诗/poet.song.192000.json','["廊廟平戎策，詩書諭善箴。", "十年纔一召，未昃忽先陰。", "史局收遺稿，宮寮出賜金。", "門生私慟處，即是萬人心。"]'),
('f16e3c8e-8393-4227-b7c9-2eaac77a3e10','徐少卿挽詞  其一','戴栩','宋','宋诗','song-poetry','','[]','盛業清朝選，香名早歲芳。',48,'全唐诗/poet.song.192000.json','["盛業清朝選，香名早歲芳。", "所忻逢舜禹，寧肯學于張。", "卿月高秋部，恩波徹夜郎。", "誰嗟賢哲事，身外欠周防。"]'),
('95f88eab-95a1-45c4-8a6b-308992f3e610','徐少卿挽詞  其二','戴栩','宋','宋诗','song-poetry','','[]','忽作嚴州夢，難隨上雍班。',48,'全唐诗/poet.song.192000.json','["忽作嚴州夢，難隨上雍班。", "行藏天分巧，夷險世機閒。", "瘴酒雲生綠，銘旌露濕斑。", "保昌鐘梵曉，依舊是家山。"]'),
('5f41dba7-55eb-463b-ace1-53f04c1c9174','陳民表挽詞','戴栩','宋','宋诗','song-poetry','','[]','住僻宜玄晏，門高聚郄詵。',48,'全唐诗/poet.song.192000.json','["住僻宜玄晏，門高聚郄詵。", "沒猶存議論，生豈恨沉淪。", "舊姓符占地，新銘勝寫真。", "登堂曾獨拜，愧見德星人。"]'),
('88dd85fa-912b-47b2-ab1c-36221de05430','奚帑院挽詞二首  其一','戴栩','宋','宋诗','song-poetry','','[]','歷官凡有幾，五駕令君車。',48,'全唐诗/poet.song.192000.json','["歷官凡有幾，五駕令君車。", "健吏猶難色，儒生未必踈。", "廩饑祠有像，鄉飲禮成書。", "惜阻蒲輪召，申公八十餘。"]'),
('623c905b-8d81-4a0c-a4c3-31edb1959ae1','奚帑院挽詞二首  其二','戴栩','宋','宋诗','song-poetry','','[]','藜杖脫朝纓，蕭閒物外情。',48,'全唐诗/poet.song.192000.json','["藜杖脫朝纓，蕭閒物外情。", "問梅添舊句，愛石品新銘。", "鶴侶歸何處，雞牛夢已成。", "中庸餘舊業，留付後儒耕。"]'),
('0158d06b-02a7-4f3a-a2db-c6c5ebd238c5','夏迪簡都倉挽詞','戴栩','宋','宋诗','song-poetry','','[]','聖代難平進，倉官不厭卑。',48,'全唐诗/poet.song.192000.json','["聖代難平進，倉官不厭卑。", "恨無終歲壽，名有上臣知。", "事業空流水，科名在墓碑。", "兒能起門戶，何止繼前基。"]'),
('522f952a-bbe4-43f1-af8e-9edfa652faf7','林酒庫挽詞','戴栩','宋','宋诗','song-poetry','','[]','靜夢鐘催漏，榮恩露眩花。',48,'全唐诗/poet.song.192000.json','["靜夢鐘催漏，榮恩露眩花。", "能鎸題墓語，終認讀書家。", "壤樂齊裘褐，風酸送旐車。", "竹軒孫幾輩，又減鴈行斜。"]'),
('19c0246d-61e6-4632-b2f7-982873a6c4d6','宋叔簡挽詞','戴栩','宋','宋诗','song-poetry','','[]','上國曾隨計，香名衆所聞。',48,'全唐诗/poet.song.192000.json','["上國曾隨計，香名衆所聞。", "百年猶是短，寸祿不霑分。", "笛送鄰家月，樓藏卧處雲。", "生芻何必奠，徐穉有銘文。"]'),
('5b92f8ac-6535-4dba-a313-7bcb1fabafb3','郭伯山挽詞','戴栩','宋','宋诗','song-poetry','','[]','歎息名流遠，西園事亦新。',48,'全唐诗/poet.song.192000.json','["歎息名流遠，西園事亦新。", "辟書三度晚，歸計一庭春。", "魂結憂邊夢，真傳苦學身。", "雙峰寒改色，應爲失高人。"]'),
('218cd0f0-254f-4070-9120-addea2b7a3e4','挽張知縣詞','戴栩','宋','宋诗','song-poetry','','[]','卓絕爲官事，碑銘字畫深。',48,'全唐诗/poet.song.192000.json','["卓絕爲官事，碑銘字畫深。", "萬鈞持重力，一點覺圓心。", "天地空輪跡，賢愚荒草林。", "老來頻閲世，有淚不沾襟。"]'),
('a6738bad-d60c-4836-9a42-71c360b01118','少文挽詞','戴栩','宋','宋诗','song-poetry','','[]','塵外拾科名，儒袍一半青。',48,'全唐诗/poet.song.192000.json','["塵外拾科名，儒袍一半青。", "凄凉余舊友，端的墓新銘。", "池浹騷人墨，山空隠士星。", "沒言猶戒佛，引葬只芻靈。"]'),
('18152394-e862-477a-a48f-909ae86245fa','戴君挽詞','戴栩','宋','宋诗','song-poetry','','[]','舊識黄巖族，與余名姓同。',48,'全唐诗/poet.song.192000.json','["舊識黄巖族，與余名姓同。", "碑呈今日志，君繼古人風。", "活弟寧憐子，通身是至公。", "松岡燐濕雨，讀易玩泉蒙。"]'),
('7e811cda-6377-459b-a6c6-64e57a6dc00c','前休處士余君挽詞','戴栩','宋','宋诗','song-poetry','','[]','事向生前了，名逾死後新。',48,'全唐诗/poet.song.192000.json','["事向生前了，名逾死後新。", "谿山三尺冢，詩酒四時春。", "急義先鄉社，憂民問搢紳。", "蜃江纔一葦，恨阻送車塵。"]'),
('cc5bed4c-4fe3-437f-80d4-9d6fb7fca88b','王秘監夫人挽詞','戴栩','宋','宋诗','song-poetry','','[]','五桂堂深處，霜萱竟不春。',48,'全唐诗/poet.song.192000.json','["五桂堂深處，霜萱竟不春。", "獨從前崦路，重見道山人。", "檢點哀詞衆，推尋碑事真。", "應言嫁時物，縱在亦爲塵。"]'),
('83fe4381-2777-4364-906b-2dc4019d2a26','上丞相壽','戴栩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','玉麒麟表中興瑞，江左風流自韶頀。',192,'全唐诗/poet.song.192000.json','["玉麒麟表中興瑞，江左風流自韶頀。", "我朝宰相越王家，身爲中興開瑞數。", "去年寶獻撲鹿花，春風端門散恩華。", "叢叢萬額扣香穗，祝公壽福逾堤沙。", "披輿地圖上意肯，黄河不渾青海靜。", "經綸有道鼎年多，惠利無邊壺晝永。", "冠蟬衣衮真天人，却笑凌烟色易陳。", "調娛乾坤入掌握，餐茹沆瀣長精神。", "鑪冶小儒蓬室底，倏憶寶從元祐起。", "元祐堂堂森鉅公，亦有文章六君子。", "欲賡烝民繼周雅，筆欠如椽聊爾耳。", "不然從頭頌勳庸，硯蟾應渴西湖水。"]'),
('dc7749e7-c92f-4c47-82a6-cd55ab676fe6','春風行爲判府韓郎中壽','戴栩','宋','宋诗','song-poetry','','[]','鴻濛何物轉膠轕，春風萬里來閶闔。',179,'全唐诗/poet.song.192000.json','["鴻濛何物轉膠轕，春風萬里來閶闔。", "佳哉可愛不可名，協氣穰穰如響答。", "去年浙水皆春波，今年鄞江春最多。", "桃源洞口一披拂，花胎柳骨含天和。", "散作油雲三日雨，田家喜氣充環堵。", "藜腸得米停春雷，共向清流浸秔稌。", "秔稌可種麥可耘，今年上瑞應十分。", "不知化工費多少，化工不自書其勳。", "歸來閶闔門四敞，更展經綸九天上。", "坐令八極一春臺，物物大鈞融溥暢。", "君不見古往今來春復春，春風歲歲長如新。"]'),
('6376c12b-2ad2-46f1-9516-a9d211849c32','題顧愷之畫洛神賦歐陽率更書高宗御跋壽右司','戴栩','宋','宋诗','song-poetry','','[]','建安七子雲錦裳，東阿冠珮儼帝傍。',224,'全唐诗/poet.song.192000.json','["建安七子雲錦裳，東阿冠珮儼帝傍。", "美人依約駐何許，巵言和飾含芳薌。", "虎頭妙處似癡絕，丹青貌出花邊月。", "空詞無色重徘徊，多態有顰轉蕭屑。", "軟風吹香熊耳蒼，蘅臯芝田晴翠長。", "玉笙飄斷牽情夢，羽葆翻開顧影光。", "蘭釵橫峩雙鳳翥，調高不染巫峯雨。", "龍髓生霞謝露鉛，蟬衫如水縈金縷。", "瀛洲學士老率更，服暗編簡誰施嬙。", "平生肝腸忽嫵媚，神氣鈎畫同飛揚。", "閲晉經唐今幾昔，光景常鮮日月白。", "紹興天子曾品題，價重珊瑚何翅百。", "吾聞商雒神靈居，祗今王會臨皇輿。", "願公翊我九疇主，更覩龜呈綠字書。"]'),
('b084481f-abdf-4dc0-8313-6e049fe93e88','楊子京益壯樓','戴栩','宋','宋诗','song-poetry','','[]','征蠻老將何矍鑠，馬如飛龍鎧如石。',144,'全唐诗/poet.song.192000.json','["征蠻老將何矍鑠，馬如飛龍鎧如石。", "不記腥雲毒雨時，苦憶阿游乘下澤。", "纍纍薏苡化明珠，讒夫萋菲何代無。", "說死嗜生非烈士，欲行輒止真賈胡。", "江東領軍今獨步，快劍雄筆風雨過。", "壯骨無身宰樹高，壯懷有弟樓名大。", "樓前萬象供指呼，遠蒼近綠開畫圖。", "榮謝隨時各稚耋，宇宙不改同朝晡。", "請君清坐自探索，此本無虧何所益。"]'),
('acedeb25-e452-49e9-ba6b-590defbfcb3b','次韻盧直院題秀邸所贈春龍出蟄圖','戴栩','宋','宋诗','song-poetry','','[]','中興斷鰲四極立，黄河不動銀河濕。',192,'全唐诗/poet.song.192000.json','["中興斷鰲四極立，黄河不動銀河濕。", "羣龍作御翊天飛，豈有泥蟠初破蟄。", "畫家畫甜難盡神，詩家詩苦空絕塵。", "上聖調合二能事，從此角鬐成活身。", "王門沉沉風鐸語，妙舞停彎歌罷句。", "夜半祥光挾電生，知從所賜春龍處。", "明朝黄麻出漢宮，草麻因贈玉堂翁。", "見者傳觀互矜詫，我爲指點開鴻濛。", "九州未畫一豐草，龍豢於官猶在島。", "後來盛理稱太平，麟鳳不厭郊原小。", "我願萬物常安舒，澤焦潤槁旱已拘。", "百靈有職不相襲，崑崙日月自出入。"]'),
('47fa27f5-ab99-43db-b0e3-7a1da8199956','題吳明輔文集後','戴栩','宋','宋诗','song-poetry','','[]','冰蠶續絲犀琢軫，欲奏南薰終不近。',160,'全唐诗/poet.song.192000.json','["冰蠶續絲犀琢軫，欲奏南薰終不近。", "水心歸宴白玉樓，一代詞華爲渠盡。", "有客觸熱來相過，手挈朗月披煙蘿。", "筆陣森森萬馬肅，夜雪未攪千羣鵝。", "游鞭戲鏑偶獨出，見者驚降什六七。", "掊摘世故窮高深，鈎揣物情懸得失。", "子雲老去方草玄，雕蟲往往羞少年。", "水心不學駢儷語，評麻品制空現前。", "子今古文自星斗，笑殺時流牛馬走。", "人間百短見一長，留此一短無何鄉。"]'),
('885ad0a0-1bf7-4240-8eba-c68fa9bc299e','走筆代書答西士','戴栩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帝城百司官事少，故府庭閑長春草。',256,'全唐诗/poet.song.192000.json','["帝城百司官事少，故府庭閑長春草。", "獨餘人事十倍多，一月束書逾束稿。", "我于其間厭見之，語可摹印百不移。", "深處難論淺處俗，今我下筆如黏黐。", "自得君書手不置，報章颯颯生新意。", "漫將長句替寒溫，臨流勝寄相思字。", "久不哦詩詩律疎，字字偃蹇煩麾呼。", "羨君作邑康廬下，柔强伏梗妥以愉。", "廼知萬事共一法，神熟意便功轉捷。", "聽訟固應哲士能，理賦未省通儒怯。", "往時蔡子尹黄巖，欲試自疑龜屢占。", "祗今登用頗衮衮，似此縣債償亦廉。", "期君規模卓魯上，隨世功名真漫浪。", "幸勿棄我頻琢磨，中年師友半凋喪。", "西湖柳色遞晴陰，蒲江遠矣誰共尋。", "近聞鄉里一奇事，宿覺庵邊祠水心。"]'),
('8ba84873-30f0-4c7e-b827-532c796991b7','捕蝗回奉化泊剡源有感','戴栩','宋','宋诗','song-poetry','','[]','十月五日江信風，小舟摇兀蘆葦叢。',224,'全唐诗/poet.song.192000.json','["十月五日江信風，小舟摇兀蘆葦叢。", "雲端初月吐復翳，時有鸛鶴鳴寒空。", "梓莢離離掛石髮，松蘿矯矯垂羽幢。", "徒步長歌者誰子，乍抑乍揚驚遠厖。", "令人慘淡百感集，呼酒不飲心未降。", "自從作吏涴泥滓，故書蛛網塵滿窗。", "海田無雨種十一，是處奔走祈淵龍。", "龍慵不報蝗四起，茹草啖葉無留蹤。", "早擊暮遮夜秉火，遺子已復同蜩蛩。", "吏無功德可銷變，勉力與爾爭長雄。", "矮屋三間自寒暑，居無十日甘憧憧。", "却憶萊堂應夢我，白雲正隔西南峰。", "人生富貴亦何用，長年菽水勝萬鍾。", "一丘一壑自不惡，我欲從之邴曼容。"]'),
('803e2f3a-0836-44a6-8137-6d4ff3ed5ab9','刈麥行自靈巖歸示趙丞','戴栩','宋','宋诗','song-poetry','','[]','大兒牽衣鐮在手，小兒携篝並畦走。',96,'全唐诗/poet.song.192000.json','["大兒牽衣鐮在手，小兒携篝並畦走。", "陌翁語嫗切莫遲，梅風溫雲晴不久。", "兩手便熟鐮無聲，黄雲捲地蒼坡平。", "一聲長歌出臺笠，麥蛾飛起緣其纓。", "炊煙幕幕暗楊柳，大婦壺飧仍榼酒。", "酒沉飧冷未暇嘗，腰骨酸辛一驤首。"]'),
('8f6348da-0e36-406e-af8f-591e0bc69b97','程郎中生日','戴栩','宋','宋诗','song-poetry','','[]','明光殿前雙侍史，瑞氛曉逐爐烟起。',128,'全唐诗/poet.song.192000.json','["明光殿前雙侍史，瑞氛曉逐爐烟起。", "玉壺一段冰作澌，風流漢署參差是。", "邇來郵館持節歸，御花金带紅氍毹。", "何假通侯聯八座，此真漢相驚單于。", "遐哉東海一萬里，浴日涵星渺無沚。", "只有潮聲似政聲，日夜流傳喧兩耳。", "男耕女織桴鼓閒，四民不動安如山。", "願公端委穆天縡，歌謠處處同東海。"]'),
('90b3c7af-be24-4bfc-ab6e-0756b334fd86','上丞相壽  其一','戴栩','宋','宋诗','song-poetry','','[]','篆金成寶玉成編，春滿東朝萬象妍。',64,'全唐诗/poet.song.192000.json','["篆金成寶玉成編，春滿東朝萬象妍。", "黼衮有尊天子聖，鹽梅無迹上公賢。", "日開喜色臨黄道，風遞和聲下碧躔。", "清曉兩宮齊錫壽，三槐影裏沸傳宣。"]'),
('f4e5294f-2cce-4977-9d19-061595ddb553','上丞相壽  其二','戴栩','宋','宋诗','song-poetry','','[]','宗祊享德本無私，手捧羲輪上玉墀。',64,'全唐诗/poet.song.192000.json','["宗祊享德本無私，手捧羲輪上玉墀。", "犧象潔新親薦處，鳧鷖燕樂守成時。", "重闉昔誦明光賦，碩輔今賡聖德詩。", "一體君臣同五福，無窮無極太平基。"]'),
('0e947f52-f0ac-4389-9871-fa0d85c5ab46','上丞相壽  其三','戴栩','宋','宋诗','song-poetry','','[]','天心妙處不難通，祗愛忠勤與至公。',64,'全唐诗/poet.song.192000.json','["天心妙處不難通，祗愛忠勤與至公。", "雲映禮容呈曉霽，雪符臘令報年豐。", "的於何處容人力，誠到無言是極功。", "試向璇璣觀大象，三台夜夜色齊同。"]'),
('2346b10f-4c4e-4735-bc58-b130e205d960','上丞相壽  其四','戴栩','宋','宋诗','song-poetry','','[]','帝里熙熙笑語閑，新春勝事總相關。',64,'全唐诗/poet.song.192000.json','["帝里熙熙笑語閑，新春勝事總相關。", "眼看長樂鴻名建，心愛淳熙盛象還。", "雪曉萬家沾廩玉，月宵九陌湧燈山。", "昇平此德將誰報，一炷晨香斗柄間。"]'),
('684381fb-396f-43aa-b6b6-d4a0719a0e15','上丞相壽  其五','戴栩','宋','宋诗','song-poetry','','[]','萬釘寶璐價連城，賜敕初宣上不名。',64,'全唐诗/poet.song.192000.json','["萬釘寶璐價連城，賜敕初宣上不名。", "虹彩助成霖雨潤，龍光疊映衮衣榮。", "五湖四海歸蟠際，萬歲千秋侍聖明。", "應笑唐家于闐玉，不於房杜表忠精。"]'),
('51645986-2d86-4613-8897-b8127ca216eb','上丞相壽  其六','戴栩','宋','宋诗','song-poetry','','[]','上傅新加鼎鉉金，辭榮幾度至如今。',64,'全唐诗/poet.song.192000.json','["上傅新加鼎鉉金，辭榮幾度至如今。", "力陳遜表撝謙甚，細想神毫注意深。", "道合明良關數運，禮隆典冊答羣心。", "越王盛業輝煌在，欲把緇衣百遍吟。"]'),
('4c41ba2c-2559-4da0-8e83-b0d8f4d39dbb','上丞相壽  其七','戴栩','宋','宋诗','song-poetry','','[]','聖主千齡不易逢，直應護養到清躬。',64,'全唐诗/poet.song.192000.json','["聖主千齡不易逢，直應護養到清躬。", "觀書子夜勤毋過，頤志宸庭樂自融。", "盛有聰明稱帝舜，深於保輔是周公。", "治平元祐從頭數，此是皇家第一功。"]'),
('f3c457a7-4016-4f99-aa2f-a426fd77b38f','上丞相壽  其八','戴栩','宋','宋诗','song-poetry','','[]','手引羣工上帝庭，常須吉士認儀型。',64,'全唐诗/poet.song.192000.json','["手引羣工上帝庭，常須吉士認儀型。", "一般笙磬方同曲，千古蒿蘭各異馨。", "泰道正應分內外，前賢錯是說調停。", "願歌周雅卷阿什，鳴鳳喈喈梧葉青。"]'),
('4f648891-1815-4e8d-aa39-9889a676b3ae','上丞相壽  其九','戴栩','宋','宋诗','song-poetry','','[]','古來要鎮及邊城，祗在深謀不在兵。',64,'全唐诗/poet.song.192000.json','["古來要鎮及邊城，祗在深謀不在兵。", "廟算何曾有遺策，將臣容易欲要名。", "弱翁持重羌還服，裴度經營蔡自平。", "靖定規模天廣大，會須混一到神京。"]'),
('113ee950-a747-49b6-b3cd-0c8b1e0959d1','上丞相壽  其一○','戴栩','宋','宋诗','song-poetry','','[]','天地深仁不自知，物纔有識荷恩私。',64,'全唐诗/poet.song.192000.json','["天地深仁不自知，物纔有識荷恩私。", "前年倉鑰塵遮面，今日朝班笏拄頤。", "宛若凌虛生羽翮，了無報效及毫絲。", "平生金石不移志，只在鈞陶聽所之。"]'),
('e4e9c987-9e50-4ea7-b287-f057fa981262','賀水心先生七十','戴栩','宋','宋诗','song-poetry','','[]','欲盟鷗鷺老昌湖，其奈君恩未許何。',64,'全唐诗/poet.song.192000.json','["欲盟鷗鷺老昌湖，其奈君恩未許何。", "遲此經綸今日後，定須酬折得年多。", "著書新稿天無盡，閲世閒心海不波。", "七十却嫌人賀壽，繚牆閉雨長庭莎。"]'),
('f1a71e89-e71b-454d-8316-06bc1c2f7ad9','題朝爽軒','戴栩','宋','宋诗','song-poetry','','[]','不須拄笏覓西山，太白峯頭雪未乾。',64,'全唐诗/poet.song.192000.json','["不須拄笏覓西山，太白峯頭雪未乾。", "物景四時俱是爽，江流三面此爲寬。", "慣來幽鳥遺巢在，欲縱香苞和雨寒。", "我有一言君記取，勿栽高樹近欄干。"]'),
('66fbc208-bc6f-4c87-bb0f-a6b9025ab486','題雲嚴寺','戴栩','宋','宋诗','song-poetry','','[]','纔見好山疑近寺，却尋流水入山來。',64,'全唐诗/poet.song.192000.json','["纔見好山疑近寺，却尋流水入山來。", "坡頭上下無平屋，松色中間有落梅。", "越地此方全是海，唐碑其字半生苔。", "萬菴老子吾家客，說到儒門眼倍開。"]'),
('ecc312ec-88a8-4f5b-a68d-6901b5ea1f32','題覺海寺廟二首  其一','戴栩','宋','宋诗','song-poetry','','[]','山頭金碧入層天，下瞰平坡百頃田。',64,'全唐诗/poet.song.192000.json','["山頭金碧入層天，下瞰平坡百頃田。", "靈跡解扶明聖運，斷碑猶記會昌年。", "日飜鳥鵲觚稜過，風落蠨蛸玉帳緣。", "祭罷數翁沙際立，暮潮一舸去翩然。"]'),
('58ba81f0-e2d2-41d7-8755-0a5754d9eefc','題覺海寺廟二首  其二','戴栩','宋','宋诗','song-poetry','','[]','秋雲閣雨暗江天，雨外鋤犁治廢田。',64,'全唐诗/poet.song.192000.json','["秋雲閣雨暗江天，雨外鋤犁治廢田。", "作吏自慙空送日，爾晨何事不逢年。", "荒村獨往無人識，古寺頻來有佛緣。", "暫借茶爐供煮藥，松風遶鼎却泠然。"]'),
('264aede5-dbcc-4fde-a679-6e48d0bf4623','祈雨二古迹','戴栩','宋','宋诗','song-poetry','','[]','已出郊坰曙色微，田翁指點路分岐。',64,'全唐诗/poet.song.192000.json','["已出郊坰曙色微，田翁指點路分岐。", "門前大白劉伶墓，壁上箜篌煬帝祠。", "五斗精神醒亦醉，二妃恩寵死相隨。", "何如一挽天河洗，却爲君刊萬古碑。"]'),
('47900183-32a8-426f-aaf9-a3c8d0bc358b','題方干墓','戴栩','宋','宋诗','song-poetry','','[]','生前知己人誰是，今日人人識姓名。',64,'全唐诗/poet.song.192000.json','["生前知己人誰是，今日人人識姓名。", "葬地不封秋樹死，詩壇空在墓山平。", "子孫零落行人酹，畫像微茫釣渚清。", "惟有寒蟬思凄切，別枝依舊曳殘聲。"]'),
('23913143-1914-469d-9c02-2d3f4f5134ce','大水次友人韻','戴栩','宋','宋诗','song-poetry','','[]','天公豈是出新奇，漲潦茫茫秋暮時。',64,'全唐诗/poet.song.192000.json','["天公豈是出新奇，漲潦茫茫秋暮時。", "牽浪何曾傳雨信，迴南不用掣風旗。", "拍浮甕盎鳴相屬，顛倒籬牆去若馳。", "數日羲和尚羞澁，嫩黄晴影浸清漪。"]'),
('b8ed8a8c-61d0-42f4-846e-cae6a4172f86','和盧直院秋懷','戴栩','宋','宋诗','song-poetry','','[]','因秋又動長年情，老却於秋分外清。',64,'全唐诗/poet.song.192000.json','["因秋又動長年情，老却於秋分外清。", "病骨汗銷衣亦健，水窗影凈日添明。", "有聲無譜寒蛩切，似定還狂暮葉輕。", "不爲鱸魚未歸得，問言微宦欲何成。"]'),
('0807a1d9-c2b3-44c5-bfdc-a9ab32b779f1','答徐提幹移居之問','戴栩','宋','宋诗','song-poetry','','[]','借居僧榻淡於僧，欲築三間屋未能。',64,'全唐诗/poet.song.192000.json','["借居僧榻淡於僧，欲築三間屋未能。", "諸盜忽聞黄榜捷，空園亦喜綠陰增。", "梅天氣濕常留火，草岸蚊多懶近燈。", "自笑病衰無可用，夢中檄就筆飛騰。"]'),
('bd120063-d5c2-47aa-8d27-90b1f9fce8e8','曹徽猷生日二首  其一','戴栩','宋','宋诗','song-poetry','','[]','東皇縹仗下層雲，來駕和風再浹辰。',64,'全唐诗/poet.song.192000.json','["東皇縹仗下層雲，來駕和風再浹辰。", "勳閥此時生鸑鷟，天家滿意抱麒麟。", "方瞳的皪輝遲日，綠鬢扶疎受蚤春。", "太史談公甚奇異，老人星即是前身。"]'),
('d669176c-ae03-4d8d-9a1a-f828de6d5df6','曹徽猷生日二首  其二','戴栩','宋','宋诗','song-poetry','','[]','天聖陰功天下母，慶源重此毓英豪。',64,'全唐诗/poet.song.192000.json','["天聖陰功天下母，慶源重此毓英豪。", "政區賢否澄冰鑑，詩得江山妙線毫。", "已使列城歌既醉，可無衆口賦崧高。", "油幢誰道容溫席，行從君王宴碧桃。"]'),
('9f5b1f7c-8676-42c9-9a04-a5ec53514135','送陳叔方閩縣丞','戴栩','宋','宋诗','song-poetry','','[]','兩年湘岸聽籌聲，又向閩峯住冷廳。',64,'全唐诗/poet.song.192000.json','["兩年湘岸聽籌聲，又向閩峯住冷廳。", "可是初階带朝籍，己聞獨薦起齋鈴。", "秋邊梧葉無風下，旱後苗根一雨青。", "客路方新世路熟，莫將彩筆鬭英靈。"]'),
('ff689c93-fc1b-4ef4-a2a3-94e895219746','送陳漫翁教授官滿赴都下','戴栩','宋','宋诗','song-poetry','','[]','嫩黄千點糝槐枝，此別諸生倍所思。',64,'全唐诗/poet.song.192000.json','["嫩黄千點糝槐枝，此別諸生倍所思。", "判牒署名書字小，開經酬問具餐遲。", "竹邊亭在誰招隠，囊裏書成合濟時。", "東府主人偏愛士，爲歌厦屋杜陵詩。"]'),
('c585257b-3f8e-4046-a7a2-5b927006b1eb','送侯居甫監軍器所門','戴栩','宋','宋诗','song-poetry','','[]','青雲直上不留難，也向神京效一官。',64,'全唐诗/poet.song.192000.json','["青雲直上不留難，也向神京效一官。", "御带禁嚴曹事少，員分省戶薦書寬。", "明時蘭錡曾何用，昨夜邊烽未肯寒。", "定有囊封神廟畧，還同新句寄來看。"]'),
('a1789df4-7d54-4ff0-9651-4c80cce4f057','送蔡子重知松陽縣','戴栩','宋','宋诗','song-poetry','','[]','葉嶺書翻昨夜風，主人應辟出山中。',64,'全唐诗/poet.song.192000.json','["葉嶺書翻昨夜風，主人應辟出山中。", "長淮再定因前畫，小邑頻難試後功。", "辦得分明歸版籍，寫將清靜入絲桐。", "朝堂赴日勤延問，應說無它只至公。"]'),
('d9366c51-98e7-48ca-a2d5-01c46deb3a15','送趙端行殿試','戴栩','宋','宋诗','song-poetry','','[]','杏園詩句定無如，却擬琱弓賜得緋。',64,'全唐诗/poet.song.192000.json','["杏園詩句定無如，却擬琱弓賜得緋。", "立仗陛郎無唱姓，過江宗相有傳衣。", "紅塵輦路桐陰滿，翠箔人家燕子飛。", "過馬傳呼齊指處，鞭絲一半拂金鞿。"]'),
('3fb018a3-559a-4809-be7f-2b3c5ef5e289','送先室歸葬西山','戴栩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','結束遥裝異昔時，江頭送爾一霑衣。',64,'全唐诗/poet.song.192000.json','["結束遥裝異昔時，江頭送爾一霑衣。", "五年客殯依禪寂，千里香魂與夢歸。", "閨美欲書碑易盡，龍封新斸草應稀。", "西山便想西湖是，雲樹深深谷鳥飛。"]'),
('50a7b254-d030-473e-a74a-dbe610c4296e','送廬陵胡季昭夢昱以上濟邸封事貶象州','戴栩','宋','宋诗','song-poetry','','[]','古郡荒凉象迹新，君行况是去裝貧。',64,'全唐诗/poet.song.192000.json','["古郡荒凉象迹新，君行况是去裝貧。", "此愁欲別柳邊雨，明日初程桂外人。", "從古不多如意事，加餐宜惜未歸身。", "春風未必天涯盡，木槲花開瘴水深。"]'),
('79a5d7b1-6c83-4124-89a0-e15e84bb406e','漁浦','戴栩','宋','宋诗','song-poetry','','[]','久慚竊食侶鵷鴻，尚以詩名玷至公。',64,'全唐诗/poet.song.192000.json','["久慚竊食侶鵷鴻，尚以詩名玷至公。", "喜對親慈說田里，了無事鄙到船蓬。", "漲流暫急潮差候，陰靄俄銷月在空。", "夢讀道經人一笑，却憐踈直有仙風。"]'),
('85931d4d-0be5-4aed-9ecc-c697820b7688','趙開府儀國公挽詞  其一','戴栩','宋','宋诗','song-poetry','','[]','郎星卿月遞輝光，忽着蟬冠換鷺行。',64,'全唐诗/poet.song.192000.json','["郎星卿月遞輝光，忽着蟬冠換鷺行。", "人世閲來知幻境，鈞天歸去侍先皇。", "棠陰政惠人人說，花底篇章字字香。", "一段風流埋不得，傳家玉雪照人旁。"]'),
('de74bbaa-335d-48ea-8a90-def0a67951b3','趙開府儀國公挽詞  其二','戴栩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖曾伴玉堂仙，我亦陪登李郭船。',64,'全唐诗/poet.song.192000.json','["西湖曾伴玉堂仙，我亦陪登李郭船。", "便有薦書如舊識，賸懷此意忽重泉。", "西風引旐笳吹咽，東國疏封寶冊鮮。", "如此哀榮將底恨，淚因知己自潸然。"]'),
('2117790a-cc3b-4826-bd6f-3f616527672d','盧直院挽詞','戴栩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','五十一迴春夢中，兄悲子哭愬東風。',64,'全唐诗/poet.song.192000.json','["五十一迴春夢中，兄悲子哭愬東風。", "別司制敕歸天上，不共塵凡住域中。", "幌拂幽絃琴自語，奩遺殘粒藥無功。", "松颸九里凄歌薤，依舊西湖不負公。"]'),
('af9ae049-206f-4c1e-a736-bb3f94d6a0c2','吳狀元兄泳挽詞','戴栩','宋','宋诗','song-poetry','','[]','理學通深藝學高，一官俄逐盛年拋。',64,'全唐诗/poet.song.192000.json','["理學通深藝學高，一官俄逐盛年拋。", "門中晁董刊新誌，海內陳雷哭舊交。", "黄落己空秋半葉，清芬未著臘寒梢。", "魂兮有句重吟否，謝脁山孤月轉坳。"]'),
('ef973583-355d-4fa9-9192-b3e97f47cfff','莆門陳東野挽詞','戴栩','宋','宋诗','song-poetry','','[]','碧海雲邊爲小隠，暮年世味等空濛。',64,'全唐诗/poet.song.192000.json','["碧海雲邊爲小隠，暮年世味等空濛。", "笑看朝友題銜闊，愛共鄰翁話歲豐。", "書述南軒兒自注，詩參東野字應同。", "一丘裘褐甘寒夢，逗曉踈鐘出梵宮。"]'),
('98020131-8f36-4ac8-8520-037f673358dc','挽張金都郎中詞','戴栩','宋','宋诗','song-poetry','','[]','喚作郎官三十年，淡於名爵自應賢。',64,'全唐诗/poet.song.192000.json','["喚作郎官三十年，淡於名爵自應賢。", "摩天靈燄諸生筆，匝地春風使者旃。", "手種路松添墓色，門開族井冽炊泉。", "淳熙耆舊今無幾，忍把豪華萬口傳。"]'),
('5727d06a-1d36-4849-b50c-8314268e32b0','挽林知縣朝奉詞','戴栩','宋','宋诗','song-poetry','','[]','兩拜恩綸世澤垂，皇天老眼未嫌遲。',64,'全唐诗/poet.song.192000.json','["兩拜恩綸世澤垂，皇天老眼未嫌遲。", "百年忽失古君子，四海難逢今吏師。", "祖奠兼排遮道帳，影祠別寫憇棠碑。", "湖堤蓀滿讀書處，雪意將雲萬疊悲。"]'),
('be61638a-ad7d-4c0b-b842-36b1578d25e5','林節推挽詞','戴栩','宋','宋诗','song-poetry','','[]','屋角皇天眼最明，君今吉報在佳城。',64,'全唐诗/poet.song.192000.json','["屋角皇天眼最明，君今吉報在佳城。", "獨僉綠水花邊字，不並黄金砌上行。", "權量無私堪宰物，詩書有澤合銷兵。", "峩峩工部新銘出，安固江流分外清。"]'),
('f8848468-3343-4951-8ef3-e528690f503a','朱邵州挽詞','戴栩','宋','宋诗','song-poetry','','[]','湖湘夢斷兩旌紅，素業俄隨逝水東。',64,'全唐诗/poet.song.192000.json','["湖湘夢斷兩旌紅，素業俄隨逝水東。", "邑政清平民是子，京錢流轉楮如銅。", "祇今吏道通才少，况爾家庭友誼崇。", "欲挽九原無好句，漫同回札寄飛鴻。"]'),
('c5198334-5539-4383-9dd1-63bb7335a81d','挽陳縣尉歌詞','戴栩','宋','宋诗','song-poetry','','[]','欲裁薤曲問耆賢，見說聲華四十年。',64,'全唐诗/poet.song.192000.json','["欲裁薤曲問耆賢，見說聲華四十年。", "六館已推天下士，一官何羨吏中仙。", "白砂舊事漁樵老，縹軸新銘蠟墨鮮。", "便覓當今徐穉筆，榜知如玉在松阡。"]'),
('794a8e1a-057c-4db2-b4d7-1535e286a959','夏運屬挽詞','戴栩','宋','宋诗','song-poetry','','[]','我愧文襄漫述銘，喜聞詩挽遍羣英。',64,'全唐诗/poet.song.192000.json','["我愧文襄漫述銘，喜聞詩挽遍羣英。", "俗媮萬事皆漓薄，子孝重泉獨顯榮。", "著脚官塵能道遠，委身王事不求名。", "故園引得湘江水，依舊東流徹底清。"]'),
('9cd90756-1d45-46c4-a3c5-71f5869b80ce','東山隠士曾公挽詞','戴栩','宋','宋诗','song-poetry','','[]','兒袍已綠鬢絲鮮，尚愛寒檠對夜編。',64,'全唐诗/poet.song.192000.json','["兒袍已綠鬢絲鮮，尚愛寒檠對夜編。", "里不聞喧欽德重，詩能藏巧得名全。", "慈平心是今時佛，隠卧身多晉傳賢。", "曉奠所親凝慟處，憶曾持酒壽新年。"]'),
('31df4506-c721-4fec-a35c-0e902f754f2c','丘處士挽詞','戴栩','宋','宋诗','song-poetry','','[]','自移小隠寄西闤，終是高人性愛閑。',64,'全唐诗/poet.song.192000.json','["自移小隠寄西闤，終是高人性愛閑。", "夢到春潮生荻渚，眼看舊友上蓬山。", "棋聲忽背樵風遠，書影空涵櫂月彎。", "令子相過猶昨日，不堪衰鬢淚霑斑。"]'),
('58b6ee6f-7a29-4744-8c8a-de2acf1211e4','哭周茂洪','戴栩','宋','宋诗','song-poetry','','[]','清襟無物最憐才，怪傲飜從怨口來。',64,'全唐诗/poet.song.192000.json','["清襟無物最憐才，怪傲飜從怨口來。", "於我此生同管鮑，昔人何處覓陳雷。", "龍駒有種長途見，寶鏡無言衆醜猜。", "一慟欲從天外酹，吳門斜日起雲埃。"]'),
('c490503d-84bf-4c79-af78-ec1f8baf64de','徐太博母夫人挽詞','戴栩','宋','宋诗','song-poetry','','[]','孫榮子貴問何如，籩斝盈庭學魯儒。',64,'全唐诗/poet.song.192000.json','["孫榮子貴問何如，籩斝盈庭學魯儒。", "若盡禮宗天下少，縱修彤史古人無。", "歸眠山館還知命，賜吉朝衣得暫娛。", "欲寄升堂千點淚，蘭風吹雨暗前湖。"]'),
('3cbbe0fa-e46e-4c1a-b25e-9451b83f8670','朱尚書夫人洪氏挽詞','戴栩','宋','宋诗','song-poetry','','[]','八座方新玉鉉家，粧臺忽掩五雲賒。',64,'全唐诗/poet.song.192000.json','["八座方新玉鉉家，粧臺忽掩五雲賒。", "徽聲不愧古彤管，覺性能空曇鉢花。", "夜月東岡踈磬度，春風南國去旌斜。", "所親多少酬恩淚，待看重封燎詔麻。"]'),
('98af6743-4f66-4235-9852-43db89506549','裴府陳夫人挽歌詞','戴栩','宋','宋诗','song-poetry','','[]','玉閨還是佛中身，只採蘋花了世塵。',64,'全唐诗/poet.song.192000.json','["玉閨還是佛中身，只採蘋花了世塵。", "閒度芳年孤月曉，貴聯戚畹一庭春。", "青枝路接藁砧近，瑞錦辭翻黄絹新。", "我亦卜鄰平樂里，忍聽歌薤咽清晨。"]'),
('d17117b7-217b-4455-90ae-f598d17bd20f','林孔英岳母盧夫人挽詞','戴栩','宋','宋诗','song-poetry','','[]','南澗承家事遍經，東床得壻衆知名。',64,'全唐诗/poet.song.192000.json','["南澗承家事遍經，東床得壻衆知名。", "縱於人世百年短，添得儒門一倍清。", "科第旋收夫又子，空緣自解歿猶生。", "新阡聞與姑塋近，松靄朝昏管送迎。"]'),
('ed9cf866-c37f-407c-b474-f599fd59cb5d','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其一','戴栩','宋','宋诗','song-poetry','','[]','一徑過寒竹，所知三兩僧。',24,'全唐诗/poet.song.192000.json','["一徑過寒竹，所知三兩僧。", "自憐入山淺，孤立本無朋。"]'),
('8d7303b5-415b-479c-a3c3-8a37eb4a33b9','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其二','戴栩','宋','宋诗','song-poetry','','[]','經年一會面，危坐擁寒灰。',24,'全唐诗/poet.song.192000.json','["經年一會面，危坐擁寒灰。", "絕勝對餘子，一朝來百回。"]'),
('8e71225e-a2cd-41dd-9aec-ed2416a5b135','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其三','戴栩','宋','宋诗','song-poetry','','[]','愛日經簷煖，游蜂撲紙窗。',24,'全唐诗/poet.song.192000.json','["愛日經簷煖，游蜂撲紙窗。", "吾生豈拘束，一笑俯濤江。"]'),
('d1320f74-26d7-4165-9945-1f2dd0294d3d','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其四','戴栩','宋','宋诗','song-poetry','','[]','伊誰同歲晚，懷抱向君開。',24,'全唐诗/poet.song.192000.json','["伊誰同歲晚，懷抱向君開。", "烟雨閟芳信，望君來不來。"]'),
('ed27ffd1-0a1b-40c5-a3c1-11b15176a76a','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其五','戴栩','宋','宋诗','song-poetry','','[]','饑雀啄芳蕾，蠹苔侵碧枝。',24,'全唐诗/poet.song.192000.json','["饑雀啄芳蕾，蠹苔侵碧枝。", "是中渾不較，刻畫未嫌時。"]'),
('71bf159f-1147-4398-8143-c43ab51748c6','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其六','戴栩','宋','宋诗','song-poetry','','[]','曠野多風雪，陽和一點通。',24,'全唐诗/poet.song.192000.json','["曠野多風雪，陽和一點通。", "不應歌兕虎，吾道豈其窮。"]'),
('e2623fb5-a83b-464a-95a9-2dda0ac2d655','官滿寓濟川館得葉嘉仲和朱宰梅花詩次韻云作梅花詩當用歐公雪中酬唱今凡詩家常用字一切屏去乃佳朱令君僕未識面見足下道其語差强人意又與斯君德潤善乃賡此詩以興譬諸草木吾臭味也  其七','戴栩','宋','宋诗','song-poetry','','[]','草木有麟鳳，衆中分等流。',24,'全唐诗/poet.song.192000.json','["草木有麟鳳，衆中分等流。", "終然浪題品，麟鳳自知不。"]'),
