('4b9d46a0-ce86-4ac0-a082-7fefef44f16e','柳耳','李劉','宋','宋诗','song-poetry','','[]','風絮起時無纊塞，雨絲添處有珠垂。',32,'全唐诗/poet.song.192000.json','["風絮起時無纊塞，雨絲添處有珠垂。", "黄鶑說盡千般語，舞困三眠總不知。"]'),
('14f44c1c-91e5-44e0-86d6-a584f903442a','筆陣','李劉','宋','宋诗','song-poetry','','[]','鼓舞先聲自管城，細聽鏖戰了無聲。',32,'全唐诗/poet.song.192000.json','["鼓舞先聲自管城，細聽鏖戰了無聲。", "看來亦異常蛇勢，掃退詞場萬馬兵。"]'),
('cd0e9e9b-f636-46e6-abaf-b5b6c35c34a4','羽扇','李劉','宋','宋诗','song-poetry','','[]','奮迹沖霄駕鶴游，霜毛鞭落在揚州。',32,'全唐诗/poet.song.192000.json','["奮迹沖霄駕鶴游，霜毛鞭落在揚州。", "仁人收拾纔揮動，風被黎元六月秋。"]'),
('6812ae67-55dd-4947-986e-291baf19729c','聞笛','李劉','宋','宋诗','song-poetry','','[]','何處桓伊酒力雄，分明嚼徵更含宮。',32,'全唐诗/poet.song.192000.json','["何處桓伊酒力雄，分明嚼徵更含宮。", "倚樓三弄西風急，不覺梅花大半空。"]'),
('3f520d25-0d3d-4d22-a880-a57d55bac589','麾蚊','李劉','宋','宋诗','song-poetry','','[]','煙驅扇擊手頻撾，奈爾傳呼又滿衙。',32,'全唐诗/poet.song.192000.json','["煙驅扇擊手頻撾，奈爾傳呼又滿衙。", "我醉不眠君不去，下帷高枕任喧嘩。"]'),
('fa7ce750-cf7b-4fd9-a2a6-03e59cd6940e','蟬','李劉','宋','宋诗','song-poetry','','[]','露滿枯腸蛻頓輕，山林那有不平鳴。',32,'全唐诗/poet.song.192000.json','["露滿枯腸蛻頓輕，山林那有不平鳴。", "薰弦寂寞無人續，故揖清風作頌聲。"]'),
('a9750524-264d-4c42-b357-f2746ba8521b','代賀皇太子生日詩二首  其一','李劉','宋','宋诗','song-poetry','','[]','寶月重輪麗虎闈，祥煙葱鬰繞黄麾。',64,'全唐诗/poet.song.192000.json','["寶月重輪麗虎闈，祥煙葱鬰繞黄麾。", "九秋沆碭平分日，萬國元良初度時。", "禮樂詩書俱習慣，聖賢仁孝況生知。", "八荒壽域從今啟，請爲豐年上玉巵。"]'),
('2e213a7b-6851-4221-8e8f-565ad91a59fe','代賀皇太子生日詩二首  其二','李劉','宋','宋诗','song-poetry','','[]','朱芾皇皇問寢門，青宮喜氣滿乾坤。',64,'全唐诗/poet.song.192000.json','["朱芾皇皇問寢門，青宮喜氣滿乾坤。", "江清淮晏干戈息，淵默雷聲匕鬯尊。", "端冕常年親舉禮，遠庖此日剩明恩。", "直將三代齊長久，愿聽長沙賈誼言。"]'),
('f2f86c1c-7955-4ce5-a476-b3ed2b8152cc','又代賀皇太子生日詩二首  其一','李劉','宋','宋诗','song-poetry','','[]','銀盤浴兔方二日，寶冊蟠龍甫半旬。',64,'全唐诗/poet.song.192000.json','["銀盤浴兔方二日，寶冊蟠龍甫半旬。", "甲觀誕彌佳氣鬰，春宮衍慶縟儀新。", "前星色正光芒遠，少海波清潤澤均。", "鶴駕歸來傳密語，更將仁義域斯民。"]'),
('643fcbdb-7452-43fb-aaf7-7f8db14983e0','又代賀皇太子生日詩二首  其二','李劉','宋','宋诗','song-poetry','','[]','粲粲祥煙繞虎闈，歡聲催捧未央巵。',64,'全唐诗/poet.song.192000.json','["粲粲祥煙繞虎闈，歡聲催捧未央巵。", "干戈東序承平日，衮冕南郊負見時。", "行中鸞和真合禮，宴陪魚藻舊聞詩。", "宮僚慚愧非周召，三善惟當效祝規。"]'),
('e4402f49-71de-40fa-8e3a-9fbbaab6f503','賀參政二首  其一','李劉','宋','宋诗','song-poetry','','[]','海山俯視百川東，中有明堂一柱隆。',64,'全唐诗/poet.song.192000.json','["海山俯視百川東，中有明堂一柱隆。", "兩社直從平地到，寸心原共老天通。", "管樂功烈非軻志，堯舜君民在尹躬。", "壽國端須壽君子，願將箕翼等延洪。"]'),
('e83fbc01-f3a5-4ef8-bc9d-62235e7c4f05','賀參政二首  其二','李劉','宋','宋诗','song-poetry','','[]','東府西樞紀誕辰，非烟郁郁更紛紛。',64,'全唐诗/poet.song.192000.json','["東府西樞紀誕辰，非烟郁郁更紛紛。", "共知崧岳生申伯，競把旃檀壽卯君。", "燮理已成六月雨，經綸更作八荒雲。", "齊安即是安天下，敢爲先生誦所聞。"]'),
('dd3b6cf9-154b-40fa-9498-edcfc6d9630c','慶瀘帥魏侍郎二首  其一','李劉','宋','宋诗','song-poetry','','[]','中庸日用脚根實，動靜天機眼力親。',64,'全唐诗/poet.song.192000.json','["中庸日用脚根實，動靜天機眼力親。", "未月鳳筩鍾地統，戌年麟跋紀生辰。", "身名宿世陳忠肅，眉壽他年范景仁。", "福祿近來賢否共，欲將斯道覺斯民。"]'),
('828c8e9f-fb14-45eb-a3c8-3b3c3022aecc','慶瀘帥魏侍郎二首  其二','李劉','宋','宋诗','song-poetry','','[]','碧油滿眼詩書帥，紫橐駢肩獻納臣。',64,'全唐诗/poet.song.192000.json','["碧油滿眼詩書帥，紫橐駢肩獻納臣。", "有客皆能歌保魯，如公方合美生申。", "莊椿坐閲人間世，嶰竹早吹天上春。", "士曰時哉起君實，只今猶可却遼人。"]'),
('a3bb0b7f-b09b-4fc9-b4ec-f30743d5a6c3','慶桂帥經略二首  其一','李劉','宋','宋诗','song-poetry','','[]','江漢浮浮炳地靈，參旗井鉞壽星明。',64,'全唐诗/poet.song.192000.json','["江漢浮浮炳地靈，參旗井鉞壽星明。", "庚寅初度周而始，戊己連營靜不驚。", "山上印成龜左顧，月中桂共兔長生。", "公堂遥想稱觴後，便報天階取履聲。"]'),
('8aecde0a-7048-4dcd-90b9-0494773b84d2','慶桂帥經略二首  其二','李劉','宋','宋诗','song-poetry','','[]','煌煌昴宿正開冬，日馭高躔龍尾宮。',64,'全唐诗/poet.song.192000.json','["煌煌昴宿正開冬，日馭高躔龍尾宮。", "賚說須知應天策，留蕭暫委守關中。", "赤雲决勝三邊壯，白日褰晴五穀豐。", "六十州人開壽域，碧幢一笑與民同。"]'),
('18f51814-1938-4184-8192-61cd7bc0a598','壽瀘帥楊尚書  其一','李劉','宋','宋诗','song-poetry','','[]','八年黄伯潁川政，十載武侯瀘水功。',64,'全唐诗/poet.song.192000.json','["八年黄伯潁川政，十載武侯瀘水功。", "還向碧幢揆初度，但愁綠詔啟元戎。", "生從峻極崧高降，壽在慈祥豈弟中。", "今歲添杯添福祿，膝前文度伴仙翁。"]'),
('7aa0faf8-05a4-4426-88a8-f16b544f21a4','壽瀘帥楊尚書  其二','李劉','宋','宋诗','song-poetry','','[]','尚書清稟秋天杳，吉夢元占玉燕飛。',64,'全唐诗/poet.song.192000.json','["尚書清稟秋天杳，吉夢元占玉燕飛。", "南定三軍須北定，西歸九罭合東歸。", "壽星出丙光丹極，華蓋丞辰近紫薇。", "要減汾陽聲樂半，直須揚濯入黄扉。"]'),
('6066d937-a071-41c1-aab2-27258282256e','壽漕使','李劉','宋','宋诗','song-poetry','','[]','金牀玉兔歲重逢，初度占星尚劍東。',64,'全唐诗/poet.song.192000.json','["金牀玉兔歲重逢，初度占星尚劍東。", "鐵馬未容耕渭上，木牛且合漕關中。", "雲屯營壘樵蘇飽，雨足郊原菽粟豐。", "更與坤垠開壽域，皇華一笑與民同。"]'),
('bea5e4bf-023f-4739-91ed-a898669b298d','壽提管','李劉','宋','宋诗','song-poetry','','[]','滿廊香霧弄霏霏，欲去還留燕子飛。',64,'全唐诗/poet.song.192000.json','["滿廊香霧弄霏霏，欲去還留燕子飛。", "酒盞自便秋思早，花枝未怯鬢毛非。", "脫巾駡灌從狂醉，剪燭留髠好緩歸。", "我欲寄君無傑語，安期大棗薦青璣。"]'),
('97bc97c1-c1ef-4086-9e72-f70dcff61cd2','慶劉教授','李劉','宋','宋诗','song-poetry','','[]','萬里秋風生桂枝，麒麟墮地有誰知。',64,'全唐诗/poet.song.192000.json','["萬里秋風生桂枝，麒麟墮地有誰知。", "摩空早奏甘泉賦，取勢猶歌泮水詩。", "好是桑蓬浮喜氣，正栽桃李助清詩。", "銀袍爭願公衣鉢，應指湘山無量師。"]'),
('2ee1aa6a-4220-4cb4-809a-a7ae5f908044','賀舍弟新得子','李劉','宋','宋诗','song-poetry','','[]','早來乾鵲鳴簷楹，報我庭階玉樹生。',64,'全唐诗/poet.song.192000.json','["早來乾鵲鳴簷楹，報我庭階玉樹生。", "告白祖宗知積善，喧傳奴婢總歡聲。", "遠增阿大中郎喜，足想殊常散騎情。", "點校六經留汝讀，吾家元不蓄金籝。"]'),
('dced0815-7e8c-49d0-b194-052813fd2e53','賀生次子又喜領薦','李劉','宋','宋诗','song-poetry','','[]','君家蘭玉滿庭除，尤喜徐卿第二雛。',64,'全唐诗/poet.song.192000.json','["君家蘭玉滿庭除，尤喜徐卿第二雛。", "方遂鵬程收鶚薦，又符熊夢獲驪珠。", "史山孕秀頭顱別，秋水爲神骨骼殊。", "況有義方嚴訓在，早看騰踏上雲衢。"]'),
('c6dccfc5-bfe9-4fb9-871e-6e9fd9c9501e','送甥回崇仁','李劉','宋','宋诗','song-poetry','','[]','萬里七年艱險同，我車西去子舟東。',64,'全唐诗/poet.song.192000.json','["萬里七年艱險同，我車西去子舟東。", "教兒强學先循理，嫁女隨宜莫諱窮。", "注就歐詩勤琢削，續成漢紀更磨礲。", "鄉人借問碧雞使，萬卷書中一老翁。"]'),
('a2fda499-6b8f-4fc2-a184-0981a6747ff6','贈刻圖書處士二首  其一','李劉','宋','宋诗','song-poetry','','[]','信手揮斤出古文，商盤秦鼎失精神。',32,'全唐诗/poet.song.192000.json','["信手揮斤出古文，商盤秦鼎失精神。", "煩君惜取鑄金手，留待人間周伯仁。"]'),
('21a7abaf-f2ab-4165-842e-a2d869610ec1','贈刻圖書處士二首  其二','李劉','宋','宋诗','song-poetry','','[]','我乏君家玉印材，强尋厄木倩君開。',32,'全唐诗/poet.song.192000.json','["我乏君家玉印材，强尋厄木倩君開。", "無鹽恐有遭逢處，也道曾將刻畫來。"]'),
('5aedfcb7-3547-40dc-9481-19221bc31463','壽劉宰','李劉','宋','宋诗','song-poetry','','[]','製錦新城衣錦歸，種桃遺愛滿桃蹊。',64,'全唐诗/poet.song.192000.json','["製錦新城衣錦歸，種桃遺愛滿桃蹊。", "恩波淮水流不盡，福力螺山高與齊。", "天上已催班玉筍，日邊行見月璇題。", "歡聲都是長生曲，薰作香雲覆寶猊。"]'),
('eacfbcfe-80e4-4efc-80a2-22d5a2cefbd9','壽帥閫','李劉','宋','宋诗','song-poetry','','[]','盛德元勳絕等倫，麟符虎節冠宗臣。',64,'全唐诗/poet.song.192000.json','["盛德元勳絕等倫，麟符虎節冠宗臣。", "大椿上古身千歲，一柱明堂力萬鈞。", "坐鎮熊羆瞻綉衮，燕居松鶴伴綸巾。", "只應便是神仙事，萬丈蓬萊却未真。"]'),
('69119c6a-a0a3-4873-8e76-cdeee952ca90','壽教授','李劉','宋','宋诗','song-poetry','','[]','襟懷錦綉富多文，人物冰壺絕點塵。',64,'全唐诗/poet.song.192000.json','["襟懷錦綉富多文，人物冰壺絕點塵。", "太華昨宵方誕呂，姑蘇今日恰生申。", "堂萱呈瑞年年綠，壇杏逢春日日新。", "更爲南豐添一瓣，即看趣詔侍嚴宸。"]'),
('848f1002-61a7-4023-ab0d-5f83df50cab5','壽先生  其一','李劉','宋','宋诗','song-poetry','','[]','明善堂前香矗雲，諸生再拜祝莊椿。',64,'全唐诗/poet.song.192000.json','["明善堂前香矗雲，諸生再拜祝莊椿。", "芹香藻綠涵和氣，楓老梅疏健小春。", "有道可爲明主佐，無氈休嘆廣文貧。", "烹羔壓酒稱千壽，會看仙桃着子新。"]'),
('53d0c957-2130-4a3e-bb99-0d8d528a0801','壽先生  其二','李劉','宋','宋诗','song-poetry','','[]','今年生日勝常年，一佛中間萬佛緣。',64,'全唐诗/poet.song.192000.json','["今年生日勝常年，一佛中間萬佛緣。", "善念纔興方寸地，恩光便下九重天。", "花香作供圍方丈，粟粒成功福大千。", "長壽如來更多寶，飽參住世小乘禪。"]'),
('0f5dfcc0-a153-4c9d-856e-76553746e024','壽太守','李劉','宋','宋诗','song-poetry','','[]','蓂飛兩葉正深春，是日人間嶽降神。',64,'全唐诗/poet.song.192000.json','["蓂飛兩葉正深春，是日人間嶽降神。", "自昔詞章推大手，即今風采見埋輪。", "書傳黄石由來遠，名壓青錢孰與倫。", "壽祿祈公如萬福，未應江海羨鱸蒪。"]'),
('3ca0e724-be84-4ab6-86d1-e54b0bec6760','壽縣尉','李劉','宋','宋诗','song-poetry','','[]','華陽傳與純陽訣，竹隠中間悟養生。',64,'全唐诗/poet.song.192000.json','["華陽傳與純陽訣，竹隠中間悟養生。", "止心情澄不撓濁，浮雲富貴澹無營。", "龍鉛虎籙交離坎，鶴算龜齡幾甲庚。", "喚起吟壇稱壽句，夜來一點壽星明。"]'),
('074017cb-031d-45fd-9e7a-cd35a3054c78','壽翁權縣','李劉','宋','宋诗','song-poetry','','[]','昴宿騰輝落建溪，鴛鴻兄弟步雲梯。',64,'全唐诗/poet.song.192000.json','["昴宿騰輝落建溪，鴛鴻兄弟步雲梯。", "暫收鸞翼來棲棘，聊鼓牛刀爲割雞。", "三月鳴琴初布政，萬家磨石擬鎸題。", "情知百里難淹驥，行看天書下紫泥。"]'),
('d72f15fb-6fc2-4244-b66c-fbc2580e9e70','壽牛都大','李劉','宋','宋诗','song-poetry','','[]','律中黄鍾九日前，長淮巨海降真賢。',64,'全唐诗/poet.song.192000.json','["律中黄鍾九日前，長淮巨海降真賢。", "鵬程九萬快摶擊，騋牝三千表塞淵。", "夜看牛星貫南極，早携鶴馭出西川。", "梅花歲歲橫參影，長伴羅浮不老仙。"]'),
('f567f21e-aa14-4682-868c-bccc17155401','壽友人','李劉','宋','宋诗','song-poetry','','[]','探勝東風一夜先，燕堂絲管沸華筵。',64,'全唐诗/poet.song.192000.json','["探勝東風一夜先，燕堂絲管沸華筵。", "魚軒並壽歡何極，鳳穴添雛慶愈綿。", "獨樂園中閑日月，香山圖裏永神仙。", "磻溪自有安車到，屈指佳期祇六年。"]'),
('0635edbe-ffdc-4e32-bc35-fcf3a21c168e','壽友人林仲喬','李劉','宋','宋诗','song-poetry','','[]','十分國艷貪春煖，一簇芳心襯曉霞。',32,'全唐诗/poet.song.192000.json','["十分國艷貪春煖，一簇芳心襯曉霞。", "送與生朝添壽斝，洛陽年少洛陽花。"]'),
('c7205d4b-9333-4262-a649-bad27e65e3cc','自壽','李劉','宋','宋诗','song-poetry','','[]','光景不相待，流年劇箭過。',48,'全唐诗/poet.song.192000.json','["光景不相待，流年劇箭過。", "酸辛前詔左，科甲後生多。", "命蹇窮爲祟，愁多睡作魔。", "蓋棺方事定，有酒且高歌。"]'),
('e536ab81-2374-4a42-8bdd-a44011a8d318','賀晚生子','李劉','宋','宋诗','song-poetry','','[]','商瞿五十子何遲，佳氣充閭慶可知。',64,'全唐诗/poet.song.192000.json','["商瞿五十子何遲，佳氣充閭慶可知。", "喜溢麟生天上日，夢回虎墮月中時。", "犀錢賸送沾佳客，麝顆輕塗付侍兒。", "英物從來聲自別，試啼容我一聽之。"]'),
('95acd39d-1efb-4c6b-88e0-52b5bdfb7bd9','賀晚生子','李劉','宋','宋诗','song-poetry','','[]','蘭玉森森天下奇，靈椿猶自長新枝。',64,'全唐诗/poet.song.192000.json','["蘭玉森森天下奇，靈椿猶自長新枝。", "從來老蚌珠生晚，豈是長庚夢到遲。", "標格銀蟾光皎潔，精神秋水碧漣漪。", "玉皇案吏家聲近，佇看追蹤入鳳池。"]'),
('6f16f2a6-7e2a-4cd0-a053-7bd5d7d500ee','慶尚書八十','李劉','宋','宋诗','song-poetry','','[]','寶唐佳氣夜充閭，八十尚書古所無。',64,'全唐诗/poet.song.192000.json','["寶唐佳氣夜充閭，八十尚書古所無。", "勘破趙州行脚案，展開老子出關圖。", "五房孫各了官事，千戶侯封食稅租。", "若問蹯溪釣漁叟，先生應道沒工夫。"]'),
('eb05afd5-e254-4386-9a69-2e7a62483632','壽成都黄副帥二首  其一','李劉','宋','宋诗','song-poetry','','[]','王正初生七葉蓂，斗牛間氣出延平。',64,'全唐诗/poet.song.192000.json','["王正初生七葉蓂，斗牛間氣出延平。", "次公恰恰九年最，叔度汪汪千頃清。", "濟北一編煩展究，劍西半壁頼生成。", "且傾江漢朝宗水，濟彼公堂薦壽觥。"]'),
('9dba088a-91b3-4121-ac69-a72bd7a29946','壽成都黄副帥二首  其二','李劉','宋','宋诗','song-poetry','','[]','玉帳公弓應六蓬，瓣香遥遺賀南豐。',64,'全唐诗/poet.song.192000.json','["玉帳公弓應六蓬，瓣香遥遺賀南豐。", "捫參以手誰憐汝，居井之眉我倚公。", "壽域八荒隨氣轉，醉鄉五福與民同。", "老𢋙不是青冥脚，也願追隨龜鶴東。"]'),
('e6bdd6f8-66eb-4f11-8697-e3878e4afa26','登謝屐亭贈謝行之','葉紹翁','宋','宋诗','song-poetry','','[]','君家靈運有山癖，平生費却幾緉屐。',176,'全唐诗/poet.song.192000.json','["君家靈運有山癖，平生費却幾緉屐。", "從人喚渠作山賊，內史風流定誰識。", "西窗小憩足力疲，夢賦池塘春草詩。", "只今屐朽詩不朽，五字句法誰人追。", "天台覽遍興未已，天竺山前聽流水。", "秦人稱帝魯連耻，寧向蒼苔留屐齒。", "乙庵是渠幾世孫，登山認得屐齒痕。", "摩挲苔石坐良久，便欲老此巖之根。", "吾儂勸渠且歸去，請君更學遥遥祖。", "遥遥之祖定阿誰，曾出東山作霖雨。", "乙庵未省却問儂，莫是當年折屐翁。"]'),
('8b5b63ae-dce6-40e4-a949-6839da58d3d8','西湖秋晚','葉紹翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','愛山不買城中地，畏客長撐屋後船。',32,'全唐诗/poet.song.192000.json','["愛山不買城中地，畏客長撐屋後船。", "荷葉無多秋事晚，又同鷗鷺過殘年。"]'),
('605db153-df48-43dd-99cb-823e87be7f10','題鄂王墓','葉紹翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬古知心只老天，英雄堪恨復堪憐。',64,'全唐诗/poet.song.192000.json','["萬古知心只老天，英雄堪恨復堪憐。", "如公更緩須臾死，此虜安能八十年。", "漠漠凝塵空偃月，堂堂遺像在凌煙。", "早知埋骨西湖路，學取鴟夷理釣船。"]'),
('b568bda1-4124-4476-b025-982fad190a67','聞頂山徐道人改卜','葉紹翁','宋','宋诗','song-poetry','','[]','先生新卜宅，只許白雲知。',48,'全唐诗/poet.song.192000.json','["先生新卜宅，只許白雲知。", "野蜜和蜂割，巖花带蝶移。", "坐諳苔石穩，醉忘木橋危。", "屋後寒梅放，因風寄一枝。"]'),
('53d114ff-35cf-47c1-af7b-362be74e63fd','游園不值','葉紹翁','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u6e38\u56ed", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406", "\u5b8b\u8bd7"]','應嫌屐齒印蒼苔，十扣柴門九不開。',32,'全唐诗/poet.song.192000.json','["應嫌屐齒印蒼苔，十扣柴門九不開。", "春色滿園關不住，一枝紅杏出牆來。"]'),
('2be4157d-77b5-4ec5-a80b-6f462222640d','仙興','葉紹翁','宋','宋诗','song-poetry','','[]','金書宮殿玉闌干，雪瀑泉飛洞口寒。',32,'全唐诗/poet.song.192000.json','["金書宮殿玉闌干，雪瀑泉飛洞口寒。", "日暮仙翁騎鶴去，碧桃花滿石棋盤。"]'),
('79b46752-63a1-426a-abe3-943b61ccc08f','秋日遊龍井','葉紹翁','宋','宋诗','song-poetry','','[]','引道煩雙鶴，携囊倩一童。',48,'全唐诗/poet.song.192000.json','["引道煩雙鶴，携囊倩一童。", "竹光杯影裏，人語水聲中。", "不雨雲常濕，無霜葉自紅。", "我來何所事，端爲聽松風。"]'),
('3d7656de-8aef-4466-9df1-56422927ea41','出北關二里','葉紹翁','宋','宋诗','song-poetry','','[]','脫衣命僕洗塵埃，籬落人家未見梅。',32,'全唐诗/poet.song.192000.json','["脫衣命僕洗塵埃，籬落人家未見梅。", "出得城門能幾步，船頭便有白鷗來。"]'),
('ff3e2333-25e4-4f93-8b0c-5b2948663f19','野蝶','葉紹翁','宋','宋诗','song-poetry','','[]','銀爲鬚翅粉爲肌，驅役春風不解肥。',32,'全唐诗/poet.song.192000.json','["銀爲鬚翅粉爲肌，驅役春風不解肥。", "桃李上林無分到，可憐却傍菜花飛。"]'),
('2651a6ee-5d71-4a45-9a63-7a085b6fd75a','嘉興界','葉紹翁','宋','宋诗','song-poetry','','[]','平野無山見盡天，九分蘆葦一分烟。',32,'全唐诗/poet.song.192000.json','["平野無山見盡天，九分蘆葦一分烟。", "悠悠綠水分枝港，撐出南鄰放鴨船。"]'),
('f510da54-826e-4694-9012-117a7c34ea40','煙村','葉紹翁','宋','宋诗','song-poetry','','[]','隠隠煙村聞犬吠，欲尋尋不見人家。',32,'全唐诗/poet.song.192000.json','["隠隠煙村聞犬吠，欲尋尋不見人家。", "只於橋斷溪回處，流出碧桃三數花。"]'),
('acac1411-9b95-4a4e-b5e5-e01c9945d0f7','石頭感古','葉紹翁','宋','宋诗','song-poetry','','[]','夷甫諸人者，龜趺已故丘。',48,'全唐诗/poet.song.192000.json','["夷甫諸人者，龜趺已故丘。", "但能揮玉麈，不解冠兜鍪。", "正朔從江左，經營僅石頭。", "中原雖可望，不忍上層樓。"]'),
('077ffbe3-b931-433d-9d4f-205e70e1285b','葛天民隠居','葉紹翁','宋','宋诗','song-poetry','','[]','種竹成新列，移蘭即舊陰。',48,'全唐诗/poet.song.192000.json','["種竹成新列，移蘭即舊陰。", "老鐺猶有耳，古柳已無心。", "得句添杯滿，貪爐到夜深。", "篝燈聊點校，春水沒衣砧。"]'),
('9007fe6e-3170-405c-a63d-9148ce264ac9','九日呈真直院','葉紹翁','宋','宋诗','song-poetry','','[]','秋風吹客客思家，破帽從渠自在斜。',32,'全唐诗/poet.song.192000.json','["秋風吹客客思家，破帽從渠自在斜。", "腸斷故山歸未得，借人籬落種黄花。"]'),
('bb856488-ef30-441b-afcf-8c0638d3df86','貴遊','葉紹翁','宋','宋诗','song-poetry','','[]','五陵年少儘風流，十日安排一日遊。',32,'全唐诗/poet.song.192000.json','["五陵年少儘風流，十日安排一日遊。", "林下幽人差省事，筆床茶竈便登舟。"]'),
('a3c64547-7d60-4c26-a5d6-74fdf1f8d21e','寓居  其一','葉紹翁','宋','宋诗','song-poetry','','[]','雲補青山缺，琴銷白日長。',48,'全唐诗/poet.song.192000.json','["雲補青山缺，琴銷白日長。", "鷗從雨外沒，蛇入樹間藏。", "客久衣常黑，童蠻髮半黄。", "螢多鄰舍少，此意自凄凉。"]'),
('af0e44ec-e5fc-4074-aca8-5f448bfa20da','寓居  其二','葉紹翁','宋','宋诗','song-poetry','','[]','無酒難留客，借書方入城。',48,'全唐诗/poet.song.192000.json','["無酒難留客，借書方入城。", "洗衣知水落，貪睡畏窗明。", "野竹藤纒殺，枯枝草寄生。", "十年林下隠，差覺世緣輕。"]'),
('800f8c65-f2bb-4a69-b9d4-6d70f7c8238e','田家三詠  其一','葉紹翁','宋','宋诗','song-poetry','','[]','織籬爲界編紅槿，排石成橋接斷塍。',32,'全唐诗/poet.song.192000.json','["織籬爲界編紅槿，排石成橋接斷塍。", "野老生涯差省事，一間茅屋兩池菱。"]'),
('0eb2ad82-9320-4fb9-bcd3-72c13594cba9','田家三詠  其二','葉紹翁','宋','宋诗','song-poetry','','[]','田因水壞秧重插，家爲蠶忙戶緊關。',32,'全唐诗/poet.song.192000.json','["田因水壞秧重插，家爲蠶忙戶緊關。", "黄犢歸來莎草闊，綠桑采盡竹梯閑。"]'),
('73f3ae27-f652-486b-98cb-cb19c98ee5ab','田家三詠  其三','葉紹翁','宋','宋诗','song-poetry','','[]','抱兒更送田頭飯，畫鬢濃調竈額煙。',32,'全唐诗/poet.song.192000.json','["抱兒更送田頭飯，畫鬢濃調竈額煙。", "爭信春風紅袖女，綠楊庭院正秋千。"]'),
('db9aa54b-4a83-483a-a484-5a9364832a5b','送馮濟川歸蜀','葉紹翁','宋','宋诗','song-poetry','','[]','勇喚東吳萬里船，皂囊來奏九重天。',64,'全唐诗/poet.song.192000.json','["勇喚東吳萬里船，皂囊來奏九重天。", "一官豈爲蘇洵冗，諸老寧容賈誼先。", "滿載月歸應有命，便耕雲去豈無田。", "竹枝歌罷篷窗掩，到此相思倍黯然。"]'),
('5c9f7eb8-e6aa-4425-a720-f521e50cfe9f','賦葛天民栽葦','葉紹翁','宋','宋诗','song-poetry','','[]','葉礙漁舟入，叢分水國寬。',48,'全唐诗/poet.song.192000.json','["葉礙漁舟入，叢分水國寬。", "低回藏鷺渚，彷彿釣魚竿。", "蕩戶和萍送，溪翁當竹看。", "所憐如許節，不耐雪霜寒。"]'),
('25f21e45-1714-4bf4-b48f-b9724ae80eec','田舍小憩','葉紹翁','宋','宋诗','song-poetry','','[]','犬馴迎且吠，兒小笑還啼。',48,'全唐诗/poet.song.192000.json','["犬馴迎且吠，兒小笑還啼。", "櫻熟施魚網，桑空卧竹梯。", "枯枝禽啄折，野草鹿眠低。", "屋後登山路，牛欄更向西。"]'),
('47397a9b-16a4-4f41-a94b-f81cfa059c6a','青溪閣','葉紹翁','宋','宋诗','song-poetry','','[]','江總能文士，空貽狎客名。',48,'全唐诗/poet.song.192000.json','["江總能文士，空貽狎客名。", "舊基荒草占，廢圃野人耕。", "古柳無多樹，新蟬第一聲。", "青溪固亡恙，依舊與孤城。"]'),
('64f3a5d1-af92-4e85-91b3-d64e77fa85aa','訪隠者','葉紹翁','宋','宋诗','song-poetry','','[]','不作王門夢，來敲隠者關。',48,'全唐诗/poet.song.192000.json','["不作王門夢，來敲隠者關。", "童先孤鶴化，雲伴一身閑。", "礙笋新移路，低牆爲看山。", "幾回松下去，鋤得茯苓還。"]'),
('049d7095-a49e-40ae-a7db-289f7c98acab','幽居書事','葉紹翁','宋','宋诗','song-poetry','','[]','窗開雙佛塔，水遶數魚家。',48,'全唐诗/poet.song.192000.json','["窗開雙佛塔，水遶數魚家。", "酒剩沾鄰里，時平買釣車。", "童閑唯伴鶴，樹老自成槎。", "枕上關心事，侵晨掃落花。"]'),
('62c7ffbe-2bdb-47ad-aaa7-c9eddd8b6f2f','訪龍井山中村叟','葉紹翁','宋','宋诗','song-poetry','','[]','雨打荒籬豆莢垂，柴門未啟立多時。',32,'全唐诗/poet.song.192000.json','["雨打荒籬豆莢垂，柴門未啟立多時。", "客來自掘蹲鴟煮，旋拾枯松三數枝。"]'),
('fcab67b4-4476-4db6-b0a3-0d161f5e2d21','西溪','葉紹翁','宋','宋诗','song-poetry','','[]','一條橫木過前溪，村女齊登採葉梯。',32,'全唐诗/poet.song.192000.json','["一條橫木過前溪，村女齊登採葉梯。", "獨立衡門春雨細，白鷄飛上樹梢啼。"]'),
('15297c44-6879-45d1-97ca-ca69dd51f5fe','和葛天民呈吳韜仲韻賦其庭館所有','葉紹翁','宋','宋诗','song-poetry','','[]','江遠潮痕細，城回路勢斜。',48,'全唐诗/poet.song.192000.json','["江遠潮痕細，城回路勢斜。", "竹行穿砌笋，風墮過牆花。", "篆葉蟲留字，銜泥燕理家。", "主人清到骨，相對只杯茶。"]'),
('eebb0038-86d3-45b8-8fe3-7e72b9d4a943','敬陪直院右史上巳後一日西齋之集','葉紹翁','宋','宋诗','song-poetry','','[]','清時天上詔書稀，曲水從游許布衣。',64,'全唐诗/poet.song.192000.json','["清時天上詔書稀，曲水從游許布衣。", "插羽滿浮寒食酒，倚欄同憶故山薇。", "碧桃繞觀春風靜，柔樐摇汀夕照微。", "慨想蘭亭如昨日，沙鷗飛下釣魚磯。"]'),
('f8771f42-a091-4795-a61e-2a9c73cb2b34','贈陳宗之  其一','葉紹翁','宋','宋诗','song-poetry','','[]','官河深水綠悠悠，門外梧桐數葉秋。',32,'全唐诗/poet.song.192000.json','["官河深水綠悠悠，門外梧桐數葉秋。", "中有武林陳學士，吟詩銷遣一生愁。"]'),
('7451f75d-6afa-4cf3-9f25-b823db158e2b','贈陳宗之  其二','葉紹翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十載京塵染布衣，西湖煙雨與心違。',32,'全唐诗/poet.song.192000.json','["十載京塵染布衣，西湖煙雨與心違。", "隨車尚有書千卷，擬向君家賣却歸。"]'),
('1ac01529-b566-47d4-9f08-6ba7d0c32e74','題山間老友壁','葉紹翁','宋','宋诗','song-poetry','','[]','山間雖寂靜，未得事全無。',48,'全唐诗/poet.song.192000.json','["山間雖寂靜，未得事全無。", "鋤地留莎草，添泉養石蒲。", "庭除風自掃，身世月同孤。", "老去知禪味，松間試結趺。"]'),
('84274781-3dea-4949-9ba6-40c2f9498be9','寄湖上黄教','葉紹翁','宋','宋诗','song-poetry','','[]','門幽緣近寺，官冷未成家。',48,'全唐诗/poet.song.192000.json','["門幽緣近寺，官冷未成家。", "樓借山爲障，風吹水作花。", "詩方酬北磵，經又節南華。", "聞說新雛鳳，賓來解喚茶。"]'),
('9b96bb95-1b00-4082-b7f8-f8a988737786','表忠觀韓小官人','葉紹翁','宋','宋诗','song-poetry','','[]','觀裏韓風子，無心似有靈。',48,'全唐诗/poet.song.192000.json','["觀裏韓風子，無心似有靈。", "繞廊時自語，捫虱故忘形。", "午暴松簷暖，晨餐柏葉青。", "客來知有饋，迎笑立中庭。"]'),
('29b16430-826b-426c-af76-f983bf6a0498','夜書所見','葉紹翁','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u5c0f\u5b66\u53e4\u8bd7", "\u4e09\u5e74\u7ea7\u4e0a\u518c", "\u5199\u666f"]','蕭蕭梧葉送寒聲，江上秋風動客情。',32,'全唐诗/poet.song.192000.json','["蕭蕭梧葉送寒聲，江上秋風動客情。", "知有兒童挑促織，夜深籬落一燈明。"]'),
('24e85cdf-85b2-4f0c-83af-f6cbc8e0e99b','訪隠者','葉紹翁','宋','宋诗','song-poetry','','[]','開門迎客着山袍，井畔獼猴一樹桃。',64,'全唐诗/poet.song.192000.json','["開門迎客着山袍，井畔獼猴一樹桃。", "兒向草間尋落果，妻從牆角過香醪。", "舊栽松子今能大，新起茅堂不甚高。", "歷遍貴遊無此味，韭和春雨笋和糟。"]'),
('75e9e8ec-2b60-4a64-876c-c069f4defc7d','題孫端甫別墅','葉紹翁','宋','宋诗','song-poetry','','[]','幽居地僻少人知，野水春風枳樹籬。',64,'全唐诗/poet.song.192000.json','["幽居地僻少人知，野水春風枳樹籬。", "檢曆預尋移竹日，題牆閑記種花時。", "堪嗤狡兔須三窟，只學鷦鷯占一枝。", "凈掃綠苔斟濁酒，鄰家吹過野棠梨。"]'),
('9adb2dff-42d7-4bad-8ef6-f96e553c210f','寄趙眉翁二首  其一','葉紹翁','宋','宋诗','song-poetry','','[]','兩度馳書未報音，溫陵尺紙定千金。',32,'全唐诗/poet.song.192000.json','["兩度馳書未報音，溫陵尺紙定千金。", "多應驛使曾相訪，短艇煙波無處尋。"]'),
('252f9acb-2c02-4f85-8bbc-f3eb1733f610','寄趙眉翁二首  其二','葉紹翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君王未肯賜西湖，鷗鷺叢中借地居。',32,'全唐诗/poet.song.192000.json','["君王未肯賜西湖，鷗鷺叢中借地居。", "憔悴風姿今釣叟，癡心猶望故人書。"]'),
('cb8db778-3b0d-47e5-9e2f-004602b0bd3d','紙帳','葉紹翁','宋','宋诗','song-poetry','','[]','五色流蘇不用垂，楮衾木枕更相宜。',64,'全唐诗/poet.song.192000.json','["五色流蘇不用垂，楮衾木枕更相宜。", "高眠但許留禪客，低唱應難着侍兒。", "白似雪窗微霽後，暖於酒力半醺時。", "蒲團靜學觀身法，歲晚工夫要自知。"]'),
('ceebcd90-b568-43c5-bde1-62063cf34c9a','謁半山祠','葉紹翁','宋','宋诗','song-poetry','','[]','歸去田疇問老農，力行新法竟何功。',64,'全唐诗/poet.song.192000.json','["歸去田疇問老農，力行新法竟何功。", "已知供佛追前過，尚惜修書謝數公。", "塑像難陪夫子壁，古祠誰訪覺王宮。", "都來二百年間事，燕麥戎葵幾度風。"]'),
('68d78e9e-6842-4e0f-ae44-dc7a4270dd05','過崇德','葉紹翁','宋','宋诗','song-poetry','','[]','野塍泉自注，斷岸柳空存。',48,'全唐诗/poet.song.192000.json','["野塍泉自注，斷岸柳空存。", "雨霽雲開塔，船過犬吠門。", "柴扉斜着水，草逕別通村。", "翻羨田家樂，盈盈老瓦盆。"]'),
('ab4ed0ff-1825-4d76-b1e8-bd531ed44e15','鷺','葉紹翁','宋','宋诗','song-poetry','','[]','無事時來立葑田，幾回驚去爲歸船。',32,'全唐诗/poet.song.192000.json','["無事時來立葑田，幾回驚去爲歸船。", "霜姿不特他人愛，照影滄波亦自憐。"]'),
('3aeefa1a-2fd3-47a1-a903-864211b22045','詠先牌','葉紹翁','宋','宋诗','song-poetry','','[]','相隨萬里途，汝豈被名驅。',48,'全唐诗/poet.song.192000.json','["相隨萬里途，汝豈被名驅。", "掛壁疑何用，辭家不可無。", "店翁先洒掃，津吏認稱呼。", "舉子無錢刻，惟將□紙糊。"]'),
('c13a45b7-e5b2-4cb1-b97c-d417a0529edb','舟次崇德','葉紹翁','宋','宋诗','song-poetry','','[]','倦身只合卧家林，客裏消磨感慨心。',64,'全唐诗/poet.song.192000.json','["倦身只合卧家林，客裏消磨感慨心。", "水國逢春梅未見，山城到午霧猶深。", "地名不記維舟問，酒味曾諳入巷尋。", "泛宅浮家何日了，莊頭栽竹已成陰。"]'),
('44adc9ef-d8e1-4071-a85e-41e78e1cec34','發長安堰','葉紹翁','宋','宋诗','song-poetry','','[]','夏老蟲聲切，晨興草氣香。',48,'全唐诗/poet.song.192000.json','["夏老蟲聲切，晨興草氣香。", "買瓜依綠樹，出水𣵡青秧。", "船聚知村近，牛閑覺晝長。", "雙鳬蓮葉蕩，無雨故生涼。"]'),
('099faf88-4f1d-4d04-ad9b-860c6e52dd39','苔錢','葉紹翁','宋','宋诗','song-poetry','','[]','家貧地上却錢流，朽貫年深不可收。',32,'全唐诗/poet.song.192000.json','["家貧地上却錢流，朽貫年深不可收。", "若使用之堪買爵，等閑門巷亦封侯。"]'),
('44be9b24-ed39-45ba-93d8-41389abd3ef0','漢武帝','葉紹翁','宋','宋诗','song-poetry','','[]','殿號長秋花寂寂，臺名思子草茫茫。',32,'全唐诗/poet.song.192000.json','["殿號長秋花寂寂，臺名思子草茫茫。", "尚無人世團圞樂，枉認蓬萊作帝鄉。"]'),
('a3ba64ab-8d0d-4b44-acbd-b5f7e635e148','大滌山','葉紹翁','宋','宋诗','song-poetry','','[]','倦身祇欲卧林丘，羽客知心解款留。',64,'全唐诗/poet.song.192000.json','["倦身祇欲卧林丘，羽客知心解款留。", "泉溜涓涓中夜雨，天風凜凜四時秋。", "虎巖月澹迷仙路，龍洞雲深透別州。", "九鎖青山元不鎖，碧桃開後更來游。"]'),
('6f9540a8-63d8-4864-a1e1-6c1bba0fa0e1','宜對亭','葉紹翁','宋','宋诗','song-poetry','','[]','講罷閑來立矮闌，袈裟衣薄翠光寒。',32,'全唐诗/poet.song.192000.json','["講罷閑來立矮闌，袈裟衣薄翠光寒。", "請師莫起雲屏想，只作當年面壁看。"]'),
('9ea75e16-6cbf-4591-9c94-256292b4a3a3','貓圖','葉紹翁','宋','宋诗','song-poetry','','[]','醉薄荷，撲蟬蛾。',16,'全唐诗/poet.song.192000.json','["醉薄荷，撲蟬蛾。", "主人家，奈鼠何。"]'),
('ab9d5f98-1074-4a51-afc4-858d08eb5657','贊洞賓像','葉紹翁','宋','宋诗','song-poetry','','[]','撚吟髭，劍在前。',16,'全唐诗/poet.song.192000.json','["撚吟髭，劍在前。", "心中月，天上圓。"]'),
('0de0557c-ea9e-46b6-9974-48757ce061b1','賞梅','葉紹翁','宋','宋诗','song-poetry','','[]','梅花宜雪猶宜月，水畔山邊更自奇。',32,'全唐诗/poet.song.192000.json','["梅花宜雪猶宜月，水畔山邊更自奇。", "十四字傳和靖後，又傳君際五言詩。"]'),
('69f21c98-5605-4a81-826c-d3f1598f3782','次韻胡少瀹題梁王山蟠松詩','劉倓','宋','宋诗','song-poetry','','[]','長松上捎日月宮，昂霄聳壑材甚雄。',296,'全唐诗/poet.song.192000.json','["長松上捎日月宮，昂霄聳壑材甚雄。", "不肯甘心卧雲巘，有時見夢十八公。", "汗顔血指，那知大匠自有體。", "斬伐丁丁，朝夕聒人幽耳聾。", "豈如吾鄉華頂一峰八萬四千丈，下蟠夭夭矯矯奇奇怪怪之蒼松。", "樛枝半壓魯隠九年之大雪，雅韻曾和虞氏五絃之薰風。", "八千靈椿三千桃實幾番見，何況籬下黄菊江頭赤葉楓。", "蕭梁劫火燒不死，坐閲五季鹿走天下人亡弓。", "世人欲識吾家所擾真龍種，請看春雷發蟄霧滃霱雲從。", "礧砢蹙縮輪囷擁腫可挫不可辱，堅剛正獨盤薄偃蹇受命不受封。", "無用之用不器之器振古成自晚，天台道人何苦汲汲圖象寄涪翁。", "搜腸鏤腎狀出怪松贊，反言挺而茂者肥瘠貴得中。", "吁嗟九原相如不可作，飄飄詞賦誰摩穹。", "閬風逸民自愧才力薄，北斗以南惟有四朝之老農。"]'),
('beae4005-1554-46be-872f-71c71236f46f','蓬島山','劉倓','宋','宋诗','song-poetry','','[]','軋軋筍輿過翠微，路經蓬島鎖雲霏。',32,'全唐诗/poet.song.192000.json','["軋軋筍輿過翠微，路經蓬島鎖雲霏。", "雨從半嶺巖窩出，雲在行人脚下飛。"]'),
('2c227e37-59ba-4ccc-8555-06054e25fbc3','繭桼花','劉倓','宋','宋诗','song-poetry','','[]','清晨步上金雞嶺，極目漫山繭桼花。',32,'全唐诗/poet.song.192000.json','["清晨步上金雞嶺，極目漫山繭桼花。", "雪蕊瓊絲亦堪賞，樵童蠶婦伐歸家。"]'),
('a259c0e6-ce94-4979-96ff-592c09514b45','小玉蕊花  其一','劉倓','宋','宋诗','song-poetry','','[]','蔌蔌碎金英，絲絲鏤玉莖。',24,'全唐诗/poet.song.192000.json','["蔌蔌碎金英，絲絲鏤玉莖。", "步摇釵朵見，老眼爲增明。"]'),
('a1445b8f-9133-4d4a-8df9-2de9326f58f7','小玉蕊花  其二','劉倓','宋','宋诗','song-poetry','','[]','山礬紛似玉，黄蘗碎如金。',24,'全唐诗/poet.song.192000.json','["山礬紛似玉，黄蘗碎如金。", "二美傳春晚，同心契爾音。"]'),
('b651d7f9-429b-4a62-a376-d4fc134f6138','登石臺山與胡融李揆王度周仲卿聯句','劉倓','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.192000.json','["無正文。"]'),
('caa2cd3a-4683-4e90-a619-d084aecdfdf8','尊勝院','劉倓','宋','宋诗','song-poetry','','[]','海角尋春雪未消，馬蹄無處避瓊瑶。',32,'全唐诗/poet.song.192000.json','["海角尋春雪未消，馬蹄無處避瓊瑶。", "己公屋下論文酒，爐火篝燈伴寂寥。"]'),
('0aec7da0-9b82-4daf-8666-42bec40f38aa','隠秀亭','劉倓','宋','宋诗','song-poetry','','[]','一重一崦一岧嶢，隠秀寒光次第高。',32,'全唐诗/poet.song.192000.json','["一重一崦一岧嶢，隠秀寒光次第高。", "借得筍輿如小艇，晚風千里泛清濤。"]'),
('035b4cc4-2e8e-49b2-857b-c015c01f43ee','橫山  其一','劉倓','宋','宋诗','song-poetry','','[]','桐林老子俗情無，覽勝探奇不覺晡。',32,'全唐诗/poet.song.192000.json','["桐林老子俗情無，覽勝探奇不覺晡。", "幸爾清溪好明月，如行四十里冰壺。"]'),
('e80e03e3-2df9-4270-a7b2-a93f18e00dbb','橫山  其二','劉倓','宋','宋诗','song-poetry','','[]','一溪徑險僕夫劬，三酌油油醉筍輿。',32,'全唐诗/poet.song.192000.json','["一溪徑險僕夫劬，三酌油油醉筍輿。", "隔岸火焱三四點，不知誰照夜灘魚。"]'),
('acc3ae34-85df-4f67-802b-7c3222641294','橫山  其三','劉倓','宋','宋诗','song-poetry','','[]','五更一霎清明雨，曉霧梨花夢白雲。',32,'全唐诗/poet.song.192000.json','["五更一霎清明雨，曉霧梨花夢白雲。", "半嶺肩輿猶兀兀，一杯卯酒尚曛曛。"]'),
('a7ca4057-79f1-4bb8-abe1-f25b2dc87ac4','橫山  其四','劉倓','宋','宋诗','song-poetry','','[]','大小萬竹望不見，上下牢巖過若飛。',32,'全唐诗/poet.song.192000.json','["大小萬竹望不見，上下牢巖過若飛。", "紅綴舞衣山躑躅，白裁玉版野薔薇。"]'),
('1ce47748-9ac3-4cea-b300-affc39679d0e','橫山  其五','劉倓','宋','宋诗','song-poetry','','[]','石鏡當年始發祥，皎如秋月弄寒光。',32,'全唐诗/poet.song.192000.json','["石鏡當年始發祥，皎如秋月弄寒光。", "山川精彩無人識，付與樵夫敲斲傷。"]'),
('0a782773-952a-420f-8a6b-39ab19edc7dc','句  其一','劉倓','宋','宋诗','song-poetry','','[]','江南春晚經行地，賸有唐昌玉蘂花。',32,'全唐诗/poet.song.192000.json','["江南春晚經行地，賸有唐昌玉蘂花。", "露綺烟絺無限態，冰清玉潤自成葩。"]'),
('46c65e4c-46b1-4b1e-80b4-2d3df7367f71','句  其二','劉倓','宋','宋诗','song-poetry','','[]','粗官差入黨侯帳，精品平收陸羽經。',16,'全唐诗/poet.song.192000.json','["粗官差入黨侯帳，精品平收陸羽經。"]'),
('325f012c-de85-44b5-bb28-bbdda3d4b82f','嘉定元載浴佛日同胡彥德何經叔游玲瓏山次東坡先生韻','黎民瑞','宋','宋诗','song-poetry','','[]','倚巖松古勢如龍，峭拔層峯翠入空。',64,'全唐诗/poet.song.192000.json','["倚巖松古勢如龍，峭拔層峯翠入空。", "九折湍泉珠散漫，遶蹊斜石玉玲瓏。", "青環木杪山藏寺，碧擁亭高竹逗風。", "策杖共尋坡句讀，登臨清賞興無窮。"]'),
('09b76a8f-d917-4a0c-aa3a-885473a64664','楊柳','宋自適','宋','宋诗','song-poetry','','[]','絲絲煙雨弄輕柔，偏稱黄鸝與白鷗。',32,'全唐诗/poet.song.192000.json','["絲絲煙雨弄輕柔，偏稱黄鸝與白鷗。", "纔著一蟬嘶晚日，西風容易便成秋。"]'),
('27381c10-903d-4610-b7d0-d880cb2249a5','送謙父弟','宋自適','宋','宋诗','song-poetry','','[]','日用功夫在細微，行逢碍處便須疑。',32,'全唐诗/poet.song.192000.json','["日用功夫在細微，行逢碍處便須疑。", "高言怕被空虛笑，闊步先防墮落時。"]'),
('cd6d3a15-69ac-47f1-ad5c-4f151bc8898b','早行','宋自適','宋','宋诗','song-poetry','','[]','西郊雲起白漫漫，近樹遥峯欲辨難。',32,'全唐诗/poet.song.192000.json','["西郊雲起白漫漫，近樹遥峯欲辨難。", "山下幾多迷路者，人間方夢大槐安。"]'),
('4cb9f272-8074-4b07-9ca4-99d3a7e52a78','贈胡季昭','宋自適','宋','宋诗','song-poetry','','[]','凜凜廬陵一澹翁，飛揚復起振高風。',64,'全唐诗/poet.song.192000.json','["凜凜廬陵一澹翁，飛揚復起振高風。", "周無二叔聖何別，商有三仁道則同。", "孤跡本如雲出岫，清名應比日行空。", "翩翩雁影梅花外，雪片飛來酒對中。"]'),
('a739a53d-6714-4f3e-8ba8-b9f13ad7b145','贈畫士陳兄','宋自適','宋','宋诗','song-poetry','','[]','解衣盤礴任猜疑，神悟如狂又似癡。',32,'全唐诗/poet.song.192000.json','["解衣盤礴任猜疑，神悟如狂又似癡。", "學到却須堅自守，世間絕藝少人知。"]'),
('eaccc846-2c33-48d0-9266-ce7e82baffec','贈醫齒道人','宋自適','宋','宋诗','song-poetry','','[]','病欺年去故相加，要害先攻兩輔車。',32,'全唐诗/poet.song.192000.json','["病欺年去故相加，要害先攻兩輔車。", "解后神工如掇拾，愧無樽酒對榴花。"]'),
('fe4cd4fd-e347-4e68-9d62-e9e29e9875b0','謝饋藥','宋自適','宋','宋诗','song-poetry','','[]','投老如僧不出家，羸軀無奈病相加。',64,'全唐诗/poet.song.192000.json','["投老如僧不出家，羸軀無奈病相加。", "頭旋似倚當風柳，目眩如看隔霧花。", "高束詩書參素問，盡拋琴劍學丹砂。", "舊時載酒今懷藥，解識揚雄獨有巴。"]'),
('e3be034b-1886-4b5b-b7f0-485ed7291b4c','詠猿','宋自適','宋','宋诗','song-poetry','','[]','生長楩柟紫翠間，攀翻接手飲潺湲。',64,'全唐诗/poet.song.192000.json','["生長楩柟紫翠間，攀翻接手飲潺湲。", "卧驚落葉霜華重，叫徹山空月影閑。", "蹭蹬失身拘竹柵，飄蕭飛夢繞松關。", "平生捷巧何由逞，縮臂無言看遠山。"]'),
('3f784d36-eb50-4ac2-acb8-98bb534aaaf0','句  其一','宋自適','宋','宋诗','song-poetry','','[]','老去放令心膽健，後來留得姓名香。',16,'全唐诗/poet.song.192000.json','["老去放令心膽健，後來留得姓名香。"]'),
('cc8e3f7d-4666-42a9-9b2e-a6d689128c6b','句  其二','宋自適','宋','宋诗','song-poetry','','[]','陰陽消長風聞際，堂陛尊嚴山立時。',16,'全唐诗/poet.song.192000.json','["陰陽消長風聞際，堂陛尊嚴山立時。"]'),
('f3e4e2af-09f7-4d2a-88e0-a61deff5abb1','句  其三','宋自適','宋','宋诗','song-poetry','','[]','江湖多少盟鷗地，莫近平津閣畔行。',16,'全唐诗/poet.song.192000.json','["江湖多少盟鷗地，莫近平津閣畔行。"]'),
('eae3c695-e857-4480-8d2b-d470d2041f0a','句  其四','宋自適','宋','宋诗','song-poetry','','[]','三聖傳心惟主一，六經載道不言真。',16,'全唐诗/poet.song.192000.json','["三聖傳心惟主一，六經載道不言真。"]'),
('9d8c64e6-3bc1-484c-bfd5-8e96d3b13e98','贈畫山水陳兄','曾有光','宋','宋诗','song-poetry','','[]','眼前畫士蠶樣密，有如陳君萬纔一。',240,'全唐诗/poet.song.192000.json','["眼前畫士蠶樣密，有如陳君萬纔一。", "少年識高畫愈精，胸蟠物象妙通神。", "描盡江山歸指點，寒林古嶂煙雲歛。", "若懸瀑布飛潺湲，樵人向晚歸山巔。", "幻出樓臺景一簇，松釵墮落鴻金屋。", "苔封石徑綠茸茸，深藏古寺無聲鐘。", "花落啼鳥四時好，綠陽繫馬迷芳草。", "溪上桃花三月春，漁翁垂釣理絲綸。", "夏日池亭避炎暑，荷花落岸香風度。", "秋聲颯颯蘆葦寒，驚飛白鷺起前灘。", "野梅冬杪香飄路，忽驚四面仝雲布。", "展開一軸指顧間，始知妙畫歸毫端。", "誰云不復見摩詰，陳君自得如神筆。", "石臺一去不復來，陳君繼芳誠奇哉。", "形容聊述歌一首，行看聲亞諸人右。"]'),
('9d5c46f4-fec1-4d7f-8e59-1ed17d96ecf9','垂絲海棠','孫惟信','宋','宋诗','song-poetry','','[]','嫋嫋垂絲不自持，更禁日炙與風吹。',32,'全唐诗/poet.song.192000.json','["嫋嫋垂絲不自持，更禁日炙與風吹。", "仙家見慣渾閑事，乞與人間看一枝。"]'),
('9edf7a9d-ce51-4f06-bb75-d103faaf8476','賦女冠還俗','孫惟信','宋','宋诗','song-poetry','','[]','疊却霞綃上醮衣，女童髽髻綠楊垂。',64,'全唐诗/poet.song.192000.json','["疊却霞綃上醮衣，女童髽髻綠楊垂。", "重調蛾黛爲眉淺，再試弓鞋與步遲。", "紫府煙花鶑喚醒，僊房雲雨鶴通知。", "簾低紅杏春風暖，清夢應曾見舊師。"]'),
('1396bf2e-d6d5-4c06-ac1d-39123beec85c','禪寂之所有賣花聲出廊廡間清婉動耳','孫惟信','宋','宋诗','song-poetry','','[]','曲巷深房憶帝州，賣花庭宇最風流。',64,'全唐诗/poet.song.192000.json','["曲巷深房憶帝州，賣花庭宇最風流。", "窗紗破曉斜開扇，簾繡籠陰半上鈎。", "少日喜拈春在手，暮年羞戴雪盈頭。", "泉南寺裹瀟瀟雨，婉婉一聲無限愁。"]'),
('79086881-2d36-43c1-9deb-e1d478c09bf6','題載雪錄','孫惟信','宋','宋诗','song-poetry','','[]','詩字崢嶸照眼開，人隨塵劫挽難回。',32,'全唐诗/poet.song.192000.json','["詩字崢嶸照眼開，人隨塵劫挽難回。", "清苕載雪流寒碧，老我扁舟獨自來。"]'),
('bdc0cd25-0adc-473c-b93c-0f3b079fc6bd','題崇壽院','孫惟信','宋','宋诗','song-poetry','','[]','未欲鞭龍上玉京，赤城來鍊八霞精。',32,'全唐诗/poet.song.192000.json','["未欲鞭龍上玉京，赤城來鍊八霞精。", "松風浩蕩吹秋暑，偶到彌陀寺裏行。"]'),
('e96e628e-8847-40ab-9496-fc10021871e5','秦村午炊','孫惟信','宋','宋诗','song-poetry','','[]','飯熟羹香客寐殘，秦村山水樹陰寒。',32,'全唐诗/poet.song.192000.json','["飯熟羹香客寐殘，秦村山水樹陰寒。", "古今一樣邯鄲枕，覺後方纔做夢看。"]'),
('10cf03c2-2f39-4b6c-ba2f-0a69d4f6e809','深院','孫惟信','宋','宋诗','song-poetry','','[]','深院清明冷鳳簫，梨花寂寂雨瀟瀟。',32,'全唐诗/poet.song.192000.json','["深院清明冷鳳簫，梨花寂寂雨瀟瀟。", "秋千一架紅牆角，終日無人影自摇。"]'),
('5585cf2c-bbcf-4179-a1d5-ccda2473417d','小院','孫惟信','宋','宋诗','song-poetry','','[]','小院無人竹簟鋪，晝眠難穩客心孤。',32,'全唐诗/poet.song.192000.json','["小院無人竹簟鋪，晝眠難穩客心孤。", "窗前嫌怕驚殘夢，自擲青梅打鷓鴣。"]'),
('b46bb44b-b379-43b4-b4d1-8a13294c55a5','玲瓏山','孫惟信','宋','宋诗','song-poetry','','[]','晉漢高人跡已陳，同君仙屐叩山靈。',64,'全唐诗/poet.song.192000.json','["晉漢高人跡已陳，同君仙屐叩山靈。", "澗懸白練流雲液，路夾蒼虬聳石屏。", "鳥下老藤摇翠木，僧歸寒屋鑰秋扃。", "蕭蕭落日聞笙鶴，滿耳天風聒醉醒。"]'),
('33784f62-0efa-49fb-b268-319c140dc785','句','孫惟信','宋','宋诗','song-poetry','','[]','柳外細聽鶑燕語，聲聲似度鞠花新。',16,'全唐诗/poet.song.192000.json','["柳外細聽鶑燕語，聲聲似度鞠花新。"]'),
('0b50ab9b-9e91-43f6-888d-a57402198cf0','題載雪錄','蕭介父','宋','宋诗','song-poetry','','[]','亂雲連野水連空，祇有沙鷗共數公。',32,'全唐诗/poet.song.192000.json','["亂雲連野水連空，祇有沙鷗共數公。", "想得句成天亦喜，雪花迎櫂入吳中。"]'),
('9f634f22-a6fb-44ec-a141-e6c368329bc2','題釣臺三賢堂','謝采伯','宋','宋诗','song-poetry','','[]','輟帆謁肖像，衣冠非漢儔。',72,'全唐诗/poet.song.192000.json','["輟帆謁肖像，衣冠非漢儔。", "翩翩掛佛幡，小櫝求香油。", "庸衲資誑惑，良爲先生羞。", "後來躋兩賢，幾與逆祠侔。", "扁堂失本旨，貽誚何時休。", "盍歸白而長，是正茲謬悠。"]'),
('5da23606-7254-41ba-8d13-708d76320883','句','謝采伯','宋','宋诗','song-poetry','','[]','歸來鄰里悉不記，未免驚呼問桑竹。',16,'全唐诗/poet.song.192000.json','["歸來鄰里悉不記，未免驚呼問桑竹。"]'),
('77fb2872-b310-438b-85d5-85a6010e572d','馬城花窠','呂午','宋','宋诗','song-poetry','','[]','老子西城住，今踰十載期。',48,'全唐诗/poet.song.192000.json','["老子西城住，今踰十載期。", "栽花成茂樹，種柳長高枝。", "移接從渠巧，誇傳到處知。", "擔頭挑賣去，一一是趨時。"]'),
('ced9b150-e543-46eb-bd2b-12b2fb41201f','題仁義寺','呂午','宋','宋诗','song-poetry','','[]','寺以仁義名，當求仁義實。',48,'全唐诗/poet.song.192000.json','["寺以仁義名，當求仁義實。", "祇在毫釐間，遂分儒與釋。", "千載幾萬言，未能合爲一。", "大笑出門去，莫問成陳迹。"]'),
('f4ac704e-08ae-4a83-a917-673ef0d54278','開壽寺壁記','呂午','宋','宋诗','song-poetry','','[]','四顧雲山滿目前，却從此地得牛眠。',32,'全唐诗/poet.song.192000.json','["四顧雲山滿目前，却從此地得牛眠。", "問君此計何爲早，且住人間五百年。"]'),
('2e843091-74fd-406b-9e55-722e3e2b6900','鳳凰臺','呂午','宋','宋诗','song-poetry','','[]','古臺曾說少年遊，彈指驚嗟歲月流。',64,'全唐诗/poet.song.192000.json','["古臺曾說少年遊，彈指驚嗟歲月流。", "山似三神浮碧海，城如一虎卧崇丘。", "鳳凰去後遺陳迹，白鷺來時認舊洲。", "但得風寒無罅隙，江河舉目不須愁。"]'),
('6c2afda5-7def-4573-bd48-cb7ed80e15f6','大滌洞留題','呂午','宋','宋诗','song-poetry','','[]','武皇御宇好神仙，帝遣初開此洞天。',64,'全唐诗/poet.song.192000.json','["武皇御宇好神仙，帝遣初開此洞天。", "山轉九回藏紫府，澗縈百折走寒泉。", "棲真飛鼠□當日，大滌神龍似昔年。", "解與名山傳不朽，祇今惟有大蘇篇。"]'),
('190bd47d-4a04-48c8-a144-413444bb8d18','和岳王廟壁上韻','呂午','宋','宋诗','song-poetry','','[]','當年唯說岳家軍，紀律森嚴孰與鄰。',64,'全唐诗/poet.song.192000.json','["當年唯說岳家軍，紀律森嚴孰與鄰。", "師過村村皆按堵，功成處處可鎸珉。", "威名千古更無敵，詞翰數行俱絕塵。", "擬取中原報明主，亦勞餘刃到黄巾。"]'),
('d76b205b-82a1-48fe-a13e-2f449f483e62','句  其一','呂午','宋','宋诗','song-poetry','','[]','杏城西城翁幽居。',8,'全唐诗/poet.song.192000.json','["杏城西城翁幽居。"]'),
('e2275908-64e9-442a-90bc-ecc2e16dc563','句  其二','呂午','宋','宋诗','song-poetry','','[]','四時鷗鷺窺圖畫，千古魚龍聽管絃。',16,'全唐诗/poet.song.192000.json','["四時鷗鷺窺圖畫，千古魚龍聽管絃。"]'),
('1b6fbeba-bff9-44e7-bed1-24b95476320e','賦秋江圖','張端義','宋','宋诗','song-poetry','','[]','浪靜風平月正中，自摇柔艣駕孤篷。',32,'全唐诗/poet.song.192000.json','["浪靜風平月正中，自摇柔艣駕孤篷。", "若無三萬六千頃，把甚江湖著此翁。"]'),
('b3b7a82f-6873-4706-aedf-abb63dac88b2','挽周晉仙','張端義','宋','宋诗','song-poetry','','[]','策杖辭朋友，形骸已可憐。',48,'全唐诗/poet.song.192000.json','["策杖辭朋友，形骸已可憐。", "無錢親藥裹，冒雨上歸船。", "官竟生前棄，詩應死後傳。", "空餘京洛月，愁照月臺邊。"]'),
('8612ebd6-64d9-465d-9e33-90acfb381bc9','句  其一','張端義','宋','宋诗','song-poetry','','[]','碧雲千里暮，紅葉十分秋。',12,'全唐诗/poet.song.192000.json','["碧雲千里暮，紅葉十分秋。"]'),
('3c298741-de23-4c52-bc58-2abbeecbbbe5','句  其二','張端義','宋','宋诗','song-poetry','','[]','不因花退盡，必是夢殘時。',12,'全唐诗/poet.song.192000.json','["不因花退盡，必是夢殘時。"]'),
('aa8169c0-9c0f-4247-bfc7-307012c8d9e4','題僦樓壁','川官','宋','宋诗','song-poetry','','[]','朝看貝葉牢籠佛，夜禮星辰取奉天。',32,'全唐诗/poet.song.192000.json','["朝看貝葉牢籠佛，夜禮星辰取奉天。", "呼召歸來聞好語，初三初四亦欣然。"]'),
('32231f94-7c35-495e-a4ba-615a24f7bde4','呈安撫使趙端明','釋凈真','宋','宋诗','song-poetry','','[]','海沸江河水接連，居民衝蕩益憂煎。',32,'全唐诗/poet.song.192000.json','["海沸江河水接連，居民衝蕩益憂煎。", "投身直入龍宮去，要止驚濤浪拍天。"]'),
('9cad81e2-3a9f-4d5c-95da-3c0c35de9859','句','釋凈真','宋','宋诗','song-poetry','','[]','饑膚片玉明。',6,'全唐诗/poet.song.192000.json','["饑膚片玉明。"]'),
('f2b75b76-e87a-4192-b351-76b4853da45b','偈頌六十五首  其一','釋普濟','宋','宋诗','song-poetry','','[]','春山疊亂青，春水漾虛碧。',24,'全唐诗/poet.song.192000.json','["春山疊亂青，春水漾虛碧。", "大解脫門開，把手拽不入。"]'),
('68e40a49-04da-409b-a242-ce3bf7d4239c','偈頌六十五首  其二','釋普濟','宋','宋诗','song-poetry','','[]','大包虛空，細入無間。',20,'全唐诗/poet.song.192000.json','["大包虛空，細入無間。", "突出當陽，如何履踐。"]'),
('b66a1520-10c9-4782-942d-0b8b989bea39','偈頌六十五首  其三','釋普濟','宋','宋诗','song-poetry','','[]','十日雨，今日晴。',36,'全唐诗/poet.song.192000.json','["十日雨，今日晴。", "一則多年公案，明明舉似諸人。", "若是覆盆之下，又爭怪得老僧。"]'),
('bc51ac84-f0f2-45c0-8f58-6b8c7f72a5fd','偈頌六十五首  其四','釋普濟','宋','宋诗','song-poetry','','[]','翳盡還明極，家鄉萬八千。',24,'全唐诗/poet.song.192000.json','["翳盡還明極，家鄉萬八千。", "懸崖重撒手，古劍髑髏前。"]'),
('7025f509-34a0-491a-a564-b853546ed165','偈頌六十五首  其五','釋普濟','宋','宋诗','song-poetry','','[]','禾山打皷，雪峰輥毬，妙勝不打箇般車裏油。',32,'全唐诗/poet.song.192000.json','["禾山打皷，雪峰輥毬，妙勝不打箇般車裏油。", "一雙窮相手，兩箇死柴頭。"]'),
('f2ff6bdd-d8c6-4153-8f69-cc3b92f77fed','偈頌六十五首  其六','釋普濟','宋','宋诗','song-poetry','','[]','浄法界身，馿腮馬面。',20,'全唐诗/poet.song.192000.json','["浄法界身，馿腮馬面。", "本無出沒，萬化千變。"]'),
('1a5f4afa-6e02-4bc0-a60f-feb60f137257','偈頌六十五首  其七','釋普濟','宋','宋诗','song-poetry','','[]','眼耳鼻舌身意，八萬四千法門，晝夜放光動地。',31,'全唐诗/poet.song.192000.json','["眼耳鼻舌身意，八萬四千法門，晝夜放光動地。", "一翳在眼，空花亂墜。"]'),
('58ebec1c-efcb-4406-a778-6420fb1ec7b2','偈頌六十五首  其八','釋普濟','宋','宋诗','song-poetry','','[]','知之一字，衆禍之門。',48,'全唐诗/poet.song.192000.json','["知之一字，衆禍之門。", "殺人放火，活捉生擒。", "不是今日樞要，亦非上古典刑。", "與賊過梯了也，攻牆割壁何人。"]'),
('6745b559-ee70-4508-822a-7cbb6b01d1c1','偈頌六十五首  其九','釋普濟','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹，截鐵斬釘。',41,'全唐诗/poet.song.192000.json','["有句無句，如藤倚樹，截鐵斬釘。", "水不借路，樹倒藤枯。", "西天胡子沒髭鬚，蹋殺楊歧三脚馿。"]'),
('025188be-bb7c-4f61-92cd-fb5b2547022c','偈頌六十五首  其一○','釋普濟','宋','宋诗','song-poetry','','[]','趁晴蓋了屋，乘時刈了禾。',24,'全唐诗/poet.song.192000.json','["趁晴蓋了屋，乘時刈了禾。", "輸納王租了，鼓腹唱謳歌。"]'),
('b5ad827f-0da5-4a74-96bb-605258a90f0e','偈頌六十五首  其一一','釋普濟','宋','宋诗','song-poetry','','[]','天晴日頭出，雨落階頭濕。',24,'全唐诗/poet.song.192000.json','["天晴日頭出，雨落階頭濕。", "寶陀岩上人，猶自不條直。"]'),
('0f294f93-be4f-4efa-807f-30a04980dc3d','偈頌六十五首  其一二','釋普濟','宋','宋诗','song-poetry','','[]','大火已西流，千山爽氣浮。',24,'全唐诗/poet.song.192000.json','["大火已西流，千山爽氣浮。", "秋河鳴一鴈，砧杵擣離愁。"]'),
('bf505ffd-a41b-4b73-a16f-62f0d0347e69','偈頌六十五首  其一三','釋普濟','宋','宋诗','song-poetry','','[]','冬至前後，沙飛石走。',20,'全唐诗/poet.song.192000.json','["冬至前後，沙飛石走。", "佛祖潜蹤，寸鐵在手。"]'),
('79a25fbc-a94e-4011-9662-5ca9932d1c7d','偈頌六十五首  其一四','釋普濟','宋','宋诗','song-poetry','','[]','圓通門戶開，湛然應一切。',48,'全唐诗/poet.song.192000.json','["圓通門戶開，湛然應一切。", "星羅雲漢低，山嶽起空翠。", "風雨雪霜寒，人驚雞犬吠。", "正法明如來，依然在門外。"]'),
('40da795f-3ace-4ddd-bd8e-a4895b9a4fc0','偈頌六十五首  其一五','釋普濟','宋','宋诗','song-poetry','','[]','一隊衲僧來，一隊衲僧去。',24,'全唐诗/poet.song.192000.json','["一隊衲僧來，一隊衲僧去。", "打破睦州關，大地無寸土。"]'),
('6685d061-670c-4aea-a1d4-c24f79227dab','偈頌六十五首  其一六','釋普濟','宋','宋诗','song-poetry','','[]','去日炎威重，歸時秋半過。',58,'全唐诗/poet.song.192000.json','["去日炎威重，歸時秋半過。", "林間坐磐石，不覺笑呵呵。", "不笑仰山插鍬叉手，不笑地藏博飯栽田。", "二勝米料人人有，笑他餓死飯籮邊。"]'),
('79d7a6bb-b514-4812-a77d-842239f2ab32','偈頌六十五首  其一七','釋普濟','宋','宋诗','song-poetry','','[]','祖師不西來，少林有妙訣。',64,'全唐诗/poet.song.192000.json','["祖師不西來，少林有妙訣。", "江南兩浙，春寒秋熱。", "錯!佛法遍天下，談玄口不開。", "這個是露柱，那個是香臺。", "錯!直饒薦得分明，未免將錯就錯。"]'),
('444b59d1-52df-48ec-953b-1faca893294f','偈頌六十五首  其一八','釋普濟','宋','宋诗','song-poetry','','[]','禁足護生脚跟下，乞命底紛紛紜紜。',32,'全唐诗/poet.song.192000.json','["禁足護生脚跟下，乞命底紛紛紜紜。", "克期取證平地上，埋沒人千千萬萬。"]'),
('8a524a24-60b7-46d0-ba64-fb4e8a010835','偈頌六十五首  其一九','釋普濟','宋','宋诗','song-poetry','','[]','臘極嚴寒，凍破泥團。',36,'全唐诗/poet.song.192000.json','["臘極嚴寒，凍破泥團。", "不可默會，不可形言。", "雞上樹，鴨下水，明朝更獻楚王看。"]'),
('f3793f18-b03d-4915-bfb9-16af608153ba','偈頌六十五首  其二○','釋普濟','宋','宋诗','song-poetry','','[]','鷲嶺拈花，少林得髓。',36,'全唐诗/poet.song.192000.json','["鷲嶺拈花，少林得髓。", "病痛一般，脈息有異。", "脈得著目前見鬼，脈不著死而不吊。"]'),
('e6e2cf1e-1dad-4bd2-9d61-237c5eed2368','偈頌六十五首  其二一','釋普濟','宋','宋诗','song-poetry','','[]','栽田博飯，詭計百出。',46,'全唐诗/poet.song.192000.json','["栽田博飯，詭計百出。", "插鍬叉手，通身荆棘。", "枷棒場中親不親，草窠交輥見當人。", "誰是當人，放筯忘恩。"]'),
('8b7a7ade-326c-4e91-9082-bc62660e6d24','偈頌六十五首  其二二','釋普濟','宋','宋诗','song-poetry','','[]','擊鼓陞堂，不談世法。',30,'全唐诗/poet.song.192000.json','["擊鼓陞堂，不談世法。", "冬至月頭，賣被買牛。", "冬至月尾，賣牛買被。"]'),
('f3005aa1-99d3-4692-b03e-ba2cdb39b0ac','偈頌六十五首  其二三','釋普濟','宋','宋诗','song-poetry','','[]','經行及坐卧，常在於其中。',24,'全唐诗/poet.song.192000.json','["經行及坐卧，常在於其中。", "要識其中事，長汀江水東。"]'),
('f638f69b-3169-428a-95ae-707f124ea83f','偈頌六十五首  其二四','釋普濟','宋','宋诗','song-poetry','','[]','同條不同條，心眼自相照。',24,'全唐诗/poet.song.192000.json','["同條不同條，心眼自相照。", "翻覆論歲寒，不覺拍手笑。"]'),
('410cb142-4f82-484c-9065-0c56c7d97676','偈頌六十五首  其二五','釋普濟','宋','宋诗','song-poetry','','["\u590f\u5929", "\u5199\u666f"]','綠樹陰濃夏日長，樓臺倒影入池塘。',32,'全唐诗/poet.song.192000.json','["綠樹陰濃夏日長，樓臺倒影入池塘。", "水晶簾動微風起，滿架薔薇一院香。"]'),
('da195d9d-d9ae-45e2-8eba-92b50deda1d7','偈頌六十五首  其二六','釋普濟','宋','宋诗','song-poetry','','[]','砉碎明月珠，始爲家寶。',43,'全唐诗/poet.song.192000.json','["砉碎明月珠，始爲家寶。", "颺下鈯斧子，方是住山。", "古策風高，天寬地闊。", "別別，別峰妙轉風雷舌。"]'),
('8285b1ad-3408-445a-bdcc-b90e6b1a4eb2','偈頌六十五首  其二七','釋普濟','宋','宋诗','song-poetry','','[]','白鶴五通賢聖，瞥喜瞥嗔無定。',62,'全唐诗/poet.song.192000.json','["白鶴五通賢聖，瞥喜瞥嗔無定。", "聞名不如見面，見面依然錯認。", "從來與渠水米無交，年年今日，鉢盂安柄。", "因甚如此，雞不喫穀，肫裏有病。"]'),
('6ec0b366-0257-497c-a7bf-7507f36a9911','偈頌六十五首  其二八','釋普濟','宋','宋诗','song-poetry','','[]','西來無意，遍天遍地。',62,'全唐诗/poet.song.192000.json','["西來無意，遍天遍地。", "玉兔東昇，金烏西墜。", "老鼠齩牀頭，貓兒正憨睡。", "莫教動著渠，動著便禍事。", "二祖動著招禍上身，天寧今日開眼失利。"]'),
('85acffa3-c48e-48d4-8037-d5abb17e5486','偈頌六十五首  其二九','釋普濟','宋','宋诗','song-poetry','','[]','風不鳴條，雨不破塊。',22,'全唐诗/poet.song.192000.json','["風不鳴條，雨不破塊。", "老胡忽西來，撥亂清平世。"]'),
('575a1079-9841-4ec0-8382-51f0748a3810','偈頌六十五首  其三○','釋普濟','宋','宋诗','song-poetry','','[]','一天星斗大家看，獨有渠儂見處偏。',32,'全唐诗/poet.song.192000.json','["一天星斗大家看，獨有渠儂見處偏。", "打失眼睛拈得口，至今脚下黑漫漫。"]'),
('16a966c9-f760-4b81-822a-fb9dd9493504','偈頌六十五首  其三一','釋普濟','宋','宋诗','song-poetry','','[]','錦城歌管日紛紛，半入江風半入雲。',32,'全唐诗/poet.song.192000.json','["錦城歌管日紛紛，半入江風半入雲。", "此曲只應天上有，人間能是幾回聞。"]'),
('21a9f92a-1a26-4b8d-86ee-217401a19863','偈頌六十五首  其三二','釋普濟','宋','宋诗','song-poetry','','[]','煆玉已經三日火，探珠曾下九重淵。',32,'全唐诗/poet.song.192000.json','["煆玉已經三日火，探珠曾下九重淵。", "毀珠擿玉無人識，十字街頭颺碌磚。"]'),
('6f227dd7-5c3e-426e-8969-ec49f0e37bda','偈頌六十五首  其三三','釋普濟','宋','宋诗','song-poetry','','[]','山家冬境致，何處不光輝。',24,'全唐诗/poet.song.192000.json','["山家冬境致，何處不光輝。", "大地冰稜合，漫天雨雪飛。"]'),
('f9ed6b01-3329-43ba-a947-bdb76030338a','偈頌六十五首  其三四','釋普濟','宋','宋诗','song-poetry','','[]','霏霏梅雨灑危層，五月山房冷似冰。',32,'全唐诗/poet.song.192000.json','["霏霏梅雨灑危層，五月山房冷似冰。", "莫謂乾坤乖大信，未明心地是炎蒸。"]'),
('d616d2a0-912f-40d7-9fd4-eb62c9c18781','偈頌六十五首  其三五','釋普濟','宋','宋诗','song-poetry','','[]','一新一舊，嘉熙淳祐。',20,'全唐诗/poet.song.192000.json','["一新一舊，嘉熙淳祐。", "皇天大曆，歲在辛丑。"]'),
('e2ca1245-ddad-402c-949c-1ded2fdc33a9','偈頌六十五首  其三六','釋普濟','宋','宋诗','song-poetry','','[]','南北山朝對，東西有路分。',24,'全唐诗/poet.song.192000.json','["南北山朝對，東西有路分。", "一步不相到，大地入無門。"]'),
('8accf595-7efc-41d9-9703-f810a5ad10eb','偈頌六十五首  其三七','釋普濟','宋','宋诗','song-poetry','','[]','崇山峻嶺，茂林脩竹。',20,'全唐诗/poet.song.192000.json','["崇山峻嶺，茂林脩竹。", "終日提綱，神號鬼哭。"]'),
('d3c624fd-0b0a-4891-90b9-c77711df5a23','偈頌六十五首  其三八','釋普濟','宋','宋诗','song-poetry','','[]','老黄龍頷下明珠，勝首座懸空撲碎。',32,'全唐诗/poet.song.192000.json','["老黄龍頷下明珠，勝首座懸空撲碎。", "黄檗山吐霧興雲，遍地走南山鼈鼻。"]'),
('3258043b-dccd-44f1-a3b0-d78c7dc620ee','偈頌六十五首  其三九','釋普濟','宋','宋诗','song-poetry','','[]','爲衆持鉢去，七佛舊儀式。',24,'全唐诗/poet.song.192000.json','["爲衆持鉢去，七佛舊儀式。", "菴園塔廟間，處處遍敲擊。"]'),
('6fbde6fd-58bf-4fab-9804-448f3977ce00','偈頌六十五首  其四○','釋普濟','宋','宋诗','song-poetry','','[]','旱地一聲雷，青天撒白雨。',52,'全唐诗/poet.song.192000.json','["旱地一聲雷，青天撒白雨。", "不是諾佛說底法，不是祖師傳底心，不是衲僧參底句。", "日月輪邊氣象高，魚龍穴下蟠根固。"]'),
('818503b5-ab85-4ad6-ba11-e690cf07eee9','偈頌六十五首  其四一','釋普濟','宋','宋诗','song-poetry','','[]','起滅不停，如珠走盤。',20,'全唐诗/poet.song.192000.json','["起滅不停，如珠走盤。", "收視返聽，墮在黑山。"]'),
('52b30336-21ea-4f1d-997b-cef03ac095c2','偈頌六十五首  其四二','釋普濟','宋','宋诗','song-poetry','','[]','不參禪，不問道。',40,'全唐诗/poet.song.192000.json','["不參禪，不問道。", "豎起鐵脊梁，死蛇鑽出草。", "不是禪，不是道。", "雲門千歲僧，越山鼐長老。"]'),
('44fe911e-c568-432e-8df7-0242bf3ac058','偈頌六十五首  其四三','釋普濟','宋','宋诗','song-poetry','','[]','悉達脚下，七花八裂。',20,'全唐诗/poet.song.192000.json','["悉達脚下，七花八裂。", "韶陽棒頭，有禮有樂。"]'),
('6c5f321a-ff43-4796-82d2-ec3a78cd70e6','偈頌六十五首  其四四','釋普濟','宋','宋诗','song-poetry','','[]','迦葉首傳，龍潭吹滅。',20,'全唐诗/poet.song.192000.json','["迦葉首傳，龍潭吹滅。", "一燈一燈，燈燈不絕。"]'),
('e987d9c2-0f89-4a30-b91f-070a90dd0395','偈頌六十五首  其四五','釋普濟','宋','宋诗','song-poetry','','[]','南山虎齩大蟲，鼈鼻蛇頭生角。',28,'全唐诗/poet.song.192000.json','["南山虎齩大蟲，鼈鼻蛇頭生角。", "大地六反震動，文殊普賢驚愕。"]'),
('63b841e8-b076-4848-8eeb-b4342f637aa3','偈頌六十五首  其四六','釋普濟','宋','宋诗','song-poetry','','[]','雪壓雙林樹，風號萬籟寒。',24,'全唐诗/poet.song.192000.json','["雪壓雙林樹，風號萬籟寒。", "瞿曇曾入滅，衲子眼難瞞。"]'),
('7cd1e2a2-d7dc-418f-91ad-050e5d9925b2','偈頌六十五首  其四七','釋普濟','宋','宋诗','song-poetry','','[]','鐵蒺藜椎，轉弄轉危。',36,'全唐诗/poet.song.192000.json','["鐵蒺藜椎，轉弄轉危。", "丹霞燒木佛，院主落鬚眉。", "南山爐添今日火，作者不同歸。"]'),
('3f1cd140-250a-4f7e-870c-b2baefa961e8','偈頌六十五首  其四八','釋普濟','宋','宋诗','song-poetry','','[]','南山雲，北山雨。',68,'全唐诗/poet.song.192000.json','["南山雲，北山雨。", "毗盧樓閣，豁開門戶。", "花簇簇，錦簇簇。", "彌勒大士，傾腸倒腹。", "百城風月，目前領話，人畜草芥。", "一時知有不知有，毗目仙人執善財手。"]'),
('02849ee8-b816-4fb7-a338-a871dbfa43a4','偈頌六十五首  其四九','釋普濟','宋','宋诗','song-poetry','','[]','鐘鼓聲喧暄，鳥雀閙中庭。',24,'全唐诗/poet.song.192000.json','["鐘鼓聲喧暄，鳥雀閙中庭。", "圓通門不鑰，眉毛落又生。"]'),
('ba6d8582-e31a-45ad-af19-b2ee947deade','偈頌六十五首  其五○','釋普濟','宋','宋诗','song-poetry','','[]','冬不寒，臘後看。',20,'全唐诗/poet.song.192000.json','["冬不寒，臘後看。", "無人知此意，令我憶南泉。"]'),
('eea769ce-d040-4042-9536-9919292d8888','偈頌六十五首  其五一','釋普濟','宋','宋诗','song-poetry','','[]','明星一見悟無生，攧落阿鼻業火坑。',32,'全唐诗/poet.song.192000.json','["明星一見悟無生，攧落阿鼻業火坑。", "三百餘番說不出，爲他閑事長無明。"]'),
('aff76d8a-87eb-4e23-bb6a-6c5693d59c5d','偈頌六十五首  其五二','釋普濟','宋','宋诗','song-poetry','','[]','壁觀婆羅門，家業大天下。',36,'全唐诗/poet.song.192000.json','["壁觀婆羅門，家業大天下。", "傳遠枝派分，寸土不存也。", "焚香作忌齋，普請禮三拜。"]'),
('9f4571e3-ed0e-40c9-b10f-ce1fcaac8f59','偈頌六十五首  其五三','釋普濟','宋','宋诗','song-poetry','','[]','古佛堂前，三頭六臂。',40,'全唐诗/poet.song.192000.json','["古佛堂前，三頭六臂。", "祖師門下，道絕人荒。", "衲僧者裏，銀山鐵壁。", "慧日峰頂，春風和氣。"]'),
('e8de248e-f46b-48e1-811a-e370886d49e3','偈頌六十五首  其五四','釋普濟','宋','宋诗','song-poetry','','[]','驗人眼，截流機。',18,'全唐诗/poet.song.192000.json','["驗人眼，截流機。", "德山臨際，伏惟伏惟。"]'),
('6fb9c1d0-819e-41c8-bdc6-bb1d7408348c','偈頌六十五首  其五五','釋普濟','宋','宋诗','song-poetry','','[]','前佛後佛，無生不滅。',22,'全唐诗/poet.song.192000.json','["前佛後佛，無生不滅。", "紫磨金色身，衲僧眼中屑。"]'),
('cb77d79f-743d-4600-9edc-afd8d9326c75','偈頌六十五首  其五六','釋普濟','宋','宋诗','song-poetry','','[]','堂中首座人天眼，漢語胡言大藏經。',32,'全唐诗/poet.song.192000.json','["堂中首座人天眼，漢語胡言大藏經。", "七百衲僧吞佛祖，靈山樂得做閑人。"]'),
('dc7ca4dd-e4fc-45be-8454-fe9fda6dfeb7','偈頌六十五首  其五七','釋普濟','宋','宋诗','song-poetry','','[]','覺皇垂迹左金輪，寶殿巍巍表至尊。',32,'全唐诗/poet.song.192000.json','["覺皇垂迹左金輪，寶殿巍巍表至尊。", "宸翰親從天上降，爛然金碧耀乾坤。"]'),
('8d759918-3734-45ba-82d4-43bdbbee1a3f','偈頌六十五首  其五八','釋普濟','宋','宋诗','song-poetry','','[]','大道無門，十方有路。',50,'全唐诗/poet.song.192000.json','["大道無門，十方有路。", "無門不可不入，有路不可不到。", "阿呵呵，不參禪，不說教。", "飽飯熟睡游談，三毒無明浩浩。"]'),
('c512adb0-4657-46a6-9000-b7e4579a91e0','偈頌六十五首  其五九','釋普濟','宋','宋诗','song-poetry','','[]','三八念誦，勞動大衆。',30,'全唐诗/poet.song.192000.json','["三八念誦，勞動大衆。", "五月陞堂，說短論長。", "打鼓入室，逼狗透牆。"]'),
('106f8542-baf4-4e23-87a4-6e5706e0bb38','偈頌六十五首  其六○','釋普濟','宋','宋诗','song-poetry','','[]','東去西去，南來北來。',20,'全唐诗/poet.song.192000.json','["東去西去，南來北來。", "殘羹餿飯，門外安排。"]'),
('ac2abc57-fa71-4255-9d75-6227023f7ad9','偈頌六十五首  其六一','釋普濟','宋','宋诗','song-poetry','','[]','深山窮谷，蛇虎縱橫。',20,'全唐诗/poet.song.192000.json','["深山窮谷，蛇虎縱橫。", "平田淺草，鴉鳴鵲噪。"]'),
('6baeaed2-b687-4a1f-9245-cbd13b1b401b','偈頌六十五首  其六二','釋普濟','宋','宋诗','song-poetry','','[]','九十日春，多雨少晴。',22,'全唐诗/poet.song.192000.json','["九十日春，多雨少晴。", "苔痕上階綠，草色入簾青。"]'),
('1463dc89-25e4-499f-84b3-af25e25454b7','偈頌六十五首  其六三','釋普濟','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','地水火風先佛記，冷灰堆裏無舍利。',32,'全唐诗/poet.song.192000.json','["地水火風先佛記，冷灰堆裏無舍利。", "掃向長江白浪中，千古萬古第一義。"]'),
('a8de6b82-ab9b-4517-9b8d-b11870f334c4','偈頌六十五首  其六四','釋普濟','宋','宋诗','song-poetry','','[]','百尺竿頭坐底人，雖然得入未爲真。',32,'全唐诗/poet.song.192000.json','["百尺竿頭坐底人，雖然得入未爲真。", "百尺竿頭進一步，十方剎土現全身。"]'),
('ca098b52-0b3c-475b-9667-d1306cbf2065','偈頌六十五首  其六五','釋普濟','宋','宋诗','song-poetry','','[]','鳴爆竹，送殘年，東村王老夜燒錢。',32,'全唐诗/poet.song.192000.json','["鳴爆竹，送殘年，東村王老夜燒錢。", "南山短拙無施設，借婆裙子拜婆年。"]'),
('3859e53a-a1ef-4751-8d91-466472dcd3d7','頌古十一首  其一','釋普濟','宋','宋诗','song-poetry','','[]','一片爺爺古化基，又逢寒食拜標時。',32,'全唐诗/poet.song.192000.json','["一片爺爺古化基，又逢寒食拜標時。", "滿前骨肉俱承蔭，一個無聊乞養兒。"]'),
('6d4f0af6-4bef-4cf9-af35-90df1c9e2187','頌古十一首  其二','釋普濟','宋','宋诗','song-poetry','','[]','肩擔口叫，曉夜撐船。',20,'全唐诗/poet.song.192000.json','["肩擔口叫，曉夜撐船。", "道路各別，養家一般。"]'),
('63729df9-e985-4fba-90a0-3fcc68327c4f','頌古十一首  其三','釋普濟','宋','宋诗','song-poetry','','[]','青氈本是家中物，時復拈來抖擻看。',32,'全唐诗/poet.song.192000.json','["青氈本是家中物，時復拈來抖擻看。", "貴要傍人知下落，不知下落被人謾。"]'),
('ad686a62-8015-4cf0-a282-0f2dcbb1453f','頌古十一首  其四','釋普濟','宋','宋诗','song-poetry','','[]','風頭策起羅生網，更向無風煖處張。',32,'全唐诗/poet.song.192000.json','["風頭策起羅生網，更向無風煖處張。", "兩度勞心又勞力，更無鸞鳳敢呈祥。"]'),
('80daa1d5-332e-4dbf-941d-ae363206bed9','頌古十一首  其五','釋普濟','宋','宋诗','song-poetry','','[]','睡濃天曉弗梳頭，洗面無湯也即休。',32,'全唐诗/poet.song.192000.json','["睡濃天曉弗梳頭，洗面無湯也即休。", "大底還他肌骨好，不搽紅粉也風流。"]'),
('153e5d3a-29ab-4767-9ff0-377555e161db','頌古十一首  其六','釋普濟','宋','宋诗','song-poetry','','[]','示疾毗耶問訊疏，知音惟有老文殊。',32,'全唐诗/poet.song.192000.json','["示疾毗耶問訊疏，知音惟有老文殊。", "問來答去膠投漆，一病翻成兩病夫。"]'),
('de368fbf-0cd8-428d-959d-b7e96471bb8c','頌古十一首  其七','釋普濟','宋','宋诗','song-poetry','','[]','臘月火燒山，胡僧入漢關。',24,'全唐诗/poet.song.192000.json','["臘月火燒山，胡僧入漢關。", "一頭卷螺髮，兩耳带金環。"]'),
('33c92a9b-141f-4190-9527-bba5d95a87ce','頌古十一首  其八','釋普濟','宋','宋诗','song-poetry','','[]','奴見婢慇懃，瞥喜瞥然嗔。',24,'全唐诗/poet.song.192000.json','["奴見婢慇懃，瞥喜瞥然嗔。", "瀟湘圖上看，分外好精神。"]'),
('e21a7577-cddf-4e26-97da-c30451bdf06e','頌古十一首  其九','釋普濟','宋','宋诗','song-poetry','','[]','金鴨香消更漏長，沉沉玉殿紫苔生。',32,'全唐诗/poet.song.192000.json','["金鴨香消更漏長，沉沉玉殿紫苔生。", "高空有月千門照，大道無人獨自行。"]'),
('5e1b2f18-3658-45d0-8d06-9b5677da4cd8','頌古十一首  其一○','釋普濟','宋','宋诗','song-poetry','','[]','光境俱忘與未忘，殺人利劍活人鎗。',32,'全唐诗/poet.song.192000.json','["光境俱忘與未忘，殺人利劍活人鎗。", "太平時節渾無用，夜夜神光射斗旁。"]'),
('b6e47b1a-1b61-464d-8620-f673f54ebbb7','頌古十一首  其一一','釋普濟','宋','宋诗','song-poetry','','[]','電電喧轟海岱昏，怒濤翻覆拍天門。',32,'全唐诗/poet.song.192000.json','["電電喧轟海岱昏，怒濤翻覆拍天門。", "錦鱗不會乘流去，空向桃花浪裏奔。"]'),
('5952cf2d-7999-42be-a4e4-0f31ecfefc4a','出山相贊','釋普濟','宋','宋诗','song-poetry','','[]','龍章鳳質出王宮，肘露衣穿下雪峰。',32,'全唐诗/poet.song.192000.json','["龍章鳳質出王宮，肘露衣穿下雪峰。", "智願必空諸有界，不知諸有幾時空。"]'),
('cd8f3b2e-d559-4bf4-aff3-4c4abb77d307','觀音大士贊','釋普濟','宋','宋诗','song-poetry','','[]','空如來藏，立大圓鏡。',30,'全唐诗/poet.song.192000.json','["空如來藏，立大圓鏡。", "水落石出，月明雲浄。", "瞻之仰之，群機普應。"]'),
('df0ae3fc-7f78-440d-92c6-f38917786fd2','金剛經書大士像贊','釋普濟','宋','宋诗','song-poetry','','[]','大士應身三十二，一身三十二重非。',32,'全唐诗/poet.song.192000.json','["大士應身三十二，一身三十二重非。", "金剛正體是非外，鵲噪鴉鳴無了時。"]'),
('6b7091e9-c1cd-4f9d-9c4d-42e86e1cae5c','馬郎婦贊','釋普濟','宋','宋诗','song-poetry','','[]','有願必從，無剎不現。',30,'全唐诗/poet.song.192000.json','["有願必從，無剎不現。", "鬢亂釵橫，金沙灘畔。", "稽首皈依，漏巵難滿。"]'),
('7e375038-808a-4934-9b6e-7a0181c234bb','善財贊','釋普濟','宋','宋诗','song-poetry','','[]','福城東際錯商量，誤入烟蘿白鳥鄉。',32,'全唐诗/poet.song.192000.json','["福城東際錯商量，誤入烟蘿白鳥鄉。", "水遠山長無限意，到頭難寫此愁腸。"]'),
('9fc73d06-a5e7-4582-9a44-004ffd4d79c6','維摩贊','釋普濟','宋','宋诗','song-poetry','','[]','指桃駡李，敗種發機。',36,'全唐诗/poet.song.192000.json','["指桃駡李，敗種發機。", "詞窮理盡，一嘿橫施。", "大地山河背震吼，七佛之師懡㦬歸。"]'),
('8076bbb3-4a4e-4847-8527-a3252f3da0aa','布袋贊  其一','釋普濟','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','南無阿逸多，忙忙走寰宇。',36,'全唐诗/poet.song.192000.json','["南無阿逸多，忙忙走寰宇。", "等个人未至，放下寬腸肚。", "來也來也，泰嶽何曾乏土。"]'),
('c2d03c5e-2892-469d-a239-9c3fd426c246','布袋贊  其二','釋普濟','宋','宋诗','song-poetry','','[]','九十七大人之相，百千億微塵數身。',32,'全唐诗/poet.song.192000.json','["九十七大人之相，百千億微塵數身。", "兜率長汀人不識，抖擻精神一欠伸。"]'),
('d15e763b-c9cf-4acc-801f-01163853580b','達磨大師贊  其一','釋普濟','宋','宋诗','song-poetry','','[]','的的西天末法僧，來分此土最初燈。',32,'全唐诗/poet.song.192000.json','["的的西天末法僧，來分此土最初燈。", "神光冷地一吹滅，葱嶺忙忙只暗登。"]'),
('0406d022-4c98-47eb-b346-8c313ee18044','達磨大師贊  其二','釋普濟','宋','宋诗','song-poetry','','[]','五天竺國，東震旦土。',34,'全唐诗/poet.song.192000.json','["五天竺國，東震旦土。", "傳佛心宗，無本可據。", "無本據，一葦橫趨，大江東去。"]'),
('520b19cd-ec2e-4644-a825-01dd79f778ad','五祖贊','釋普濟','宋','宋诗','song-poetry','','[]','萬本松杉，山山栽遍。',36,'全唐诗/poet.song.192000.json','["萬本松杉，山山栽遍。", "颺下钁頭，再呈舊面。", "雙峰峨峨翠插天，天下人見渠不見。"]'),
('8fae4767-361c-49eb-bbae-070fc27cc2bb','六祖贊','釋普濟','宋','宋诗','song-poetry','','[]','應無所住，白日迷路。',36,'全唐诗/poet.song.192000.json','["應無所住，白日迷路。", "失脚黄梅，道傳千古。", "不是風動非幡動，會也蚍蜉撼鐵柱。"]'),
('a1bca356-73af-4113-a2ab-cae3abc06cf3','五祖送六祖渡江圖贊','釋普濟','宋','宋诗','song-poetry','','[]','有傳有受恩成怨，無受無傳怨似恩。',32,'全唐诗/poet.song.192000.json','["有傳有受恩成怨，無受無傳怨似恩。", "船到岸頭恩怨絕，遍天遍地一兒孫。"]'),
('a48cf40e-d834-4a21-9fbd-081920abfa90','懶瓚贊','釋普濟','宋','宋诗','song-poetry','','[]','垂頤寒涕滿頭霜，黄獨煨來別有香。',32,'全唐诗/poet.song.192000.json','["垂頤寒涕滿頭霜，黄獨煨來別有香。", "三詔入雲三不起，兒孫各自立封疆。"]'),
('4b82aec2-9aa1-45ca-a6c8-f79f79316404','楊歧祖師贊','釋普濟','宋','宋诗','song-poetry','','[]','三脚馿子弄蹄行，金毛師子大哮吼。',32,'全唐诗/poet.song.192000.json','["三脚馿子弄蹄行，金毛師子大哮吼。", "五峰峭峻摩蒼穹，千古萬古揚家醜。"]'),
('32f71c8a-9248-40cb-91f8-c58af6a5b703','夾山見船子贊','釋普濟','宋','宋诗','song-poetry','','[]','毒手一橈難躲避，點頭不見問津人。',32,'全唐诗/poet.song.192000.json','["毒手一橈難躲避，點頭不見問津人。", "烟波浩渺無窮恨，父子雖親未是親。"]'),
('f6dc2f53-31d6-4c28-a239-3b975b77a5a5','馬祖接石鞏贊','釋普濟','宋','宋诗','song-poetry','','[]','三十年不少鹽醤，一鏃群狐中的時。',32,'全唐诗/poet.song.192000.json','["三十年不少鹽醤，一鏃群狐中的時。", "大地山河諸草木，至今盡發箭鋒機。"]'),
('04fd7f51-4061-4c1a-bf83-0f789d40e5c1','鳥窠贊','釋普濟','宋','宋诗','song-poetry','','[]','道高德高名愈高，問佛法而吹布毛。',32,'全唐诗/poet.song.192000.json','["道高德高名愈高，問佛法而吹布毛。", "不是尋常閑啐啄，飛出鳳兒空鵲巢。"]'),
('be018c15-d4b5-41a0-8030-ca13eee6f940','諾詎羅尊者贊','釋普濟','宋','宋诗','song-poetry','','[]','石壁攙空起，銀河一派懸。',24,'全唐诗/poet.song.192000.json','["石壁攙空起，銀河一派懸。", "貪觀無斷續，來去不知原。"]'),
('c4006270-3f3b-4b7d-a61f-265dbb7c9197','四睡贊','釋普濟','宋','宋诗','song-poetry','','[]','離了峨嵋別五臺，倒騎白額下天台。',32,'全唐诗/poet.song.192000.json','["離了峨嵋別五臺，倒騎白額下天台。", "松間石上夢中夢，喚得閭丘太守回。"]'),
('4222fa16-74ac-4472-b162-b854c57b0d72','寒山贊','釋普濟','宋','宋诗','song-poetry','','[]','採樵沿嶺去，提水傍谿歸。',24,'全唐诗/poet.song.192000.json','["採樵沿嶺去，提水傍谿歸。", "个般無出豁，七佛不曾師。"]'),
('f09bd957-a961-43c4-baf7-dca38c1ee78f','佛心禪師頂相','釋普濟','宋','宋诗','song-poetry','','[]','千聖頭邊殃禍作，春風和氣滿叢林。',80,'全唐诗/poet.song.192000.json','["千聖頭邊殃禍作，春風和氣滿叢林。", "隨其機上者上之，任其器下者下之。", "一處不通，回天轉地。", "活天下死衲僧，死大地活衲子。", "是謂父不傳子不記之妙，如保福千聖頭邊殃禍者鮮矣。"]'),
('603865b9-66a2-4873-83bf-ea901feee0e6','石佛清長老請贊','釋普濟','宋','宋诗','song-poetry','','[]','東山之源，東磵之淵。',67,'全唐诗/poet.song.192000.json','["東山之源，東磵之淵。", "截流之機，驗人之眼。", "揚清激濁，地覆天翻。", "六代祖師，豎毛呵手。", "三生大像，頓足擎拳。", "彼又何須指南，吳越令行，而後有傳。"]'),
('bfdd918b-2a01-45cd-8b54-7acc59606ef5','圓覺頑空覺講主真贊二首  其一','釋普濟','宋','宋诗','song-poetry','','[]','頭鬅鬙，眼乖角。',112,'全唐诗/poet.song.192000.json','["頭鬅鬙，眼乖角。", "得天台之奧旨，繼永嘉之先覺。", "執文字見，離文字縛。", "說大義則四座風生，徵異解則百川潮落。", "昭昭乎教苑之祥麟，昂昂乎雞群之野鶴。", "雖正席四處不足暢其設施，然分座五山亦不負其所學。", "是爲廣智九世之孫，嘯巖一枝不致寥寞者矣。"]'),
('a7905619-34a8-45e8-b285-2b678732ed99','圓覺頑空覺講主真贊二首  其二','釋普濟','宋','宋诗','song-poetry','','[]','眼裏有筋，舌頭無骨。',88,'全唐诗/poet.song.192000.json','["眼裏有筋，舌頭無骨。", "卓然特立，天台祖室。", "寫懸河辯而四方絕唱，離文字相而諸天雨花。", "扣其關者紛紛紜紜而退席，得其旨者崢崢嶸嶸而莫及。", "且不以慈悲寶帳破麈白拂而當家傳，自有鸞膠續斷絃。"]'),
('dc457e74-24ba-484d-b454-2e264b153839','悅堂穆知閤寫師頂相請贊','釋普濟','宋','宋诗','song-poetry','','[]','春水滿四澤，夏雲多奇峰。',48,'全唐诗/poet.song.192000.json','["春水滿四澤，夏雲多奇峰。", "秋月揚明輝，冬嶺秀孤松。", "難描邈，絕知音。", "悅堂不是閑相識，贊不欣兮駡不嗔。"]'),
('12510a74-72fa-4422-a320-4472be2b9fab','覺如周居士圓相贊','釋普濟','宋','宋诗','song-poetry','','[]','一片虛凝絕謂情，眼橫鼻直强圖形。',32,'全唐诗/poet.song.192000.json','["一片虛凝絕謂情，眼橫鼻直强圖形。", "不如不覺全聲色，駡得毗耶老浄名。"]'),
('bbf79f4d-e5aa-452a-b054-133a8d45988e','自贊','釋普濟','宋','宋诗','song-poetry','','[]','出林虎方怒，橫岡蟒正嗔。',24,'全唐诗/poet.song.192000.json','["出林虎方怒，橫岡蟒正嗔。", "世無途路客，終是不傷人。"]'),
('d2047e19-27e4-4b4e-8818-2f60ed973979','福州長谿樂山王居士遣兒惟惺投師薙髮寫師頂相請贊  其一','釋普濟','宋','宋诗','song-poetry','','[]','聞名不如見面，見面不如聞名。',82,'全唐诗/poet.song.192000.json','["聞名不如見面，見面不如聞名。", "兩重虛假，一對眼睛。", "不近人情處，是句也剗，非句也剗。", "一味拍盲時，逼犬透牆，證龜成鼈。", "如斯杜撰，豈堪人師。", "誰知千里同風句，却有樂山居士知。"]'),
('7620c40a-1a25-43cb-b600-82bb147b1264','福州長谿樂山王居士遣兒惟惺投師薙髮寫師頂相請贊  其二','釋普濟','宋','宋诗','song-poetry','','[]','瘦骨稜層一擔夫，幾年寥落在江湖。',32,'全唐诗/poet.song.192000.json','["瘦骨稜層一擔夫，幾年寥落在江湖。", "面皮捩轉無人識，有甚閑名上祖圖。"]'),
('30eaf399-e79c-4029-98ff-c487e4173855','彌勒大士二月八生','釋普濟','宋','宋诗','song-poetry','','[]','契此老翁無記性，都忘生月與生辰。',32,'全唐诗/poet.song.192000.json','["契此老翁無記性，都忘生月與生辰。", "春風桃李能多事，特地年年說向人。"]'),
('32915147-1e9a-42b8-9ff9-c9eda84d0cc3','化炭','釋普濟','宋','宋诗','song-poetry','','[]','皮膚脫盡黑粼皴，猶有當時刀斧痕。',32,'全唐诗/poet.song.192000.json','["皮膚脫盡黑粼皴，猶有當時刀斧痕。", "待入門來重點化，教伊隨處衮烟塵。"]'),
('4ed62b3b-2687-4cba-a7fc-39bfb76ac5e6','雪庭','釋普濟','宋','宋诗','song-poetry','','[]','一度寒來不可禁，森羅萬象盡平沉。',32,'全唐诗/poet.song.192000.json','["一度寒來不可禁，森羅萬象盡平沉。", "個般門戶誰能入，著脚分明三尺深。"]'),
('655a3e9e-b0f1-4805-9a65-0d5a94893045','蜘蛛','釋普濟','宋','宋诗','song-poetry','','[]','一絲挂得虛空住，百億絲頭殺氣生。',32,'全唐诗/poet.song.192000.json','["一絲挂得虛空住，百億絲頭殺氣生。", "上下四維羅織了，一無漏網話方行。"]'),
('4800ab8a-48df-49cd-91dc-2ee594f022e2','示覺悟侍者','釋普濟','宋','宋诗','song-poetry','','[]','起家難似破家難，蕩盡田園出故關。',32,'全唐诗/poet.song.192000.json','["起家難似破家難，蕩盡田園出故關。", "佛祖二千年冷債，不消咳嗽一時還。"]'),
('e940adde-24c0-4459-a9d0-ecc752c57aac','水茶磨','釋普濟','宋','宋诗','song-poetry','','[]','機輪轉處水潺潺，機若停時水自閑。',32,'全唐诗/poet.song.192000.json','["機輪轉處水潺潺，機若停時水自閑。", "末上一遭知落處，十分春色滿人間。"]'),
('6880f7a3-a445-4b7e-8d7e-076d88cd8ee0','浮香閣','釋普濟','宋','宋诗','song-poetry','','[]','江城夜雨滿樓臺，池上殘紅撥不開。',32,'全唐诗/poet.song.192000.json','["江城夜雨滿樓臺，池上殘紅撥不開。", "慈氏家風都漏泄，善財南去未回來。"]'),
('3d3e98cf-fa3d-4fd1-9da5-b529940f98e5','送清凉淮海和尚住萬年','釋普濟','宋','宋诗','song-poetry','','[]','潮聲忽轉石頭城，大舍峰高側耳聽。',32,'全唐诗/poet.song.192000.json','["潮聲忽轉石頭城，大舍峰高側耳聽。", "五百箇僧都不會，教他一一侍巾瓶。"]'),
('c3d041ff-d5ec-469d-b589-8cf2a3581dbe','送夢窗和尚住浄慈','釋普濟','宋','宋诗','song-poetry','','[]','誌公有語問思大，東磵無言記夢窗。',32,'全唐诗/poet.song.192000.json','["誌公有語問思大，東磵無言記夢窗。", "今日夢窗下山去，笑他思大舌頭長。"]'),
('3c170355-4180-47e4-a80c-7487ba401a3e','送廣州泰長老','釋普濟','宋','宋诗','song-poetry','','[]','老盧曾見老黄梅，一首長廊落韻詩。',32,'全唐诗/poet.song.192000.json','["老盧曾見老黄梅，一首長廊落韻詩。", "既是同坑無異土，家私莫與路人知。"]'),
('6c766efd-e597-43e0-a74a-fef784a9e907','鍼醫','釋普濟','宋','宋诗','song-poetry','','[]','藥知性亦病知源，誰管屍靈骨已寒。',32,'全唐诗/poet.song.192000.json','["藥知性亦病知源，誰管屍靈骨已寒。", "痛下一針雙眼活，耆婆應未得其傳。"]'),
('6bcbd75e-8994-496a-9282-8a4895ba2e94','西隠','釋普濟','宋','宋诗','song-poetry','','[]','泥牛鬭入海門關，直到如今萬象閑。',32,'全唐诗/poet.song.192000.json','["泥牛鬭入海門關，直到如今萬象閑。", "百鳥不來春自老，柴門依舊向東山。"]'),
('59a3206e-c716-4257-a804-612a2cb9a837','大死','釋普濟','宋','宋诗','song-poetry','','[]','上門上戶拚窮命，不覺全身墮險崖。',32,'全唐诗/poet.song.192000.json','["上門上戶拚窮命，不覺全身墮險崖。", "盡十方空俱殞滅，玲瓏八面露死骸。"]'),
('3b7995b2-ac70-431b-abbd-87d9dfad906c','送貓兒','釋普濟','宋','宋诗','song-poetry','','[]','大慈悲種小斑斑，軟血功能也是閑。',32,'全唐诗/poet.song.192000.json','["大慈悲種小斑斑，軟血功能也是閑。", "首尾直兮眸子正，不知走却屋頭山。"]'),
('70e22303-1ff3-4019-83bb-2ecd31630ce6','寒衲','釋普濟','宋','宋诗','song-poetry','','[]','針鋒不露重重補，線脚通時密密參。',32,'全唐诗/poet.song.192000.json','["針鋒不露重重補，線脚通時密密參。", "放下無針無劄處，凍雲垂地一肩擔。"]'),
('056aed75-b13d-4139-b832-96dee02f9e2e','起水陸堂','釋普濟','宋','宋诗','song-poetry','','[]','一漚大覺海中興，十趣波濤不暫停。',32,'全唐诗/poet.song.192000.json','["一漚大覺海中興，十趣波濤不暫停。", "返本還源空覺海，滿堂風月雨初晴。"]'),
('6382a809-a6e3-4f77-bf52-6cc2584403a3','幹藏','釋普濟','宋','宋诗','song-poetry','','[]','惡語重重放出門，只圖一个不知恩。',32,'全唐诗/poet.song.192000.json','["惡語重重放出門，只圖一个不知恩。", "二千年事難遮覆，動便隨人脚後跟。"]'),
('9fc81335-14b7-466e-9ab4-3dec1bcaae15','示若臨侍者','釋普濟','宋','宋诗','song-poetry','','[]','一思面門摘不斷，放下重新買草鞋。',32,'全唐诗/poet.song.192000.json','["一思面門摘不斷，放下重新買草鞋。", "有路莫行無路入，照顧渾家落險崖。"]'),
('f363f79e-99c1-412f-91c1-f8b17ea4d056','在庵','釋普濟','宋','宋诗','song-poetry','','[]','世間幾見劫灰飛，老屋依前對落暉。',32,'全唐诗/poet.song.192000.json','["世間幾見劫灰飛，老屋依前對落暉。", "四大部洲都遍歷，到頭還向此中歸。"]'),
('196132e1-2a52-44c3-a3f0-d09f0aa55fe2','樵屋','釋普濟','宋','宋诗','song-poetry','','[]','鬻薪無價嶺南歸，尚有兒孫在翠微。',32,'全唐诗/poet.song.192000.json','["鬻薪無價嶺南歸，尚有兒孫在翠微。", "執樹縛茆門戶別，離離荆棘惹人衣。"]'),
('86bd8803-2aff-47e7-a547-d4e9c088bdb2','送人游方','釋普濟','宋','宋诗','song-poetry','','[]','南有天台北五臺，分明記取莫疑猜。',32,'全唐诗/poet.song.192000.json','["南有天台北五臺，分明記取莫疑猜。", "話頭打失不知處，乞我三文買草鞋。"]'),
('97ae573d-4562-481a-9874-003883429b56','胡桃','釋普濟','宋','宋诗','song-poetry','','[]','枝頭葉底不能藏，獨脫無依未廝當。',32,'全唐诗/poet.song.192000.json','["枝頭葉底不能藏，獨脫無依未廝當。", "一擊渾身如粉碎，不堪收拾始馨香。"]'),
('52febf8e-2638-4f3c-98f6-bf3bbf2aeb39','送日本國僧二首  其一','釋普濟','宋','宋诗','song-poetry','','[]','壁觀胡僧入大梁，單傳必死活人方。',32,'全唐诗/poet.song.192000.json','["壁觀胡僧入大梁，單傳必死活人方。", "至今此術遍天下，航海梯山空自忙。"]'),
('d89ca96a-e52e-439a-8543-d6367eae567f','送日本國僧二首  其二','釋普濟','宋','宋诗','song-poetry','','[]','大舶浮空駕浪來，頂門有眼未曾開。',32,'全唐诗/poet.song.192000.json','["大舶浮空駕浪來，頂門有眼未曾開。", "南山虎口翻身出，日本生成一禍胎。"]'),
('72c141b6-7779-4715-9e27-d100eaeb4ad7','送祖達侍者','釋普濟','宋','宋诗','song-poetry','','[]','呼喚不曾離左右，大都相見一番難。',32,'全唐诗/poet.song.192000.json','["呼喚不曾離左右，大都相見一番難。", "攢眉切齒歸來日，痛駡國師南北山。"]'),
('8033c3ae-58a4-4900-b4a8-e1beab676126','髑髏人我擔','釋普濟','宋','宋诗','song-poetry','','[]','一我一人裝一擔，不知出入幾胞胎。',32,'全唐诗/poet.song.192000.json','["一我一人裝一擔，不知出入幾胞胎。", "鐵圍山嶽高如許，撞破髑髏歸去來。"]'),
('65031895-f316-4b0c-abfd-0b5c09f14fa5','造龕子','釋普濟','宋','宋诗','song-poetry','','[]','病病相尋早是遲，鎖空龕子做多時。',32,'全唐诗/poet.song.192000.json','["病病相尋早是遲，鎖空龕子做多時。", "北邙山下明朝約，火後誰收眼底眉。"]'),
('23f1bdf8-5d9d-4448-8fca-cac98abfb8f7','柏巖','釋普濟','宋','宋诗','song-poetry','','[]','苗裔忽生崖石裂，不同松檜拂雲長。',32,'全唐诗/poet.song.192000.json','["苗裔忽生崖石裂，不同松檜拂雲長。", "蒼蒼無一閑枝葉，子落叢林也有香。"]'),
('0adb6f8b-f416-46f5-b7a6-59401f619859','進月軒','釋普濟','宋','宋诗','song-poetry','','[]','桂輪孤朗碧天寬，簾卷清光入座寒。',32,'全唐诗/poet.song.192000.json','["桂輪孤朗碧天寬，簾卷清光入座寒。", "底事明明人不薦，又移花影上欄干。"]'),
('2ad451f5-07e3-4c90-ae70-339deff1f126','示資壽慧一監寺','釋普濟','宋','宋诗','song-poetry','','[]','二由一有一莫守，面首面南看北斗。',32,'全唐诗/poet.song.192000.json','["二由一有一莫守，面首面南看北斗。", "勘破末山不露頂，玄機無著高叉手。"]'),
('14bea6af-3277-4940-9cd7-9aa9bb3a87de','竹谿','釋普濟','宋','宋诗','song-poetry','','[]','漱石穿崖落落，隨流截流自瞞。',28,'全唐诗/poet.song.192000.json','["漱石穿崖落落，隨流截流自瞞。", "窮到不知源處，風枝雨葉蕭然。"]'),
('8a737251-0e1c-47a9-8906-8e4502d7fb1c','山翁','釋普濟','宋','宋诗','song-poetry','','[]','重疊春風面，高低雪滿頭。',24,'全唐诗/poet.song.192000.json','["重疊春風面，高低雪滿頭。", "渠無生老相，孤峻罕人游。"]'),
('83a4b96b-f70f-4ffc-89ba-b071099741a5','刀鑷','釋普濟','宋','宋诗','song-poetry','','[]','得心應手乖毫髮，心手俱亡處處通。',32,'全唐诗/poet.song.192000.json','["得心應手乖毫髮，心手俱亡處處通。", "摘一莖髭彈一鑷，有相同有不相同。"]'),
