('009eb887-7c19-488f-be28-78acd7d67c59','嘉禾百詠 趙老園','張堯同','宋','宋诗','song-poetry','','[]','藏書幾萬卷，歸老此林泉。',24,'全唐诗/poet.song.192000.json','["藏書幾萬卷，歸老此林泉。", "不爲尋蓴鱠，于公亦有賢。"]'),
('c8bc3c62-4c90-4d59-949d-803dd87b6ef8','嘉禾百詠 施墓','張堯同','宋','宋诗','song-poetry','','[]','蒼苔侵壞道，晚雀散空林。',24,'全唐诗/poet.song.192000.json','["蒼苔侵壞道，晚雀散空林。", "莫問人賢否，浮生一古今。"]'),
('950a04a2-6505-4e56-8534-393da204ba94','嘉禾百詠 衛墓','張堯同','宋','宋诗','song-poetry','','[]','惆悵黎陽客，飄流浙水濱。',24,'全唐诗/poet.song.192000.json','["惆悵黎陽客，飄流浙水濱。", "定忘空腹恨，知是赤心人。"]'),
('5ae02d26-7eca-411d-8f63-79d6dca70c9a','嘉禾百詠 劉伶墓','張堯同','宋','宋诗','song-poetry','','[]','荷鍤從吾後，叮嚀死便埋。',24,'全唐诗/poet.song.192000.json','["荷鍤從吾後，叮嚀死便埋。", "人皆譏嗜酒，我獨愛忘懷。"]'),
('649f68ca-36e7-4272-b616-779b6a38f519','嘉禾百詠 嚴忌墓','張堯同','宋','宋诗','song-poetry','','[]','有子如君少，終緣叛國亡。',24,'全唐诗/poet.song.192000.json','["有子如君少，終緣叛國亡。", "冢前無後嗣，切勿怨張湯。"]'),
('e86ef222-c5ef-4217-a46d-0ada01cf2df5','嘉禾百詠 朱買臣墓','張堯同','宋','宋诗','song-poetry','','[]','世事春風轉，榮枯一夢間。',24,'全唐诗/poet.song.192000.json','["世事春風轉，榮枯一夢間。", "繡衣人不見，孤冢舊家山。"]'),
('ce188cb6-5561-447c-9e59-df8bacd30af7','嘉禾百詠 周都官墓','張堯同','宋','宋诗','song-poetry','','[]','不識君名字，應難問子孫。',24,'全唐诗/poet.song.192000.json','["不識君名字，應難問子孫。", "一丘浮水際，神怪欲誰論。"]'),
('a8d80c78-b513-428e-848f-f77164abbe43','嘉禾百詠 蘇小小墓','張堯同','宋','宋诗','song-poetry','','[]','泉下骨應朽，幽魂獨未消。',24,'全唐诗/poet.song.192000.json','["泉下骨應朽，幽魂獨未消。", "幾番清夜月，孤影度南橋。"]'),
('1da86be0-df2b-4570-9b87-a7b679c2cace','嘉禾百詠 羞墓','張堯同','宋','宋诗','song-poetry','','[]','傷哉負薪子，五十始登朝。',24,'全唐诗/poet.song.192000.json','["傷哉負薪子，五十始登朝。", "空使埋羞處，山花復採樵。"]'),
('c93a52e1-08bc-4e0b-b915-f30b5ab37c14','嘉禾百詠 木紋觀音','張堯同','宋','宋诗','song-poetry','','[]','雙瞳分日月，眉際一星懸。',24,'全唐诗/poet.song.192000.json','["雙瞳分日月，眉際一星懸。", "照見人間苦，三辰不在天。"]'),
('f170565d-c074-4b63-b650-b9efaee650bf','嘉禾百詠 邦藥王龕','張堯同','宋','宋诗','song-poetry','','[]','父老懷遺愛，誰傳肘後方。',24,'全唐诗/poet.song.192000.json','["父老懷遺愛，誰傳肘後方。", "藥囊同日葬，空憶紫元香。"]'),
('7fc4681d-7fdd-4313-9f81-7dc3e21bdb0b','嘉禾百詠 浄相佳李','張堯同','宋','宋诗','song-poetry','','[]','地重因名果，如分沆瀣漿。',24,'全唐诗/poet.song.192000.json','["地重因名果，如分沆瀣漿。", "傷心吳越戰，未敢盡情嘗。"]'),
('ca20c7be-43ec-44a6-a3c8-dc183d4ae876','嘉禾百詠 符姥瑞竹','張堯同','宋','宋诗','song-poetry','','[]','一幅霜縑外，青青出自然。',24,'全唐诗/poet.song.192000.json','["一幅霜縑外，青青出自然。", "天機何敢議，珍重白衣仙。"]'),
('b6c2e4ad-3ac7-4734-925e-b7647103e74b','徐家莊','張堯同','宋','宋诗','song-poetry','','[]','節義窮方見，高名薦玉京。',24,'全唐诗/poet.song.192000.json','["節義窮方見，高名薦玉京。", "一封天子敕，千載故鄉榮。"]'),
('a6a0d2f0-9dc3-41f1-b54b-c9595ff1e0c4','立秋','沈說','宋','宋诗','song-poetry','','[]','昨日午時秋，西風夜轉頭。',48,'全唐诗/poet.song.192000.json','["昨日午時秋，西風夜轉頭。", "吹來溪外雨，藏却樹間樓。", "暝带棲鴉色，凉催客燕愁。", "一樽吟未了，衰鬢早颼颼。"]'),
('4d82a757-251e-418f-948a-2649eabfdaeb','仁福道中','沈說','宋','宋诗','song-poetry','','[]','山徑少曾平，人烟隔隴青。',48,'全唐诗/poet.song.192000.json','["山徑少曾平，人烟隔隴青。", "淺流分石渡，低樹礙輿行。", "稅籍全編戶，村童半壯丁。", "我來官此邑，三度究民情。"]'),
('6b9666b2-8612-449a-a7f4-f2632f7c29b7','偶成','沈說','宋','宋诗','song-poetry','','[]','讀罷黄庭一卷經，磬殘烟冷夜壇清。',32,'全唐诗/poet.song.192000.json','["讀罷黄庭一卷經，磬殘烟冷夜壇清。", "月明何處人開戶，驚起松梢睡鶴鳴。"]'),
('bde02dc4-5a8e-4b87-b9f5-a2c5d8ee710d','征途','沈說','宋','宋诗','song-poetry','','[]','桂管三千里，征人一寸心。',48,'全唐诗/poet.song.192000.json','["桂管三千里，征人一寸心。", "自從登驛路，幾見換鄉音。", "古樹春陰薄，寒塘野水深。", "渴行呼得酒，瓦碗不辭斟。"]'),
('a3ee888e-2bf5-4575-b0ef-36b3091f915f','暮春','沈說','宋','宋诗','song-poetry','','[]','燕翼初乾淥滿池，桑陰收盡麥黄時。',64,'全唐诗/poet.song.192000.json','["燕翼初乾淥滿池，桑陰收盡麥黄時。", "一年春事又成夢，幾日愁懷欲廢詩。", "料理病身嘗藥遍，揩摩睡眼看書遲。", "翛然獨倚闌干立，花下狸奴卧弄兒。"]'),
('46429f1a-796f-42e6-96c4-5afb0e393049','紙衾三首  其一','沈說','宋','宋诗','song-poetry','','[]','碎搗霜藤月下砧，清泉瀉出簟紋勻。',32,'全唐诗/poet.song.192000.json','["碎搗霜藤月下砧，清泉瀉出簟紋勻。", "老翁採藥歸來晚，剪得山南半段雲。"]'),
('e2e8ec6b-6f76-4c07-8567-947884872186','紙衾三首  其二','沈說','宋','宋诗','song-poetry','','[]','繭面新乾带露揉，春回斗帳伴吟愁。',32,'全唐诗/poet.song.192000.json','["繭面新乾带露揉，春回斗帳伴吟愁。", "殘年已辦蒙頭過，風雪從教打戍樓。"]'),
('54ab2d98-bece-425f-af51-6ee6182e3a27','紙衾三首  其三','沈說','宋','宋诗','song-poetry','','[]','一幅新裁碧澗冰，野人留客宿雲層。',32,'全唐诗/poet.song.192000.json','["一幅新裁碧澗冰，野人留客宿雲層。", "山房恰好松醪熟，夜半無眠話葛藤。"]'),
('70837234-71ba-42c7-971e-bba916b6ee21','春詞','沈說','宋','宋诗','song-poetry','','[]','水漲寒溝柳又陰，小窗風度一聲禽。',32,'全唐诗/poet.song.192000.json','["水漲寒溝柳又陰，小窗風度一聲禽。", "若將離緒縈春事，片片飛花是客心。"]'),
('48cc8cde-888b-489e-acd0-becce1da9963','送何榷院之官金陵','沈說','宋','宋诗','song-poetry','','[]','分司陪宰掾，賜勑带朝銜。',48,'全唐诗/poet.song.192000.json','["分司陪宰掾，賜勑带朝銜。", "見說成行李，無因別去帆。", "秋風石城路，夜月雨花巖。", "料有驚人句，鴻邊寄短函。"]'),
('1c612be7-3087-4bf2-8bf8-1a84ead72e0a','溪樓','沈說','宋','宋诗','song-poetry','','[]','心遠俗塵隔，樓高野興多。',48,'全唐诗/poet.song.192000.json','["心遠俗塵隔，樓高野興多。", "稻花黄雀雨，山影白鷗波。", "灘澀推船上，橋危挽客過。", "日斜欄倚遍，無句奈愁何。"]'),
('a93d7ce3-c2d2-4c4d-a4b6-b57af97482d7','寄張永堂','沈說','宋','宋诗','song-poetry','','[]','浙江風浪闊，夢不落吟邊。',48,'全唐诗/poet.song.192000.json','["浙江風浪闊，夢不落吟邊。", "書到知何日，君歸想隔年。", "才高朝士重，命拙故人憐。", "早辦山中計，吾今省俗緣。"]'),
('9040ec68-1be0-4bfb-8205-5ea8efa7f49c','烟浦','沈說','宋','宋诗','song-poetry','','[]','烟浦殘鴉舞夕陽，風枝病葉似初霜。',64,'全唐诗/poet.song.192000.json','["烟浦殘鴉舞夕陽，風枝病葉似初霜。", "眼中秋色十分浄，沙外寒流一綫長。", "溪女得魚烹碎白，田家收穀曬新黄。", "偶尋野趣歸來晚，草際螢飛點點光。"]'),
('d642dfb1-e6bb-4997-ba73-0f23219aae9c','渠流','沈說','宋','宋诗','song-poetry','','[]','岸石濕黏萍，一渠流水清。',48,'全唐诗/poet.song.192000.json','["岸石濕黏萍，一渠流水清。", "每來疑雨過，少立見魚行。", "樹隔炎歊遠，橋分午影平。", "主人契幽事，客到出相迎。"]'),
('7a44a8f7-78d7-40fb-bc45-8521cb5d9ba4','安石嶺','沈說','宋','宋诗','song-poetry','','[]','茅屋雞聲勘夜分，杖藜挑月带餘醺。',32,'全唐诗/poet.song.192000.json','["茅屋雞聲勘夜分，杖藜挑月带餘醺。", "不知身在孤峰頂，回首人家盡白雲。"]'),
('3db7b817-d487-4f13-8ad1-63c17f26afd1','縉雲道中','沈說','宋','宋诗','song-poetry','','[]','去作京華客，離家此月前。',48,'全唐诗/poet.song.192000.json','["去作京華客，離家此月前。", "問程恰中道，數日近殘年。", "山雨易成雪，村雲疑是烟。", "僕行愁不進，添乞酒漿錢。"]'),
('5372797b-9f1f-40ea-a33b-e037858e2790','次韻立方何園','沈說','宋','宋诗','song-poetry','','[]','春事覺垂垂，春行似後期。',48,'全唐诗/poet.song.192000.json','["春事覺垂垂，春行似後期。", "草根花片積，人語鳥聲隨。", "酒病因過量，棋輸爲好奇。", "欲歸愁路遠，月色若爲私。"]'),
('19c3546d-08a0-459b-b222-59cfeacf17dc','次韻永堂','沈說','宋','宋诗','song-poetry','','[]','鶑聲未改春，葉底一蟬新。',48,'全唐诗/poet.song.192000.json','["鶑聲未改春，葉底一蟬新。", "幻境老無夢，醉鄉詩有神。", "整巾因把鏡，懶語怕逢人。", "似此衰遲者，勞君料理頻。"]'),
('44b2cbe3-0b4b-445b-941f-4eb3220cee9a','古樹','沈說','宋','宋诗','song-poetry','','[]','古樹被青蘚，蟠溪作卧龍。',48,'全唐诗/poet.song.192000.json','["古樹被青蘚，蟠溪作卧龍。", "窮冬不蔽日，入夏却生風。", "枝少禽難託，根空蟻聚封。", "幸爲斤斧棄，得老雪霜中。"]'),
('ebada104-2962-4251-a21c-19937894eb5f','買舟','沈說','宋','宋诗','song-poetry','','[]','租得舟如葉，低低半搭篷。',48,'全唐诗/poet.song.192000.json','["租得舟如葉，低低半搭篷。", "僅堪容野客，還喜友漁翁。", "溯水斜分浪，懸崖逆鬭風。", "去程應不計，且泊槿花叢。"]'),
('9282b56c-08e8-4828-9928-c0e09b2631b1','明融盆池二首  其一','沈說','宋','宋诗','song-poetry','','[]','凉入湘簾影半開，小窗午枕夢初回。',32,'全唐诗/poet.song.192000.json','["凉入湘簾影半開，小窗午枕夢初回。", "蕭疏數葉秋菰上，也解聲聲報雨來。"]'),
('19db473e-fdc2-4ba5-b43c-57102a4fc0a9','明融盆池二首  其二','沈說','宋','宋诗','song-poetry','','[]','老瓦盆深漾細萍，雨多流却半瓣青。',32,'全唐诗/poet.song.192000.json','["老瓦盆深漾細萍，雨多流却半瓣青。", "夜凉偶出庭心看，缺處光涵三兩星。"]'),
('c2d09e56-2dbf-42d4-81d2-dcb5653bdd9e','聽雨','沈說','宋','宋诗','song-poetry','','[]','耳根聽不歇，滴滴冷於秋。',24,'全唐诗/poet.song.192000.json','["耳根聽不歇，滴滴冷於秋。", "疑是山翁醉，巖前枕瀑流。"]'),
('f002ea24-bf9a-445c-974d-2657b113db65','晚春','沈說','宋','宋诗','song-poetry','','[]','白頭何計是生涯，日日樽前卧落花。',32,'全唐诗/poet.song.192000.json','["白頭何計是生涯，日日樽前卧落花。", "綠滿池塘無一夢，夜來風雨過誰家。"]'),
('98ead1f4-eb25-405d-aab8-3ac61e316d1b','贈段琴','沈說','宋','宋诗','song-poetry','','[]','我琴未弦時，渾然心與耳。',48,'全唐诗/poet.song.192000.json','["我琴未弦時，渾然心與耳。", "自從識開指，反爲琴所使。", "清風千古曲，雪澗敲寒玉。", "誰能繼此音，蒼梧泣脩竹。"]'),
('277843f2-ded4-47e6-830b-2bdcf48db33d','贈段琴  其一','沈說','宋','宋诗','song-poetry','','[]','我琴未弦時，渾然心與耳。',24,'全唐诗/poet.song.192000.json','["我琴未弦時，渾然心與耳。", "自從識開指，反爲琴所使。"]'),
('8196e8d0-571d-434f-aaaf-59699e325cc7','贈段琴  其二','沈說','宋','宋诗','song-poetry','','[]','清風千古曲，雪澗敲寒玉。',24,'全唐诗/poet.song.192000.json','["清風千古曲，雪澗敲寒玉。", "誰能繼此音，蒼梧泣脩竹。"]'),
('da546f65-8540-4726-b54c-fb269912f67d','食梅','沈說','宋','宋诗','song-poetry','','[]','兒時摘青梅，葉底尋彈丸。',72,'全唐诗/poet.song.192000.json','["兒時摘青梅，葉底尋彈丸。", "所恨襟袖窄，不憚頰舌穿。", "我年不自覺，以我齒尚完。", "嘗新試一薦，喉棘眉先攢。", "豈味不悅口，豈老難强餐。", "人生煎百憂，算梅未爲酸。"]'),
('ac376cfd-3e28-4b70-b763-d3d48ec548ff','秋詞','沈說','宋','宋诗','song-poetry','','[]','雨放凉飈晚復晴，小窗人亦共秋清。',32,'全唐诗/poet.song.192000.json','["雨放凉飈晚復晴，小窗人亦共秋清。", "月華網在蛛絲上，錯認疏簾挂水晶。"]'),
('e7a7e0dd-0520-4141-b4d7-88cdbf0587b9','閨詞  其一','沈說','宋','宋诗','song-poetry','','[]','密幄香燒錦瑟橫，佳人半醉覺寒輕。',32,'全唐诗/poet.song.192000.json','["密幄香燒錦瑟橫，佳人半醉覺寒輕。", "忽思塞下新番曲，彈作黄蘆孤雁聲。"]'),
('355977ec-ffec-46ac-8f62-6485b1248afe','閨詞  其二','沈說','宋','宋诗','song-poetry','','[]','冬事侵尋渾未知，隔隣聽得理寒衣。',32,'全唐诗/poet.song.192000.json','["冬事侵尋渾未知，隔隣聽得理寒衣。", "驚心步出庭西曲，日影斜斜木葉飛。"]'),
('2862ada6-4ffa-4ab7-b8f3-b3e9d8b1af7d','馮公嶺','沈說','宋','宋诗','song-poetry','','[]','曉上馮公嶺，艱難見客情。',48,'全唐诗/poet.song.192000.json','["曉上馮公嶺，艱難見客情。", "雨和殘葉落，身逐亂雲行。", "野店山腰出，秋泉石罅生。", "若將世途比，此路更爲平。"]'),
('63d3f50a-1bbd-45ce-88fb-4077916ce6f9','山中秋興','沈說','宋','宋诗','song-poetry','','[]','山戶少曾扃，居貧易得清。',48,'全唐诗/poet.song.192000.json','["山戶少曾扃，居貧易得清。", "秋衣和月卧，溪茗雜雲烹。", "學字書紅葉，看騷些落英。", "從他頭早白，心事本和平。"]'),
('e06d374f-19bf-450c-b4e4-e41ccbf841a7','別墅','沈說','宋','宋诗','song-poetry','','[]','野舍清溪曲，連茅接樹陰。',48,'全唐诗/poet.song.192000.json','["野舍清溪曲，連茅接樹陰。", "呼童隣錯應，貰酒婦同斟。", "落照收殘雨，寒烟出寸岑。", "江湖成夢事，投老屬山林。"]'),
('3442e729-be8f-4797-a4f3-0d9ae59610f0','次韻古愚立冬日觀菊','沈說','宋','宋诗','song-poetry','','[]','閑繞籬頭看菊花，深黄淺紫自窠窠。',64,'全唐诗/poet.song.192000.json','["閑繞籬頭看菊花，深黄淺紫自窠窠。", "清於簷蔔香尤耐，韻比猗蘭色更多。", "九節番疑今日是，一樽未覺晚秋過。", "從教白髮須簪遍，且任當筵作笑歌。"]'),
('037e9776-f20c-4a68-870d-63fa40bca6a2','竹色','沈說','宋','宋诗','song-poetry','','[]','竹色留清睡，薰風晝一簾。',48,'全唐诗/poet.song.192000.json','["竹色留清睡，薰風晝一簾。", "懶因人事少，病覺老顔添。", "開檻臨昏鏡，齊書補墜籤。", "晚蟬聲欲斷，新月到虛簷。"]'),
('b31b8002-2cd6-4029-8366-4e703268ebdf','曉色','沈說','宋','宋诗','song-poetry','','[]','曉色闌干外，翛然一欠伸。',48,'全唐诗/poet.song.192000.json','["曉色闌干外，翛然一欠伸。", "雨中無過鳥，烟際有行人。", "樹濕清陰重，沙坍潦漲新。", "憑誰借蓑笠，整釣傍溪隣。"]'),
('64ab378a-5be9-4994-ae58-3cdd4ca19dd8','薌溪途中','沈說','宋','宋诗','song-poetry','','[]','天風吹落日，秋色上遥岑。',48,'全唐诗/poet.song.192000.json','["天風吹落日，秋色上遥岑。", "倦客未投館，棲鴉已滿林。", "妻孥非遠別，歲月易驚心。", "市酒不成醉，新蛩助我吟。"]'),
('2e83322c-d37e-4f4f-b887-560e3a50af81','雪','沈說','宋','宋诗','song-poetry','','[]','凍項縮如龜，茅簷諷雪詩。',48,'全唐诗/poet.song.192000.json','["凍項縮如龜，茅簷諷雪詩。", "冷於初下日，好是未消時。", "樹重高枝折，窗明晚色遲。", "忽思溪上路，擬借蹇馿騎。"]'),
('b7b61b3f-e1f2-4a99-ac98-5fcb07b0e1cd','遊真巖','沈說','宋','宋诗','song-poetry','','[]','一徑入松林，真巖峭莫尋。',48,'全唐诗/poet.song.192000.json','["一徑入松林，真巖峭莫尋。", "山空泉自落，日出地長陰。", "鶴去仙臺浄，丹成古井深。", "殘碑看未了，屋角轉幽禽。"]'),
('c6cfbd13-5d16-46f7-a82d-f01b35b6db18','送周堂長歸慈溪寄何贊府','沈說','宋','宋诗','song-poetry','','[]','慈溪隔楚雲，問不接鴻鱗。',48,'全唐诗/poet.song.192000.json','["慈溪隔楚雲，問不接鴻鱗。", "因送還鄉客，重懷佐邑人。", "海明看出日，山晚倦行春。", "料得雙松下，吟成瘦鶴身。"]'),
('acee7a0d-6342-4e2a-924f-77cf92835c58','超化雲山','沈說','宋','宋诗','song-poetry','','[]','入門松作徑，步步接秋陰。',48,'全唐诗/poet.song.192000.json','["入門松作徑，步步接秋陰。", "山带孤城起，雲歸古殿深。", "隔池聞鶴唳，倚樹看僧吟。", "笑指煎茶處，青烟出竹林。"]'),
('ac506e7b-3a45-404c-8b73-f849ee4a41ec','題黄止庵詩集','沈說','宋','宋诗','song-poetry','','[]','燈前幾寒夜，編得近詩成。',48,'全唐诗/poet.song.192000.json','["燈前幾寒夜，編得近詩成。", "對客時評看，歸囊喜带行。", "風高霜鶻健，木落澗秋清。", "吟到無吟處，蕭蕭白髮生。"]'),
('391f8569-c139-46df-bcbe-74c1ced7255d','釣臺','沈說','宋','宋诗','song-poetry','','[]','山束江流起素湍，羊裘立盡暮雲寒。',32,'全唐诗/poet.song.192000.json','["山束江流起素湍，羊裘立盡暮雲寒。", "早知鈎餌成虛設，多却當時一釣竿。"]'),
('ac60c2a6-1f42-4698-841b-9690f7871486','西湖獨步','沈說','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平湖開霽色，寒碧照空心。',48,'全唐诗/poet.song.192000.json','["平湖開霽色，寒碧照空心。", "小立背橋影，緩行隨柳陰。", "幾年勞遠夢，到日記曾吟。", "荷蕩成茭地，蕭蕭秋意深。"]'),
('6712cdee-49fe-44f3-84c2-99ee2e1413b7','送何水竹需次入剡易齋赴浙漕','沈說','宋','宋诗','song-poetry','','[]','弟兄聯騎出，秋色赴行裝。',48,'全唐诗/poet.song.192000.json','["弟兄聯騎出，秋色赴行裝。", "慈水瓜應熟，孤山桂又香。", "對床村店寂，起飯曉燈凉。", "到日分吳越，江流兩岸長。"]'),
('6c3a0548-381e-444d-a34d-ca0e05bb5d55','南坡不以科目自累而以風雅自鳴請余爲賦','沈說','宋','宋诗','song-poetry','','[]','鳳銜科詔出祥雲，底事儒林有逸民。',64,'全唐诗/poet.song.192000.json','["鳳銜科詔出祥雲，底事儒林有逸民。", "四海聲名難著我，一坡風月正宜人。", "鏡留白髮非遮俗，家釀黄柑可接春。", "只許詩朋自來往，素袍青履華陽巾。"]'),
('1eacdbb4-c9fe-4d9d-a41e-b4b73b43a528','雞鳴','沈說','宋','宋诗','song-poetry','','[]','雞鳴霜葉下，月在紙窗寒。',48,'全唐诗/poet.song.192000.json','["雞鳴霜葉下，月在紙窗寒。", "客路千家曉，山居一枕安。", "秫收催歲釀，韮種接春盤。", "縱有少年夢，其如心事闌。"]'),
('60a4ad42-b65c-4ae9-ae6d-ded1964738dc','寄永堂','沈說','宋','宋诗','song-poetry','','[]','落日照江東，思君訊便風。',48,'全唐诗/poet.song.192000.json','["落日照江東，思君訊便風。", "棲遲定何處，約莫過殘冬。", "小隠時曾到，安書久未通。", "自憐心易老，盤屈似寒松。"]'),
('b147c570-8b31-4e46-b8b7-cbbf80671aba','送觀過免舉赴省','沈說','宋','宋诗','song-poetry','','[]','樽前逢臘近，行李獨西征。',48,'全唐诗/poet.song.192000.json','["樽前逢臘近，行李獨西征。", "事歷風霜慣，春回雨露生。", "一經家自學，千佛世題名。", "昨夜瞻奎宿，寒芒萬丈明。"]'),
('256ad34c-f584-43a3-9918-a23f64080f71','茅簷','沈說','宋','宋诗','song-poetry','','[]','茅簷夜雪曉開晴，自洗寒衣漉澗清。',32,'全唐诗/poet.song.192000.json','["茅簷夜雪曉開晴，自洗寒衣漉澗清。", "如此過冬何不可，梅花休笑鬢星星。"]'),
('818fcef3-4820-4600-ab67-4502e91161a6','冬半','沈說','宋','宋诗','song-poetry','','[]','歲逢冬欲半，心事更迢迢。',48,'全唐诗/poet.song.192000.json','["歲逢冬欲半，心事更迢迢。", "細雨寒窗閉，孤燈長夜挑。", "遠書和夢寫，新酒带愁澆。", "明日有幽興，尋梅到石橋。"]'),
('7ab006a5-d2ea-428d-9ac6-630ff4c472ba','挽鮑監鎮','沈說','宋','宋诗','song-poetry','','[]','一紙辟書馳，華年發軔時。',48,'全唐诗/poet.song.192000.json','["一紙辟書馳，華年發軔時。", "排雲何不到，殞露遽如斯。", "幼子未知父，偏親反哭兒。", "有書來謁些，忍淚看埋碑。"]'),
('4a04f432-64dd-4731-9c70-d161a44610d2','送何仲遠適越因之官霅水','沈說','宋','宋诗','song-poetry','','[]','樽酒沙頭綠漲波，事歡其柰別愁何。',64,'全唐诗/poet.song.192000.json','["樽酒沙頭綠漲波，事歡其柰別愁何。", "去程想憩蘭亭竹，到日須看霅浦荷。", "年少莫嫌官職小，名高却怕薦書多。", "臘前擬作孤山夢，還許扁舟載雪過。"]'),
('e1d7f61a-7ea1-43b5-b873-8115f2cfe232','簡柳濬卿','沈說','宋','宋诗','song-poetry','','[]','一別僅三年，相看事宛然。',48,'全唐诗/poet.song.192000.json','["一別僅三年，相看事宛然。", "旋添新蒜髮，猶聳舊吟肩。", "紅日征途外，黄花喜氣邊。", "不須勞寄問，姓字有人傳。"]'),
('15a84efd-234d-4d21-a6ca-468d76ec2d62','秋溪','沈說','宋','宋诗','song-poetry','','[]','迎月步秋溪，蘆長與樹齊。',48,'全唐诗/poet.song.192000.json','["迎月步秋溪，蘆長與樹齊。", "水光連漢近，夜氣壓山低。", "岸隔呼漁渡，林疏見鳥棲。", "酒微風力勁，歸袖冷凄凄。"]'),
('8631bdf0-482e-4831-a8e1-f131637b2f0d','晚行','沈說','宋','宋诗','song-poetry','','[]','晚行疏松間，遥見青烟處。',48,'全唐诗/poet.song.192000.json','["晚行疏松間，遥見青烟處。", "群牧下山遲，斜陽半芳樹。", "孤雲駕回飈，介水橫不渡。", "傾意望幽人，待月同歸步。"]'),
('81039bdb-21da-4411-a18c-56de019d10b5','野店','沈說','宋','宋诗','song-poetry','','[]','幽人逢野客，相約過雲莊。',48,'全唐诗/poet.song.192000.json','["幽人逢野客，相約過雲莊。", "去路稻粱熟，入山松柏香。", "試霜寒尚薄，落葉夜初長。", "對坐煨茅栗，瓶中取酒嚐。"]'),
('a9d4614d-ec0a-46a2-b453-337719784edb','閒居雜興六首  其一','陳耆卿','宋','宋诗','song-poetry','','[]','萬化逐流水，一往不復回。',48,'全唐诗/poet.song.192000.json','["萬化逐流水，一往不復回。", "昨日欄中花，今晨安在哉。", "焚香心如冰，未受寒暑催。", "贈花以片言，自落還自開。"]'),
('eb8461f0-29b0-4400-a602-96d821a99760','閒居雜興六首  其二','陳耆卿','宋','宋诗','song-poetry','','[]','稷契不明經，伊傅不决科。',48,'全唐诗/poet.song.192000.json','["稷契不明經，伊傅不决科。", "方冊鎸勳名，千古光不磨。", "百年等一死，自立須嵯峨。", "啾啾候蟲鳴，辛苦如之何。"]'),
('2898d638-f85f-4125-8235-d30e41f8ea53','閒居雜興六首  其三','陳耆卿','宋','宋诗','song-poetry','','[]','牆西幾篔簹，我昔手所種。',48,'全唐诗/poet.song.192000.json','["牆西幾篔簹，我昔手所種。", "年來飽風露，錦綳紛錯綜。", "種善如種竹，此語合擎誦。", "眇然方寸間，仁不可勝用。"]'),
('41e6ee8b-9535-41b1-9298-92304885218f','閒居雜興六首  其四','陳耆卿','宋','宋诗','song-poetry','','[]','我不學楚人，滋蘭以自馥。',48,'全唐诗/poet.song.192000.json','["我不學楚人，滋蘭以自馥。", "亦未羨東陵，種瓜以混俗。", "富貴自有時，貧賤寧可欲。", "達則濟四海，窮則獨善足。"]'),
('0aed9ea5-76ca-49fe-9908-8e1d47107e8e','閒居雜興六首  其五','陳耆卿','宋','宋诗','song-poetry','','[]','狂飆捲春去，永日送夏來。',48,'全唐诗/poet.song.192000.json','["狂飆捲春去，永日送夏來。", "天地一劇戲，役人如嬰孩。", "借使長青春，人生能幾回。", "仰羨松心堅，雪裏常崔嵬。"]'),
('69c7d20d-fa74-4f68-9ab9-2518933abf23','閒居雜興六首  其六','陳耆卿','宋','宋诗','song-poetry','','[]','爐烟上疎櫺，閉戶白日靜。',48,'全唐诗/poet.song.192000.json','["爐烟上疎櫺，閉戶白日靜。", "堯舜亦人耳，萬善吾所性。", "紙上空支離，言外獨輝映。", "一笑千載寬，此樂無終竟。"]'),
('b5309451-c0b8-4021-a6ad-0723272d2928','以新凉入郊墟爲韻簡葉孟我丈  其一','陳耆卿','宋','宋诗','song-poetry','','[]','日月不相貸，四序如昏晨。',48,'全唐诗/poet.song.192000.json','["日月不相貸，四序如昏晨。", "話秋即秋隨，化工一何神。", "今年既悲秋，明年復懷春。", "人心有去來，天道無故新。"]'),
('1de0c4af-26c6-46db-8a54-7a0838305922','以新凉入郊墟爲韻簡葉孟我丈  其二','陳耆卿','宋','宋诗','song-poetry','','[]','警夜聽鳴蛩，聒午聞啼螿。',48,'全唐诗/poet.song.192000.json','["警夜聽鳴蛩，聒午聞啼螿。", "不知誰使令，萬態俱悠揚。", "宋玉辯已非，歐陽賦何忙。", "正念有冰壺，日日如此凉。"]'),
('6ff025ba-d918-45c3-bd02-be609cc3c102','以新凉入郊墟爲韻簡葉孟我丈  其三','陳耆卿','宋','宋诗','song-poetry','','[]','世事如車輪，可旋不可執。',48,'全唐诗/poet.song.192000.json','["世事如車輪，可旋不可執。", "得者未須歌，失者何勞泣。", "我觀人心躁，甚如西風急。", "役役幾時休，山林可深入。"]'),
('63b8f001-3d8a-43e9-8f8b-61c4ae2cc4f4','以新凉入郊墟爲韻簡葉孟我丈  其四','陳耆卿','宋','宋诗','song-poetry','','[]','平生一飽足，大宴非珍肴。',48,'全唐诗/poet.song.192000.json','["平生一飽足，大宴非珍肴。", "秋月拓綺羅，秋風奏笙匏。", "問此有何樂，無樂樂乃高。", "琴書足匡坐，干旌謝在郊。"]'),
('b0d1fbb3-098c-4c99-b3a7-16c9533caeb9','以新凉入郊墟爲韻簡葉孟我丈  其五','陳耆卿','宋','宋诗','song-poetry','','[]','蕭散不耐事，常甘賓客疎。',48,'全唐诗/poet.song.192000.json','["蕭散不耐事，常甘賓客疎。", "不見葉夫子，我心却躊躇。", "願勿寒前盟，相從带經鋤。", "羲黄未埃塵，周孔不丘墟。"]'),
('64ed42d9-de08-4dac-a0b0-25ad31c6eb39','種菊','陳耆卿','宋','宋诗','song-poetry','','[]','手種黄金花，摩挱待其成。',72,'全唐诗/poet.song.192000.json','["手種黄金花，摩挱待其成。", "朝來風雨過，萬彙秋竛竮。", "起問花知不，獨立常亭亭。", "嘗於清霜下，退然得此生。", "南山與東籬，我亦學淵明。", "久落塵網中，問花花不譍。"]'),
('7428e202-880c-46f3-9dd2-939dc82c5c40','和芥庵韻','陳耆卿','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','孟軻談一本，孔子號無我。',228,'全唐诗/poet.song.192000.json','["孟軻談一本，孔子號無我。", "聖賢超警趣，不作流俗墮。", "故能貫堪輿，中立而不頗。", "黄冠宗無爲，衲子只打坐。", "言若高峭甚，又與聖賢左。", "須於真實處，大海穩扶柁。", "須於疑似間，曲戶牢著鎖。", "世道震遂泥，人心履俱跛。", "競作夔憐蚿，徒勞螟祝臝。", "芥庵之心鏡，淵珠光徹顆。", "常時足歡娛，此日類坎軻。", "乃能貞其頤，不爲名利朶。", "敲棋聲落枰，哦詩氣摧垜。", "此外澹一視，泰山如草蓏。", "未妨師孔孟，匪涉佛老惰。", "汩余抱孤戇，匪惟縶庸瑣。", "涉世雖云闊，詣理猶未妥。", "正性水下月，邪焰風中火。", "因子當自强，朝聞夕死可。"]'),
('39a7f967-b326-47fd-adce-1e98db2a770a','夷齊咏','陳耆卿','宋','宋诗','song-poetry','','[]','商道昔波蕩，周王網九圍。',120,'全唐诗/poet.song.192000.json','["商道昔波蕩，周王網九圍。", "二子如冥鴻，翩然獨高飛。", "周粟固可耻，薇亦周之薇。", "云胡挾孤憤，了不悟衆誹。", "天地有正氣，日月無斜暉。", "惜哉權一字，謬誤無已時。", "武德紂之虐，賢者誠知之。", "爲欲扶此教，之死不願違。", "吁嗟臣道薄，千載常凄其。", "欲上西山望，草際露未晞。"]'),
('cc8ae43a-ef5c-407f-8c4a-3d5c5e23c490','種麥','陳耆卿','宋','宋诗','song-poetry','','[]','新穀未升陳穀罄，宵人托麥以爲命。',128,'全唐诗/poet.song.192000.json','["新穀未升陳穀罄，宵人托麥以爲命。", "今年種麥如去年，去年滿屋今空田。", "吁嗟皇天毋乃戾，去年浙右當死歲。", "湘中死寇淮死兵，留得東州僅旒綴。", "只今艱食遽如斯，豈是造化有乘除。", "我無一語活四海，對之泣下徒霑裾。", "催租官吏如束濕，里正打門急復急。", "眼中安得豳風圖，繪出麥田蓑與笠。"]'),
('ec068790-7979-4aee-91b8-6a968fe24a62','題湯正仲墨梅','陳耆卿','宋','宋诗','song-poetry','','[]','閒庵筆底回三春，平生愛爲梅寫真。',160,'全唐诗/poet.song.192000.json','["閒庵筆底回三春，平生愛爲梅寫真。", "只今龍鍾已八十，雙瞳挾電摇青旻。", "芒鞋轍跡半天下，學語兒曹讀君畫。", "孤根踞鐵幾經年，轉作平梢月倒掛。", "我家破屋同蝸牛，素壁懸來春復秋。", "試携纖練覓天巧，門外觀者何其稠。", "真花著雪苔枝醜，君爲描摸應添瘦。", "朝開暮落春不留，豈若墨本堪不朽。", "臨風靜玩意趣長，何當爛熳揮滿床。", "孤山老人醉中見，便欲信手賦暗香。"]'),
('49da1281-be16-4d89-bb1e-195e174892ba','東郊','陳耆卿','宋','宋诗','song-poetry','','[]','要拓郊原眼，短筇扶我東。',48,'全唐诗/poet.song.192000.json','["要拓郊原眼，短筇扶我東。", "秧寒針怯水，麥熟浪酣風。", "古寺荒烟外，孤禽落照中。", "得醪嫌獨醉，猶及灌園翁。"]'),
('05a47120-37d9-49fd-a0b6-a86c2aeff4ca','夢林雪巢','陳耆卿','宋','宋诗','song-poetry','','[]','感舊空黄葉，經時又綠苔。',48,'全唐诗/poet.song.192000.json','["感舊空黄葉，經時又綠苔。", "未應天上去，猶解夢中來。", "雪亦本幻爾，巢今安在哉。", "淋浪詩萬軸，花鳥自驚猜。"]'),
('307b4b06-a091-4432-bdbd-a4763ff54aa7','過龍潭澳','陳耆卿','宋','宋诗','song-poetry','','[]','久闊松楸信，因爲龍澳來。',48,'全唐诗/poet.song.192000.json','["久闊松楸信，因爲龍澳來。", "四山黄戀葉，一水綠澄苔。", "地曠樵聲出，天寒雁影回。", "無人且無酒，清坐興悠哉。"]'),
('bb857d40-89c8-4f66-852d-22fba04c9328','磨鏡','陳耆卿','宋','宋诗','song-poetry','','[]','蠹蝕寧堪久，挂揩長恨遲。',48,'全唐诗/poet.song.192000.json','["蠹蝕寧堪久，挂揩長恨遲。", "浮雲手底盡，明月眼中移。", "鑑垢渾能治，心塵不解醫。", "休云磨者賤，此是主人師。"]'),
('2418f6f9-2fb7-4c55-82e5-f20f6e680b6c','春日書懷','陳耆卿','宋','宋诗','song-poetry','','[]','閒來情思浩無涯，徙倚東窗日未斜。',64,'全唐诗/poet.song.192000.json','["閒來情思浩無涯，徙倚東窗日未斜。", "乍雨乍晴鶑喚柳，不寒不暖蝶穿花。", "讀書有味慵拖杖，覓句新成自煮茶。", "未必貴遊知此趣，乘除合付野人家。"]'),
('9caa0391-8ccc-47b2-b99a-603c66b7329b','送葉子春赴官慈溪','陳耆卿','宋','宋诗','song-poetry','','[]','眼邊英氣鬰嵯峨，甫及同堂奈別何。',64,'全唐诗/poet.song.192000.json','["眼邊英氣鬰嵯峨，甫及同堂奈別何。", "正以簿書觀道力，且於言動卜天和。", "聖門克己勤登岸，後學褆身感逝波。", "三載歸來話新益，梅花仍向臘前多。"]'),
('246395aa-b760-4d81-9f6d-97c4caa7ec76','和清臣病後韻','陳耆卿','宋','宋诗','song-poetry','','[]','契闊芝眉兩月中，往尋一笑思春融。',64,'全唐诗/poet.song.192000.json','["契闊芝眉兩月中，往尋一笑思春融。", "知君近日能尋樂，款我昨宵多發蒙。", "快得聯詩到侯喜，何當載酒過揚雄。", "交情須作霜松老，莫學翻翻桃李風。"]'),
('0a56a545-da9d-4012-8d8d-b5e1231ee37c','九日阻雨晚晴二首  其一','陳耆卿','宋','宋诗','song-poetry','','[]','秋氣重陽故故深，臨欄極目一披襟。',64,'全唐诗/poet.song.192000.json','["秋氣重陽故故深，臨欄極目一披襟。", "紫萸黄菊常年事，冷雨淒風此日心。", "節物將迎人易老，塵埃追逐我難任。", "笑驅萬慮歸何有，獨自低頭課楚吟。"]'),
('7e8fce22-918d-472c-b8cb-14caecf4d3d8','九日阻雨晚晴二首  其二','陳耆卿','宋','宋诗','song-poetry','','[]','年年此日競躋攀，今日柴門雨遣關。',64,'全唐诗/poet.song.192000.json','["年年此日競躋攀，今日柴門雨遣關。", "不見白衣人送酒，難偕烏帽客登山。", "鴉聲不斷遥天暮，鳥影爭迴落照間。", "未識明年誰健在，逢時只合暫開顔。"]'),
('225ca94f-667d-450a-95b1-eb8e7a4d210e','壽章參政','陳耆卿','宋','宋诗','song-poetry','','[]','聲名早已壓人寰，手握樞機鬢未斑。',64,'全唐诗/poet.song.192000.json','["聲名早已壓人寰，手握樞機鬢未斑。", "嘉會宛如魚在水，遠猷直放馬歸山。", "風生帷幄深沉處，春在邊陲廣莫間。", "聞說吳兒眠正熟，月明夜戶不曾關。"]'),
('ac74c67b-13c3-4991-8b8f-e8aac7b339db','與二三友遊天慶觀','陳耆卿','宋','宋诗','song-poetry','','[]','適興相携步晚凉，琳宮因得縱徜徉。',64,'全唐诗/poet.song.192000.json','["適興相携步晚凉，琳宮因得縱徜徉。", "月翻楊柳盡頭影，風擢芙蓉閙處香。", "縱論從來難得友，清遊似此喜逢場。", "石欄坐久笑分袂，無酒渾疑在醉鄉。"]'),
('2fb7e009-a445-4223-a3e0-021fccfbb540','挽陳知縣','陳耆卿','宋','宋诗','song-poetry','','[]','爲訊華亭鶴唳無，琴聲斷處客悲渠。',64,'全唐诗/poet.song.192000.json','["爲訊華亭鶴唳無，琴聲斷處客悲渠。", "日邊消息花爭閙，露下光陰柳變疎。", "未嘆子雲新第宅，最憐定國舊門閭。", "風簷讀罷閒居賦，向後何人奉板輿。"]'),
('1014066e-13ba-49c1-be70-6544dda77cb3','挽王吉父知縣','陳耆卿','宋','宋诗','song-poetry','','[]','不把升沉掛舌端，排空劍氣逼人寒。',64,'全唐诗/poet.song.192000.json','["不把升沉掛舌端，排空劍氣逼人寒。", "竟鋤卉服功良易，及試花封事轉難。", "病骨欲從閒裏過，長身仍作夢中看。", "醒庵文獻知多少，一子雍容尚耐官。"]'),
('7211127a-171a-4bbe-a506-e419b6204839','代挽何知縣二首  其一','陳耆卿','宋','宋诗','song-poetry','','[]','一第聲名動冕旒，淵源家學自梁丘。',64,'全唐诗/poet.song.192000.json','["一第聲名動冕旒，淵源家學自梁丘。", "誰知雨化青衿日，最解風馳紫塞秋。", "幕府石洪嗟不作，河陽潘岳竟成休。", "鴈行無復雲邊訊，愁絕萱堂正白頭。"]'),
('a53f082b-0e82-4257-b513-b2fcd9491af1','代挽何知縣二首  其二','陳耆卿','宋','宋诗','song-poetry','','[]','才非似舅辱心知，露豁襟期喜溢眉。',64,'全唐诗/poet.song.192000.json','["才非似舅辱心知，露豁襟期喜溢眉。", "縣組秦淮久依託，賓筵建鄴又追隨。", "聞君馴雉未多日，洎我分魚已後時。", "徒對絃歌誦遺愛，西風涕淚强裁詩。"]'),
('52d0c35f-7a65-4fb3-9626-d3e6693c13bf','讀商君傳二首  其一','陳耆卿','宋','宋诗','song-poetry','','[]','大信之信本不約，至誠之誠乃如神。',32,'全唐诗/poet.song.192000.json','["大信之信本不約，至誠之誠乃如神。", "欲識唐虞感通處，泊然無物自相親。"]'),
('1e625911-1ed8-4ca0-995e-d61f6053720e','讀商君傳二首  其二','陳耆卿','宋','宋诗','song-poetry','','[]','計事應須遠作程，快心多釀後災成。',32,'全唐诗/poet.song.192000.json','["計事應須遠作程，快心多釀後災成。", "遁來關下無人舍，正爲商君法太行。"]'),
('4754d3a8-521a-412d-8724-00186591c8f4','詠史  其一','陳耆卿','宋','宋诗','song-poetry','','[]','沛公家業本無能，休責渠曹不治生。',32,'全唐诗/poet.song.192000.json','["沛公家業本無能，休責渠曹不治生。", "看取帝王他日事，方知俗眼未分明。"]'),
('e8cc9ab9-f83e-4cdb-bb1c-a15a7b3e10f2','詠史  其二','陳耆卿','宋','宋诗','song-poetry','','[]','赤族誠非漢道洪，違時賈禍亦緣公。',32,'全唐诗/poet.song.192000.json','["赤族誠非漢道洪，違時賈禍亦緣公。", "最憐老却從陳豨，不道先曾闢蒯通。"]'),
('3b7ac862-9442-4da3-98a0-ba32afd28ce1','代和陳郎中丹桂三首  其一','陳耆卿','宋','宋诗','song-poetry','','[]','千古陵陽芳桂叢，凌風擎出蕊珠宮。',32,'全唐诗/poet.song.192000.json','["千古陵陽芳桂叢，凌風擎出蕊珠宮。", "渥丹自是天然質，不學桃花點注紅。"]'),
('91dacb0b-b3f9-41b4-abb6-9f8442e950dc','代和陳郎中丹桂三首  其二','陳耆卿','宋','宋诗','song-poetry','','[]','春蘭媿死菊羞黄，世上龍涎不敢香。',32,'全唐诗/poet.song.192000.json','["春蘭媿死菊羞黄，世上龍涎不敢香。", "獨有含香人晚步，搘筇一笑倚斜陽。"]'),
('b06b250d-24a0-4c8a-a96d-155bd40b6696','代和陳郎中丹桂三首  其三','陳耆卿','宋','宋诗','song-poetry','','[]','露沐烟梳冉冉時，朗然新月似蛾眉。',32,'全唐诗/poet.song.192000.json','["露沐烟梳冉冉時，朗然新月似蛾眉。", "傍人盡向天邊覓，不信蟾宮在樹枝。"]'),
('7d985f5e-41ee-4793-8c65-3d1d7fc5a2cc','和黄臨海詠雪','陳耆卿','宋','宋诗','song-poetry','','[]','剪水紛紛撲面來，須臾灑滿舊瓊臺。',32,'全唐诗/poet.song.192000.json','["剪水紛紛撲面來，須臾灑滿舊瓊臺。", "今年不用箋丹極，聞說金穰百室開。"]'),
('90c635a2-c203-44d7-86e6-bbf3c6d2adc0','似村','陳耆卿','宋','宋诗','song-poetry','','[]','縛茅本不傍孤村，盡日焚香深閉門。',32,'全唐诗/poet.song.192000.json','["縛茅本不傍孤村，盡日焚香深閉門。", "陌上紅塵高沒馬，誰知巢父箇中存。"]'),
('95a21ca1-7280-4c1c-ad26-ba8f4c78fcbc','讀經口占','陳耆卿','宋','宋诗','song-poetry','','[]','盤誥通凡民，風雅出賤隸。',96,'全唐诗/poet.song.192000.json','["盤誥通凡民，風雅出賤隸。", "後世諸老生，懷疑以沒世。", "喧呶挾訓詁，洋溢滿天地。", "多聞豈無取，大義恐憔悴。", "譬彼醫之工，用藥不相比。", "未足以愈病，或者反致祟。", "我欲刊衆訛，引之於平易。", "當世無聖人，誰其哀此志。"]'),
('116f4750-1dd6-44eb-bd40-44e6b3940c9a','夜坐','陳耆卿','宋','宋诗','song-poetry','','[]','空庭杳已夜，孤坐悄無言。',48,'全唐诗/poet.song.192000.json','["空庭杳已夜，孤坐悄無言。", "雨後山疑活，雲中月欲吞。", "清愁難獨遣，古意與誰論。", "聽罷琴中操，呼童早閉門。"]'),
('0db4a645-0389-4173-bfb2-de56f4561e4e','聞湖寇','陳耆卿','宋','宋诗','song-poetry','','[]','淮上兵戈血染川，浙河餓莩骨盈船。',64,'全唐诗/poet.song.192000.json','["淮上兵戈血染川，浙河餓莩骨盈船。", "又聞寇盜湖南起，不覺遲回夜半眠。", "食肉貴人無恙否，剝膚巧吏尚依然。", "吾皇聖德如天大，誰採吾言作奏篇。"]'),
('72f53ca0-7648-4f21-b32b-e0ff3f06a8d1','訪趙公戴','陳耆卿','宋','宋诗','song-poetry','','[]','西原僊境即西山，流水桃花隔世間。',32,'全唐诗/poet.song.192000.json','["西原僊境即西山，流水桃花隔世間。", "自笑重來湖海客，紅塵惹到白雲關。"]'),
('fe7a659a-0c6f-4e11-89f1-c2ff783c625b','青山夾','陶夢桂','宋','宋诗','song-poetry','','[]','天宇秋來淡，江流急處鳴。',48,'全唐诗/poet.song.192000.json','["天宇秋來淡，江流急處鳴。", "小風旗脚活，晴日鼓聲清。", "歲晚冬歸客，時危北望情。", "沿江十萬戶，流寓若爲生。"]'),
('e45f943c-1037-4739-a98c-362284483abe','次韻張彥謨','陶夢桂','宋','宋诗','song-poetry','','[]','滄海張公子，秋來會面稀。',48,'全唐诗/poet.song.192000.json','["滄海張公子，秋來會面稀。", "携詩曉相訪，話舊夜忘歸。", "德劭吾身潤，道行天下肥。", "窮通都莫問，一炷篆煙微。"]'),
('0a2c4795-b68d-4bbf-b85e-0d2e211c969a','送堅大師往雲蓋兼簡隆老','陶夢桂','宋','宋诗','song-poetry','','[]','梅月廉纖雨，麥秋清潤天。',48,'全唐诗/poet.song.192000.json','["梅月廉纖雨，麥秋清潤天。", "幾程雲蓋路，一葉石山船。", "瓦礫猶能說，葫蘆自去纏。", "到時應問我，爲道只高眠。"]'),
('7676e5e4-ca11-4e1c-b5cc-4010250bdbe1','送敞上人遊湖湘','陶夢桂','宋','宋诗','song-poetry','','[]','分手仍携手，南昌更武昌。',48,'全唐诗/poet.song.192000.json','["分手仍携手，南昌更武昌。", "細論文暢序，重憶贊公房。", "衡嶽雲如故，曹溪水更香。", "不須論遠近，秋盡却還鄉。"]'),
('7d30bdea-afc7-48ea-b113-4ec86c4c107f','自述','陶夢桂','宋','宋诗','song-poetry','','[]','每與溪山對，自然懷抱開。',48,'全唐诗/poet.song.192000.json','["每與溪山對，自然懷抱開。", "不愁明日事，何用即時杯。", "一任頭如雪，孤眠鼻有雷。", "早間巾履潤，池上看魚來。"]'),
('5d48f4d7-0600-45ee-a99b-75cf772c9d0f','謾興','陶夢桂','宋','宋诗','song-poetry','','[]','溪山爭獻狀，易得小詩成。',48,'全唐诗/poet.song.192000.json','["溪山爭獻狀，易得小詩成。", "病骨如松瘦，清愁似草生。", "苦無人比飯，喜有弟分羹。", "下及長鬚輩，人言似顧榮。"]'),
('0263550f-c3d2-4348-96a6-3cc8803a61b7','次韻同舟諸丈','陶夢桂','宋','宋诗','song-poetry','','[]','古岸留雲色，晴江老日華。',48,'全唐诗/poet.song.192000.json','["古岸留雲色，晴江老日華。", "捉船人上水，撾鼓客還家。", "已自身如葉，何堪眼更花。", "摇摇强招飲，茅店酒旗斜。"]'),
('fcf5ef26-6430-4193-8f82-50d34f9a5914','送舒用之葬有感','陶夢桂','宋','宋诗','song-poetry','','[]','藕塘三畝宅，松竹蔭蘭蓀。',48,'全唐诗/poet.song.192000.json','["藕塘三畝宅，松竹蔭蘭蓀。", "有酒曾留客，無香可返魂。", "親朋惟我老，心事與誰論。", "苦怳如縻綆，隨風灑墓門。"]'),
('7ab4367d-a958-4b57-9589-412813972f79','示次兒柔中出贅','陶夢桂','宋','宋诗','song-poetry','','[]','誨汝汝知乎，家貧廼贅居。',48,'全唐诗/poet.song.192000.json','["誨汝汝知乎，家貧廼贅居。", "奉身須節約，接物要謙虛。", "勿以清罇污，而於黄卷疎。", "只須銘此語，一任命何如。"]'),
('7612add3-d286-41e9-a070-41e1b37922ab','大兒時中堂成德脩弟喜而賦之因次元韻','陶夢桂','宋','宋诗','song-poetry','','[]','有譚名利者，耳若了不聞。',96,'全唐诗/poet.song.192000.json','["有譚名利者，耳若了不聞。", "心乎平似水，身也懶於雲。", "眇眇居人世，駸駸過隙曛。", "田園趣歸去，風月謾平分。", "有子萬事足，一堂何足論。", "還欣身有托，或謂壽無根。", "靜處安吾分，超然忘世紛。", "爐薰祝萬壽，持用答吾君。"]'),
('d4c0ec9f-bfd8-4225-b899-4c042d58cab8','余試吏初期六十止今遂初願喜而賦之','陶夢桂','宋','宋诗','song-poetry','','[]','小兒無力報明時，六十休官早自期。',64,'全唐诗/poet.song.192000.json','["小兒無力報明時，六十休官早自期。", "今歲纔週花甲子，此身已在菊東籬。", "行年如許化未化，天命而今知不知。", "休問聖賢千古事，從今詩酒是吾師。"]'),
('1fc0b7c2-b3f0-4613-a5c7-d0010c5de2f9','記初第時贈相士詩','陶夢桂','宋','宋诗','song-poetry','','[]','覓得荷衣亦偶然，三壬三甲莫虛傳。',64,'全唐诗/poet.song.192000.json','["覓得荷衣亦偶然，三壬三甲莫虛傳。", "知無皂蓋朱幡分，奈有清泉白石緣。", "今日爲貧行作吏，他時有路即歸田。", "頭顱自斷祇如許，但問閑居得幾年。"]'),
('a6b72d0e-5f98-4df8-a628-e526dffed031','追次前韻','陶夢桂','宋','宋诗','song-poetry','','[]','清泉白石故依然，俚語當時已浪傳。',64,'全唐诗/poet.song.192000.json','["清泉白石故依然，俚語當時已浪傳。", "千里歸來尋舊約，一生鞅掌任前緣。", "身强只欠登山屐，老去何須負郭田。", "金石舊交半淪謝，新松嫩竹是忘年。"]'),
('5e8a255b-e6ec-446c-8f24-fc45391f0612','岳陽樓','陶夢桂','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','朱欄獨倚晚天晴，喚起江湖萬里情。',64,'全唐诗/poet.song.192000.json','["朱欄獨倚晚天晴，喚起江湖萬里情。", "風撼君山波浩蕩，雲歸衡嶽月分明。", "飄飄杜老乘槎興，杳杳軒皇奏樂聲。", "好把天瓢盛此水，滌除旱魃作秋成。"]'),
('27ccd7fe-ae0d-4c79-b1f1-da0e53f0c0fd','酬君山遠上人送別','陶夢桂','宋','宋诗','song-poetry','','[]','戀戀君山未解維，高僧來送贈行詩。',64,'全唐诗/poet.song.192000.json','["戀戀君山未解維，高僧來送贈行詩。", "誰知歸去陶元亮，又遇當年遠法師。", "蓮社欲留聽說法，菊籬那忍負歸期。", "臨岐重約頭陀會，記得江干話別時。"]'),
('ff3bc2ca-979a-4486-a31e-a24b555569e3','九日登江湖偉觀矩堂董先生時帥九江慰勞甚至','陶夢桂','宋','宋诗','song-poetry','','[]','琵琶亭下北風狂，浩蕩江天接大荒。',64,'全唐诗/poet.song.192000.json','["琵琶亭下北風狂，浩蕩江天接大荒。", "亟舍扁舟登偉觀，旋呼官酒作重陽。", "故人一見驚頭白，寒菊新開滿眼黄。", "底用四絃如裂帛，異鄉遊覽自悲傷。"]'),
('81243696-ba57-4225-aea3-62b6493a1b37','舟次吳城山','陶夢桂','宋','宋诗','song-poetry','','[]','淮蜀荆襄老此生，歸與雙眼識吳城。',64,'全唐诗/poet.song.192000.json','["淮蜀荆襄老此生，歸與雙眼識吳城。", "樹依神力連雲暗，水到江西徹底清。", "去棹來帆南北客，孤鴻落日古今情。", "枯腸尚可搜詩句，三老放船鉦一聲。"]');
